class RandomStringGenerationError(Exception):
    """Custom exception for random string generation errors."""


_MAX_COUNT = 1_000
_MAX_LENGTH = 1_000
_MAX_TOTAL_CHARS = 1_000_000  # safeguard against excessive memory usage


def _validate_int(value: int, name: str, min_value: int = 1, max_value: int = _MAX_COUNT) -> int:
    if not isinstance(value, int):
        raise RandomStringGenerationError(f"{name} must be an integer.")
    if not (min_value <= value <= max_value):
        raise RandomStringGenerationError(
            f"{name} must be between {min_value} and {max_value}."
        )
    return value


def _validate_str(value: str, name: str, max_length: int = 256) -> str:
    if not isinstance(value, str):
        raise RandomStringGenerationError(f"{name} must be a string.")
    if len(value) > max_length:
        raise RandomStringGenerationError(
            f"{name} length must not exceed {max_length} characters."
        )
    return value


def generate_random_strings(
    count: int,
    length: int = 12,
    prefix: str = "key_",
    charset: Optional[str] = None
) -> Tuple[Dict[str, str], str]:
    """
    Generate a dictionary of random strings with prefixed keys and return its JSON representation.

    :param count: Number of random strings to generate.
    :param length: Length of each random string.
    :param prefix: Prefix for each dictionary key.
    :param charset: Optional custom character set; defaults to URL‑safe characters.
    :return: Tuple containing the dictionary and its JSON string.
    :raises RandomStringGenerationError: If validation fails or an unexpected error occurs.
    """
    try:
        count = _validate_int(count, "count", max_value=_MAX_COUNT)
        length = _validate_int(length, "length", max_value=_MAX_LENGTH)
        prefix = _validate_str(prefix, "prefix")

        if count * length > _MAX_TOTAL_CHARS:
            raise RandomStringGenerationError(
                f"The total size (count * length) must not exceed {_MAX_TOTAL_CHARS} characters."
            )

        if charset is not None:
            charset = _validate_str(charset, "charset")
            if not charset:
                raise RandomStringGenerationError("charset must contain at least one character.")
        else:
            charset = string.ascii_letters + string.digits + "-_"

        result: Dict[str, str] = {}
        for i in range(count):
            random_str = ''.join(secrets.choice(charset) for _ in range(length))
            key = f"{prefix}{i}"
            result[key] = random_str

        json_repr = json.dumps(result, ensure_ascii=False)
        return result, json_repr

    except RandomStringGenerationError:
        raise
    except Exception as exc:
        logger.exception("Unexpected error during random string generation")
        raise RandomStringGenerationError(f"An unexpected error occurred: {exc}") from exc

