class BridgeValidationError(Exception):
    """Raised when bridge input validation fails."""
    pass

_MAX_TRANSPORTS = 5

_PRINTABLE_ASCII_REGEX = re.compile(r"^[\x20-\x7E]+$")        # printable characters
_TRANSPORT_NAME_REGEX = re.compile(r"^[A-Za-z0-9_-]+$")      # allowed name chars
_FINGERPRINT_REGEX = re.compile(r"^[0-9A-Fa-f]{40}$")       # SHA‑1 hex fingerprint

def _validate_ip(ip: str) -> str:
    ip = ip.strip()
    try:
        addr = ipaddress.ip_address(ip)
    except ValueError as exc:
        raise BridgeValidationError("Invalid IP address.") from exc

    # Reject non‑routable addresses
    if (addr.is_private or addr.is_loopback or addr.is_link_local or addr.is_multicast):
        raise BridgeValidationError("IP address must be public and routable.")
    return ip

def _validate_port(port: Any) -> int:
    try:
        port_int = int(port)
    except (TypeError, ValueError) as exc:
        raise BridgeValidationError("Port must be an integer.") from exc
    if not (1 <= port_int <= 65535):
        raise BridgeValidationError("Port must be in the range 1-65535.")
    return port_int

def _validate_fingerprint(fingerprint: str) -> str:
    fingerprint = fingerprint.strip()
    if not _FINGERPRINT_REGEX.fullmatch(fingerprint):
        raise BridgeValidationError("Fingerprint must be a 40-character hex string.")
    return fingerprint.upper()

def _validate_transport(transport: Dict[str, Any]) -> Dict[str, Any]:
    if not isinstance(transport, dict):
        raise BridgeValidationError("Transport must be provided as a dictionary.")
    name = transport.get("name")
    if not isinstance(name, str) or not name:
        raise BridgeValidationError("Transport name must be a non‑empty string.")
    if not _TRANSPORT_NAME_REGEX.fullmatch(name):
        raise BridgeValidationError("Transport name contains invalid characters.")

    allowed_keys = {"name", "options"}
    unexpected = set(transport.keys()) - allowed_keys
    if unexpected:
        raise BridgeValidationError(f"Unexpected transport fields: {unexpected}")

    options = transport.get("options", {})
    if not isinstance(options, dict):
        raise BridgeValidationError("Transport options must be a dictionary.")
    sanitized_options = {}
    for k, v in options.items():
        if not isinstance(k, str) or not isinstance(v, str):
            raise BridgeValidationError("Transport option keys and values must be strings.")
        v_stripped = v.strip()
        if not _PRINTABLE_ASCII_REGEX.fullmatch(v_stripped):
            raise BridgeValidationError("Transport option values contain disallowed characters.")
        sanitized_options[k] = v_stripped
    transport["options"] = sanitized_options
    return transport

@dataclass
class Bridge:
    ip: str
    port: int
    fingerprint: str
    transports: List[Dict[str, Any]] = field(default_factory=list)

def add_bridge(
    bridges: List[Bridge],
    ip: str,
    port: Any,
    fingerprint: str,
    transport: Optional[Dict[str, Any]] = None,
) -> Bridge:
    """
    Create a Bridge object with validated parameters, optionally attach a pluggable transport,
    add it to the provided bridges list, and return the created Bridge.
    """
    try:
        validated_ip = _validate_ip(ip)
        validated_port = _validate_port(port)
        validated_fingerprint = _validate_fingerprint(fingerprint)

        new_bridge = Bridge(
            ip=validated_ip,
            port=validated_port,
            fingerprint=validated_fingerprint,
        )

        if transport is not None:
            if len(new_bridge.transports) >= _MAX_TRANSPORTS:
                raise BridgeValidationError("Maximum number of transports exceeded.")
            validated_transport = _validate_transport(transport)
            new_bridge.transports.append(validated_transport)

        bridges.append(new_bridge)
        return new_bridge
    except BridgeValidationError as exc:
        _logger.warning("Bridge validation failed: %s", exc, exc_info=True)
        raise BridgeValidationError("Failed to add bridge due to invalid input.") from None

