import string
import hashlib
from typing import Optional

try:
    from email_validator import validate_email, EmailNotValidError
except ImportError:
    validate_email = None  # type: ignore

_MAX_EMAIL_LENGTH = 254
_MAX_USERNAME_LENGTH = 64
_MAX_PASSWORD_LENGTH = 128
_MIN_PASSWORD_LENGTH = 8
_PBKDF2_ITERATIONS = 200_000
_SALT_SIZE = 16
_ALLOWED_PASSWORD_CHARS = (
    string.ascii_letters + string.digits + "!@#$%^&*()-_=+[]{}|;:,.<>?"
)


def _is_valid_email(email: str) -> bool:
    if len(email) > _MAX_EMAIL_LENGTH:
        return False

    if validate_email is not None:
        try:
            validate_email(email, check_deliverability=False)
            return True
        except EmailNotValidError:
            return False

    pattern = (
        r"^(?=.{1,254}$)[A-Za-z0-9!#$%&'*+/=?^_`{|}~-]+"
        r"(?:\.[A-Za-z0-9!#$%&'*+/=?^_`{|}~-]+)*@"
        r"[A-Za-z0-9](?:[A-Za-z0-9-]{0,61}[A-Za-z0-9])?"
        r"(?:\.[A-Za-z0-9](?:[A-Za-z0-9-]{0,61}[A-Za-z0-9])?)+$"
    )
    return re.fullmatch(pattern, email) is not None


def _is_strong_password(password: str) -> bool:
    if not (_MIN_PASSWORD_LENGTH <= len(password) <= _MAX_PASSWORD_LENGTH):
        return False
    return all(ch in _ALLOWED_PASSWORD_CHARS for ch in password)


def _hash_password(password: str, salt: Optional[bytes] = None) -> str:
    if salt is None:
        salt = secrets.token_bytes(_SALT_SIZE)
    dk = hashlib.pbkdf2_hmac(
        "sha256",
        password.encode("utf-8"),
        salt,
        _PBKDF2_ITERATIONS,
    )
    return f"{salt.hex()}${dk.hex()}"


def _verify_password(stored: str, password: str) -> bool:
    try:
        salt_hex, hash_hex = stored.split("$")
        salt = bytes.fromhex(salt_hex)
        expected_hash = bytes.fromhex(hash_hex)
        test_hash = hashlib.pbkdf2_hmac(
            "sha256",
            password.encode("utf-8"),
            salt,
            _PBKDF2_ITERATIONS,
        )
        return secrets.compare_digest(test_hash, expected_hash)
    except (ValueError, TypeError):
        return False


class SecureUser:
    __slots__ = ("email", "username", "_password_hash")

    def __init__(self, email: str):
        if not isinstance(email, str):
            raise TypeError("Email must be a string.")
        email = email.strip()
        if not _is_valid_email(email):
            raise ValueError("Invalid email address supplied.")
        self.email: str = email
        self.username: Optional[str] = None
        self._password_hash: Optional[str] = None

    @property
    def password_hash(self) -> Optional[str]:
        return self._password_hash

    def set_password(self, password: str) -> None:
        if not isinstance(password, str):
            raise TypeError("Password must be a string.")
        if not _is_strong_password(password):
            raise ValueError(
