def _is_path_secure(target_path: str, base_dir: str) -> bool:
    """Return True if target_path resolves within base_dir after symlink resolution."""
    try:
        abs_path = os.path.realpath(os.path.abspath(target_path))
        base_real = os.path.realpath(os.path.abspath(base_dir))
