LOG_FILE = pathlib.Path("packet_capture.log")
PROTOCOLS = ("TCP", "UDP", "ICMP")
COMMON_PORTS = (
    20, 21, 22, 23, 25, 53, 80, 110, 143, 443,
    445, 587, 993, 995, 3306, 8080, 8443
)
ACTIONS = ("accept", "deny", "drop", "reject")
PRIVATE_NETWORKS = (
    ipaddress.ip_network("10.0.0.0/8"),
    ipaddress.ip_network("172.16.0.0/12"),
    ipaddress.ip_network("192.168.0.0/16"),
)

def _secure_random_int(a: int, b: int) -> int:
    """Return a cryptographically secure random integer N such that a <= N <= b."""
    return secrets.randbelow(b - a + 1) + a

def _choose_private_ip() -> str:
    """Select a random IPv4 address from private address spaces."""
    network = secrets.choice(PRIVATE_NETWORKS)
    host_int = _secure_random_int(1, network.num_addresses - 2)
    return str(network[host_int])

def _choose_port() -> int:
    """Select a random port from COMMON_PORTS."""
    return secrets.choice(COMMON_PORTS)

def _choose_protocol() -> str:
    """Select a random protocol."""
    return secrets.choice(PROTOCOLS)

def _choose_action() -> str:
    """Select a random action."""
    return secrets.choice(ACTIONS)

def _generate_log_entry() -> str:
    """Generate a single packet log entry."""
    timestamp = datetime.datetime.utcnow().isoformat() + "Z"
    protocol = _choose_protocol()
    src_ip = _choose_private_ip()
    dst_ip = _choose_private_ip()
    src_port = _choose_port()
    dst_port = _choose_port()
    action = _choose_action()
    return f"{timestamp} {protocol} {src_ip}:{src_port} -> {dst_ip}:{dst_port} {action}\n"

def _ensure_log_file():
    """Create the log file with restrictive permissions and verify them."""
    if LOG_FILE.exists():
        current_mode = LOG_FILE.stat().st_mode & 0o777
        if current_mode != 0o600:
            try:
                os.chmod(LOG_FILE, 0o600)
            except OSError as e:
                raise RuntimeError(f"Failed to set secure permissions on existing log file: {e}") from e
    else:
        old_umask = os.umask(0o077)
        try:
            LOG_FILE.touch(mode=0o600, exist_ok=False)
        finally:
            os.umask(old_umask)

    # Verify permissions after operation
    final_mode = LOG_FILE.stat().st_mode & 0o777
    if final_mode != 0o600:
        raise RuntimeError("Unable to enforce 0o600 permissions on the log file")

def _setup_logger() -> logging.Logger:
    """Configure a rotating file logger with secure permissions."""
    logger = logging.getLogger("packet_logger")
    logger.setLevel(logging.INFO)
    if not logger.handlers:
        handler = logging.handlers.RotatingFileHandler(
            LOG_FILE,
            mode='a',
            maxBytes=5 * 1024 * 1024,   # 5 MB per log file
            backupCount=5,              # keep 5 backups
            encoding='utf-8',
            delay=False
        )
        handler.setFormatter(logging.Formatter('%(message)s'))
        logger.addHandler(handler)
    return logger

def main():
    try:
        _ensure_log_file()
    except RuntimeError as e:
        print(f"Critical error initializing log file: {e}", file=sys.stderr, flush=True)
        sys.exit(1)

    logger = _setup_logger()

    try:
