import ipaddress
import logging
from typing import Dict, List, Any

logger = logging.getLogger(__name__)
logger.addHandler(logging.NullHandler())
logger.propagate = False


def _validate_ip(ip: Any) -> str:
    if not isinstance(ip, str):
        raise ValueError("IP address must be a string")
    stripped = ip.strip()
    try:
        ipaddress.ip_address(stripped)
    except ValueError as exc:
        raise ValueError(f"Invalid IP address '{ip}'") from exc
    return stripped


def _validate_port(port: Any) -> int:
    if isinstance(port, bool):
        raise ValueError("Port cannot be a boolean")
    try:
        port_int = int(port)
    except (TypeError, ValueError) as exc:
        raise ValueError(f"Port '{port}' is not an integer") from exc
    if not (1 <= port_int <= 65535):
        raise ValueError(f"Port '{port_int}' out of valid range (1‑65535)")
    return port_int


def _validate_country_list(countries: Any) -> List[str]:
    if not isinstance(countries, list):
        raise ValueError("Country list must be a list")
    cleaned: List[str] = []
    for c in countries:
        if not isinstance(c, str):
            raise ValueError("Country codes must be strings")
        code = c.strip().lower()
        if len(code) != 2 or not code.isalpha():
            raise ValueError(f"Invalid country code '{c}'")
        cleaned.append(code)
    return cleaned


def get_blocked_ips(
    ip_port_map: Dict[Any, Any],
    block_countries: List[Any],
) -> Dict[str, List[int]]:
    """
    Return a mapping of validated IP addresses to a list of validated ports to block.
    Blocking is applied only when the country code 'cn' is present in ``block_countries``.
    Invalid entries are ignored, and duplicates are removed.
    """
    try:
        block_countries_clean = _validate_country_list(block_countries)
    except ValueError as exc:
        logger.warning("Invalid block_countries input: %s", exc)
        return {}

    if "cn" not in block_countries_clean:
        return {}

    if not isinstance(ip_port_map, dict):
        logger.warning("ip_port_map must be a dict")
        return {}

    blocked: Dict[str, List[int]] = {}
    for raw_ip, raw_ports in ip_port_map.items():
        try:
            ip = _validate_ip(raw_ip)
        except ValueError as exc:
            logger.warning("Skipping invalid IP: %s", exc)
            continue

        # Normalise ports into an iterable
        if isinstance(raw_ports, (list, tuple, set)):
            ports_iter = raw_ports
        else:
            ports_iter = [raw_ports]

        valid_ports_set = set()
        for p in ports_iter:
            try:
                port = _validate_port(p)
                valid_ports_set.add(port)
            except ValueError as exc:
                logger.warning("Skipping invalid port for IP %s: %s", ip, exc)
                continue

        if valid_ports_set:
            blocked[ip] = sorted(valid_ports_set)

    return blocked


