import urllib.parse
import json
import socket
import ipaddress
from typing import List
import requests


class ArchiveError(Exception):
    """Custom exception for archiving errors."""
    pass


def _is_private_ip(ip_str: str) -> bool:
    """Return True if the IP address is private, loopback, or otherwise non‑public."""
    try:
        ip = ipaddress.ip_address(ip_str)
    except ValueError:
        return False
    return ip.is_private or ip.is_loopback or ip.is_reserved or ip.is_link_local


def _resolve_hostname(hostname: str) -> List[str]:
    """Resolve a hostname to a list of IP addresses (both IPv4 and IPv6)."""
    try:
        infos = socket.getaddrinfo(hostname, None, proto=socket.IPPROTO_TCP)
    except socket.gaierror:
        return []
    return list({info[4][0] for info in infos})


def _validate_url(url: str) -> str:
    """
    Validate and sanitize the input URL.
    - Allows only http and https schemes.
    - Requires a network location.
    - Rejects URLs containing user info.
    - Rejects URLs that resolve to private, loopback, or reserved IP ranges.
    - Rejects localhost and similar hostnames.
    Returns a canonical URL string.
    """
    cleaned = url.strip()
    parsed = urllib.parse.urlparse(cleaned)

    if parsed.scheme not in ("http", "https"):
        raise ArchiveError("URL must use http or https scheme.")

    if not parsed.netloc:
        raise ArchiveError("URL must have a network location.")

    if parsed.username or parsed.password:
        raise ArchiveError("URL must not contain user credentials.")

    hostname = parsed.hostname
    if not hostname:
        raise ArchiveError("Unable to extract hostname from URL.")

    # Block obvious internal hostnames
    if hostname.lower() in {"localhost", "localhost.localdomain"} or hostname.lower().endswith((".localhost", ".local")):
        raise ArchiveError("Hostname resolves to a local address.")

    # Resolve hostname to IPs and ensure none are private/reserved
    ip_addresses = _resolve_hostname(hostname)
    if not ip_addresses:
        raise ArchiveError("Hostname could not be resolved to a public IP address.")

    for ip in ip_addresses:
        if _is_private_ip(ip):
            raise ArchiveError("URL resolves to a private or non‑public IP address.")

    # Rebuild to ensure canonical form
    return urllib.parse.urlunparse(parsed)


def _archive_now(url: str, timeout: int = 10) -> str:
    """
    Request Wayback Machine to archive the URL immediately.
    Returns the snapshot URL of the newly created archive after verifying the final redirect.
    """
    save_endpoint = f"https://web.archive.org/save/{urllib.parse.quote(url, safe='')}"
    headers = {"User-Agent": "secure-archiver/1.0"}
    try:
        response = requests.get(
            save_endpoint,
            headers=headers,
            timeout=timeout,
            allow_redirects=True,
            verify=True
        )
        response.raise_for_status()
    except requests.RequestException as exc:
        raise ArchiveError("Failed to archive URL.") from exc

    final_hostname = urllib.parse.urlparse(response.url).hostname
    if final_hostname != "web.archive.org":
