import uuid
import math
from dataclasses import dataclass, field
from typing import Any, Dict, Mapping
from types import MappingProxyType

MAX_FEATURES = 1000
MAX_VALUE = 1_000_000.0
MIN_VALUE = 0.0


class PlanError(Exception):
    """Custom exception for plan creation/modification errors."""
    pass


def _validate_features(raw: Any) -> Dict[str, float]:
    """
    Validate and sanitize the input to ensure it is a mapping with string keys
    and numeric (int or float) values within a safe range.
    """
    if not isinstance(raw, Mapping):
        raise PlanError("Features must be a mapping type.")
    if len(raw) > MAX_FEATURES:
        raise PlanError(f"Too many features (max {MAX_FEATURES}).")
    sanitized: Dict[str, float] = {}
    for key, value in raw.items():
        if not isinstance(key, str):
            raise PlanError("Feature keys must be strings.")
        if not isinstance(value, (int, float)):
            raise PlanError(f"Feature '{key}' must be numeric.")
        numeric_value = float(value)
        if not math.isfinite(numeric_value):
            raise PlanError(f"Feature '{key}' must be a finite number.")
        if not (MIN_VALUE <= numeric_value <= MAX_VALUE):
            raise PlanError(f"Feature '{key}' out of allowed range [{MIN_VALUE}, {MAX_VALUE}].")
        sanitized[key] = numeric_value
    return sanitized


def _modify_features(features: Mapping[str, float]) -> Dict[str, float]:
    """
    Apply a deterministic modification to feature values.
    Ensures resulting values stay within allowed limits.
    """
    modified: Dict[str, float] = {}
    for k, v in features.items():
        new_val = v + 1.0
        if new_val > MAX_VALUE:
            raise PlanError(f"Modified feature '{k}' exceeds maximum allowed value.")
        modified[k] = new_val
    return modified


@dataclass(frozen=True)
class Plan:
    identifier: uuid.UUID = field(default_factory=uuid.uuid4)
    features: Mapping[str, float] = field(default_factory=lambda: MappingProxyType({}))


def create_and_modify_plan(raw_features: Any) -> Plan:
    """
    Creates a new Plan with validated features, modifies the features,
    and ensures the identifier remains unchanged.
    Returns the modified Plan.
    """
    try:
        validated = _validate_features(raw_features)
        original_plan = Plan(features=MappingProxyType(validated))

        modified_dict = _modify_features(original_plan.features)

        modified_plan = Plan(
            identifier=original_plan.identifier,
            features=MappingProxyType(modified_dict)
        )

        if modified_plan.identifier != original_plan.identifier:
            raise PlanError("Plan identifier mismatch after modification.")

        return modified_plan
    except PlanError:
        raise
    except Exception as exc:
        raise PlanError("An unexpected error occurred while processing the plan.") from exc

