from typing import List, Optional

import requests

MAX_PARTS = 1000
MIN_PART_SIZE = 1024  # bytes
DEFAULT_TIMEOUT = 10
DEFAULT_USER_AGENT = "SecureDownloader/1.0"
MAX_CONTENT_LENGTH = 500 * 1024 * 1024  # 500 MiB


class DownloadError(Exception):
    """Generic download error without leaking internal details."""
    pass


def _is_private_ip(host: str) -> bool:
    try:
        ip = ipaddress.ip_address(host)
        return ip.is_private
    except ValueError:
        # Not an IP literal, treat as non‑private (will be resolved later if needed)
        return False


def _validate_url(url: str) -> str:
    parsed = urllib.parse.urlparse(url)

    # Scheme check
    if parsed.scheme not in ("http", "https"):
        raise ValueError("Unsupported URL scheme")

    # Netloc presence
    if not parsed.netloc:
        raise ValueError("Invalid URL: missing network location")

    # Disallow user credentials in URL
    if parsed.username or parsed.password:
        raise ValueError("URL must not contain user credentials")

    # Disallow IPv6 literals with brackets not properly parsed
    if parsed.hostname and ":" in parsed.hostname and not ipaddress.ip_address(parsed.hostname).version == 6:
        raise ValueError("Invalid IPv6 address format")

    # Disallow private IP addresses
    if parsed.hostname and _is_private_ip(parsed.hostname):
        raise ValueError("URL resolves to a private IP address")

    # Optionally reject unsafe characters (basic check)
    unsafe_chars = set(' <>\"#%{}|\\^`')
    if any(c in unsafe_chars for c in url):
        raise ValueError("URL contains unsafe characters")

    return url


def _get_content_length(url: str, user_agent: str) -> int:
    try:
        resp = requests.head(
            url,
            allow_redirects=False,
            timeout=DEFAULT_TIMEOUT,
            headers={"User-Agent": user_agent},
        )
    except requests.RequestException as exc:
        raise DownloadError("Unable to retrieve file metadata") from exc

    # Reject redirects to avoid SSRF via Location header
    if 300 <= resp.status_code < 400:
        raise DownloadError("Redirects are not allowed")

    if resp.status_code >= 400:
        raise DownloadError("Unable to retrieve file metadata")

    length = resp.headers.get("Content-Length")
    if not length:
        raise DownloadError("Missing Content-Length header")

    try:
        size = int(length)
    except ValueError as exc:
        raise DownloadError("Invalid Content-Length header") from exc

    if size <= 0:
        raise DownloadError("Content-Length must be positive")
    if size > MAX_CONTENT_LENGTH:
        raise DownloadError(f"File size exceeds allowed maximum of {MAX_CONTENT_LENGTH} bytes")
    return size


def download_file_in_parts(
    file_url: str,
    max_part_size: int,
    user_agent: Optional[str] = None,
) -> List[str]:
    if not isinstance(file_url, str):
        raise TypeError("file_url must be a string")
    if not isinstance(max_part_size, int):
        raise TypeError("max_part_size must be an integer")
    if max_part_size < MIN_PART_SIZE:
        raise ValueError(f"Part size must be at least {MIN_PART_SIZE} bytes")

    ua = user_agent or DEFAULT_USER_AGENT

    # Validate and obtain metadata
    url = _validate_url(file_url)
    total_size = _get_content_length(url, ua)

    # Determine part sizes
    part_size = min(max_part_size, total_size)
    num_parts = math.ceil(total_size / part_size)
    if num_parts > MAX_PARTS:
        raise ValueError(f"Number of parts ({num_parts}) exceeds limit of {MAX_PARTS}")

    temp_dir = tempfile.mkdtemp(prefix="download_")
    part_files: List[str] = []

    try:
        for i in range(num_parts):
            start = i * part_size
            end = min(start + part_size - 1, total_size - 1)
            headers = {
                "Range": f"bytes={start}-{end}",
                "User-Agent": ua,
            }
            try:
                resp = requests.get(
                    url,
                    headers=headers,
                    stream=True,
                    timeout=DEFAULT_TIMEOUT,
                    allow_redirects=False,
                )
            except requests.RequestException as exc:
                raise DownloadError("Error during file download") from exc

            if resp.status_code not in (200, 206):
                raise DownloadError("Server does not support ranged requests for this file")

            part_path = os.path.join(temp_dir, f"part_{i}")
            try:
                with open(part_path, "wb") as fp:
                    for chunk in resp.iter_content(chunk_size=8192):
                        if chunk:
                            fp.write(chunk)
                part_files.append(part_path)
            finally:
                resp.close()

        return part_files
    except (DownloadError, OSError, requests.RequestException) as exc:
        # Clean up any partially written files and the temporary directory
        shutil.rmtree(temp_dir, ignore_errors=True)
        raise DownloadError("Failed to download file in parts") from exc
    except Exception as exc:
        shutil.rmtree(temp_dir, ignore_errors=True)
        raise DownloadError("An unexpected error occurred") from exc

