from typing import Sequence, Tuple, Any, List, Dict, Callable

# Configuration
MAX_COMMANDS = 1000
MAX_TOTAL_LENGTH = 100000
MAX_ARG_LENGTH = 4096

# Whitelisted minimizer methods and optional simple validators
# The validator receives the raw string arguments and returns a list of
# arguments to pass to the method.  By default it enforces length limits.
def _default_validator(args: List[str]) -> List[Any]:
    for arg in args:
        if len(arg) > MAX_ARG_LENGTH:
            raise ValueError("Argument exceeds maximum allowed length")
    return args  # type: ignore[return-value]

ALLOWED_METHODS: Dict[str, Callable[[List[str]], List[Any]]] = {
    "set_parameters": _default_validator,
    "fit": _default_validator,
    "reset": _default_validator,
    # add other allowed methods here
}


class MinimizerCommandError(RuntimeError):
    """Raised when a minimizer command fails."""

    def __init__(self, message: str, original_exc: Exception):
        super().__init__(message)
        self.__cause__ = original_exc


def _is_primitive(value: Any) -> bool:
    return isinstance(value, (int, float, bool, str, type(None)))


def _safe_copy(obj: Any) -> Any:
    """Recursively copy only plain data structures without invoking custom __deepcopy__."""
    if _is_primitive(obj):
        return obj
    if isinstance(obj, dict):
        return {k: _safe_copy(v) for k, v in obj.items()}
    if isinstance(obj, (list, tuple, set)):
        typ = type(obj)
        return typ(_safe_copy(v) for v in obj)
    raise ValueError("Unsupported type encountered while copying minimizer state")


def evaluate_minimizer_commands(
    commands: Sequence[Sequence[str]],
    minimizer: Any,
) -> Tuple[Any, Any, Any, Any]:
    """
    Execute a sequence of whitelisted commands on a minimizer object safely.
    Returns a tuple (parameters, chi2, ndf, normalizedChi2) representing the
    minimizer state after successful execution of all commands.
    """

    # Basic structural validation
    if not isinstance(commands, (list, tuple)):
        raise ValueError("commands must be a list or tuple")
    if len(commands) > MAX_COMMANDS:
        raise ValueError("Number of commands exceeds allowed maximum")
    total_length = 0
    for cmd in commands:
        if not isinstance(cmd, (list, tuple)):
            raise ValueError("each command must be a list or tuple")
        if not cmd:
            raise ValueError("command cannot be empty")
        if not all(isinstance(item, str) for item in cmd):
            raise ValueError("all command items must be strings")
        total_length += sum(len(item) for item in cmd)
    if total_length > MAX_TOTAL_LENGTH:
        raise ValueError("Total size of commands exceeds allowed maximum")

    # Helper to capture minimizer state safely
    def _get_state() -> Tuple[Any, Any, Any, Any]:
        return (
            _safe_copy(getattr(minimizer, "parameters", None)),
            getattr(minimizer, "chi2", None),
            getattr(minimizer, "ndf", None),
            getattr(minimizer, "normalizedChi2", None),
        )

    # Process each command
    for cmd in commands:
        method_name = cmd[0]
        raw_args = list(cmd[1:])

        if method_name.startswith("_"):
            raise ValueError(f"Invalid method name: {method_name}")

        if method_name not in ALLOWED_METHODS:
            raise ValueError(f"Method '{method_name}' is not allowed")

        # Resolve method
        try:
            method = getattr(minimizer, method_name)
        except AttributeError as exc:
            raise AttributeError(f"Minimizer has no method '{method_name}'") from exc

        if not callable(method):
            raise TypeError(f"Attribute '{method_name}' is not callable")

        # Validate and possibly transform arguments
        validator = ALLOWED_METHODS[method_name]
        try:
            validated_args = validator(raw_args)
        except Exception as exc:
            raise ValueError(f"Argument validation failed for method '{method_name}'") from exc

        # Execute the method
        try:
            method(*validated_args)
        except Exception as exc:
            # Capture state before propagating a wrapped error
            parameters, chi2, ndf, normalized_chi2 = _get_state()
            raise MinimizerCommandError(
                f"Error executing minimizer command '{method_name}'", exc
            ) from exc

    # Return final safe state
    return _get_state()

