            raise ValueError("Length must be a positive integer")
        if length > SecureCommandRunner._MAX_RANDOM_STRING_LENGTH:
            raise ValueError(f"Length must not exceed {SecureCommandRunner._MAX_RANDOM_STRING_LENGTH}")
