            args = []
        if not isinstance(args, list):
            raise TypeError("Args must be a list of strings")
        for arg in args:
            if not isinstance(arg, str):
                raise TypeError("All arguments must be strings")
            # Basic printable character check
            if not re.fullmatch(r"[\x20-\x7E]*", arg):
                raise ValueError(f"Invalid argument: {arg}")
            # Additional restrictions for file‑system commands
            if command in {"ls", "cat"}:
                # Disallow path traversal and absolute paths
                if os.path.isabs(arg):
                    raise ValueError(f"Absolute paths are not allowed: {arg}")
                if ".." in arg.split(os.path.sep):
                    raise ValueError(f"Path traversal components are not allowed: {arg}")
