        absolute_cmd = cls._ALLOWED_COMMAND_PATHS[command]
        if not os.path.isabs(absolute_cmd) or not os.path.isfile(absolute_cmd):
            raise ValueError(f"Executable for command '{command}' not found at expected path")
        return [absolute_cmd] + args

    @classmethod
    def execute_command(cls, command: str, args: Optional[List[str]] = None, timeout: int = 30) -> str:
        """
