# Decimal and JSON handling limits
MAX_DECIMAL_DIGITS = 30          # maximum total digits allowed in a Decimal
MAX_DECIMAL_EXPONENT = 100       # maximum absolute exponent magnitude
MAX_JSON_STRING_LENGTH = 10_000 # maximum allowed length of JSON string input
