def _check_decimal_limits(value: Decimal, field_name: str) -> None:
    """Enforce size limits on a Decimal to mitigate DoS attacks."""
    tup = value.as_tuple()
    digit_count = len(tup.digits)
    exponent = abs(tup.exponent)
    if digit_count > MAX_DECIMAL_DIGITS:
        logger.warning(
            "Decimal digit count exceeded for field '%s': %d digits",
            field_name,
            digit_count,
        )
        raise ValueError(f"Decimal value for '{field_name}' exceeds allowed precision")
    if exponent > MAX_DECIMAL_EXPONENT:
        logger.warning(
            "Decimal exponent magnitude exceeded for field '%s': %d",
            field_name,
            exponent,
        )
        raise ValueError(f"Decimal value for '{field_name}' has too large an exponent")


def _check_json_depth(obj: Any, current_depth: int = 0) -> None:
    """Recursively verify that JSON structures do not exceed depth limits."""
    if current_depth > MAX_JSON_DEPTH:
        raise ValueError("JSON input exceeds maximum nesting depth")
    if isinstance(obj, dict):
        for v in obj.values():
            _check_json_depth(v, current_depth + 1)
    elif isinstance(obj, list):
        for item in obj:
