def _run_command(cmd: List[str], job_id: str) -> subprocess.CompletedProcess:
    safe_env = {"PATH": "/usr/bin:/bin", "LANG": "C"}
    try:
        result = subprocess.run(
            cmd,
            capture_output=True,
            text=True,
            check=False,
            shell=False,
            timeout=10,
            env=safe_env,
        )  # nosec B603
        # Guard against excessive output that could exhaust memory.
        if len(result.stdout) > _MAX_OUTPUT_SIZE or len(result.stderr) > _MAX_OUTPUT_SIZE:
            raise RuntimeError(
                f"Command output exceeded size limit for job {_redact_job_id(job_id)}"
            )
        return result
    except subprocess.TimeoutExpired as exc:
        logger.error(
            "Command timed out for job %s: %s", _redact_job_id(job_id), exc
        )
        raise RuntimeError(
            f"Command timed out for job {job_id}"
        ) from exc
    except OSError as exc:
        logger.error(
            "OS error executing command for job %s: %s", _redact_job_id(job_id), exc
        )
        raise RuntimeError(
            f"Failed to execute command for job {job_id}"
        ) from exc
    except Exception as exc:  # pragma: no cover
        logger.error(
            "Unexpected error executing command for job %s: %s",
            _redact_job_id(job_id),
            exc,
        )
        raise


def get_job_exit_code(job_id: str) -> int:
    _validate_job_id(job_id)

    cmd = ["/usr/bin/jobctl", "exit-code", job_id]

    result = _run_command(cmd, job_id)

    if result.returncode != 0:
        logger.error(
            "Command returned non-zero status for job %s: %s",
            _redact_job_id(job_id),
            result.stderr.strip(),
        )
        raise RuntimeError(f"Command failed for job {job_id}")

    output = result.stdout.strip()
    logger.info(
        "Command output for job %s: %s", _redact_job_id(job_id), output
    )

    match = re.search(r"exit\s*code\s*[:=]\s*(\d+)", output, re.IGNORECASE)
    if not match:
        logger.error(
            "Unable to parse exit code from output for job %s", _redact_job_id(job_id)
        )
        raise ValueError("Exit code not found in command output")

    exit_code = int(match.group(1))
    logger.info(
        "Job %s completed with exit code %d", _redact_job_id(job_id), exit_code
    )
    return exit_code

