RETURNS void AS $func$
DECLARE
    rec RECORD;
    cur CURSOR FOR
        SELECT id_val, name_val
        FROM unnest(p_ids, p_names) AS t(id_val, name_val);
BEGIN
    IF p_ids IS NULL OR p_names IS NULL THEN
        RAISE EXCEPTION 'Invalid input: arrays must not be null.';
    END IF;

    IF array_length(p_ids,1) IS DISTINCT FROM array_length(p_names,1) THEN
        RAISE EXCEPTION 'Invalid input: arrays must have the same length.';
    END IF;

    CREATE TEMP TABLE IF NOT EXISTS temp_demo (
        id   integer NOT NULL,
        name text    NOT NULL
    ) ON COMMIT DROP;

    OPEN cur;
    LOOP
        FETCH cur INTO rec;
        EXIT WHEN NOT FOUND;
        INSERT INTO temp_demo (id, name) VALUES (rec.id_val, rec.name_val);
    END LOOP;
    CLOSE cur;

    DROP TABLE IF EXISTS temp_demo;
EXCEPTION
    WHEN OTHERS THEN
        IF cur%ISOPEN THEN
            CLOSE cur;
        END IF;
        DROP TABLE IF EXISTS temp_demo;
        RAISE;
END;
