# Configure logger without altering global logging configuration
logger = logging.getLogger(__name__)
if not logger.handlers:
    logger.addHandler(logging.NullHandler())

# Whitelisted note types
_ALLOWED_NOTE_TYPES: Set[str] = {"C", "D", "E", "F", "G", "A", "B", "REST"}

# Maximum length for string inputs
_MAX_STRING_LENGTH = 32


@dataclass(frozen=True)
class Note:
    x: float
    y: float
    time: float
    note_type: str
    curve: float = 0.0
    repeat: int = 0


def _validate_numeric(value: Any, name: str, *, allow_negative: bool = False) -> float:
    if isinstance(value, bool) or not isinstance(value, (int, float)):
        raise ValueError(f"Invalid {name}: must be numeric")
    if not allow_negative and value < 0:
        raise ValueError(f"Invalid {name}: must be non‑negative")
    return float(value)


def _validate_int(value: Any, name: str, *, allow_negative: bool = False) -> int:
    if isinstance(value, bool) or not isinstance(value, int):
        raise ValueError(f"Invalid {name}: must be an integer")
    if not allow_negative and value < 0:
        raise ValueError(f"Invalid {name}: must be non‑negative")
    return value


def _validate_string(value: Any, name: str, whitelist: Set[str] | None = None) -> str:
    if not isinstance(value, str):
        raise ValueError(f"Invalid {name}: must be a string")
    cleaned = value.strip()
    if len(cleaned) > _MAX_STRING_LENGTH:
        raise ValueError(f"Invalid {name}: exceeds maximum length")
    if whitelist is not None and cleaned not in whitelist:
        raise ValueError(f"Invalid {name}: not an allowed value")
    return cleaned


def create_notes(objects: List[Dict[str, Any]]) -> List[Note]:
    """
    Convert a list of dictionaries describing musical notes into a list of Note instances.
    All inputs are validated and sanitized to mitigate security risks.
    """
    if not isinstance(objects, list):
        logger.error("Input is not a list")
        raise TypeError("Input must be a list of dictionaries")

    notes: List[Note] = []

    for idx, obj in enumerate(objects):
        try:
            if not isinstance(obj, dict):
                raise ValueError("Item is not a dictionary")

            x = _validate_numeric(obj.get("x"), "x")
            y = _validate_numeric(obj.get("y"), "y")
            time = _validate_numeric(obj.get("time"), "time")
            note_type = _validate_string(obj.get("note_type"), "note_type", _ALLOWED_NOTE_TYPES)

            curve = _validate_numeric(obj.get("curve", 0.0), "curve", allow_negative=True)
            repeat = _validate_int(obj.get("repeat", 0), "repeat")

            notes.append(Note(x=x, y=y, time=time, note_type=note_type, curve=curve, repeat=repeat))
        except Exception:  # pragma: no cover
            logger.error("Failed to process note at index %s", idx)
            continue

    return notes

