import argparse
import sys
import pathlib
import pkgutil


def _is_safe_path(base_dir: pathlib.Path, target_path: pathlib.Path) -> bool:
    """
    Return True if ``target_path`` is located inside ``base_dir``.
    ``base_dir`` must exist; ``target_path`` may be non‑existent (e.g., for output files).
    """
    try:
        base_dir_resolved = base_dir.resolve(strict=True)
        target_path_resolved = target_path.resolve(strict=False)
        # ``Path.is_relative_to`` is available on Python 3.9+
        return target_path_resolved.is_relative_to(base_dir_resolved)
    except Exception:
        return False


def _load_package_modules(package_path: pathlib.Path) -> list[str]:
    """Return a sorted list of dotted module names found under ``package_path``."""
    modules: set[str] = set()
    if not package_path.is_dir():
        return []
    for _, name, is_pkg in pkgutil.iter_modules([str(package_path)]):
        modules.add(name)
        if is_pkg:
            sub_path = package_path / name
            sub_modules = _load_package_modules(sub_path)
            for sub in sub_modules:
                modules.add(f"{name}.{sub}")
    return sorted(modules)


def _replace_placeholder(template_text: str, placeholder: str, replacement: str) -> str:
    return template_text.replace(placeholder, replacement)


def main() -> None:
    parser = argparse.ArgumentParser(
        description="Generate README from template with module list."
    )
    parser.add_argument(
        "template",
        type=str,
        help="Path to the README template file.",
    )
    parser.add_argument(
        "output",
        type=str,
        help="Path where the generated README will be written.",
    )
    parser.add_argument(
        "package",
        type=str,
        help="Path to the Python package directory to inspect.",
    )
    parser.add_argument(
        "--placeholder",
        type=str,
        default="{{MODULES}}",
        help="Placeholder string in the template to replace.",
    )
    args = parser.parse_args()

    cwd = pathlib.Path.cwd()

    template_path = pathlib.Path(args.template)
    output_path = pathlib.Path(args.output)
    package_path = pathlib.Path(args.package)

    # Validate template and package paths
    for p, name, is_file_expected in (
        (template_path, "template", True),
        (package_path, "package", False),
    ):
        if is_file_expected:
            if not p.is_file():
                sys.stderr.write(f"Error: Invalid {name} file.\n")
                sys.exit(1)
        else:
            if not p.is_dir():
                sys.stderr.write(f"Error: Invalid {name} directory.\n")
                sys.exit(1)

        if not _is_safe_path(cwd, p):
            sys.stderr.write(f"Error: {name} path is not within the working directory.\n")
            sys.exit(1)

    # Validate output directory
    if not _is_safe_path(cwd, output_path.parent):
        sys.stderr.write("Error: Output path is outside the working directory.\n")
        sys.exit(1)

    try:
        with template_path.open("r", encoding="utf-8") as f:
            template_text = f.read()
    except Exception:
        sys.stderr.write("Error: Unable to read template file.\n")
        sys.exit(1)

    modules = _load_package_modules(package_path)
    module_list_str = "\n".join(f"- {m}" for m in modules)

    result_text = _replace_placeholder(template_text, args.placeholder, module_list_str)

    try:
        # Ensure parent directories exist
        output_path.parent.mkdir(parents=True, exist_ok=True)
        with output_path.open("w", encoding="utf-8", newline="\n") as f:
            f.write(result_text)
    except Exception:
        sys.stderr.write("Error: Unable to write output file.\n")
        sys.exit(1)


if __name__ == "__main__":
    main()

