import argparse
import logging
import os
import sys
import hashlib
from pathlib import Path
from typing import Set

MAX_FILE_SIZE = 10 * 1024 * 1024  # 10 MiB


def configure_logging() -> None:
    logger = logging.getLogger()
    logger.setLevel(logging.INFO)
    handler = logging.StreamHandler(sys.stderr)
    formatter = logging.Formatter("%(asctime)s - %(levelname)s - %(message)s")
    handler.setFormatter(formatter)
    logger.handlers.clear()
    logger.addHandler(handler)


def parse_arguments() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Process column and row files, compute differences, and manage files securely."
    )
    parser.add_argument(
        "columns_file",
        type=Path,
        help="Path to the file containing a list of columns.",
    )
    parser.add_argument(
        "rows_file",
        type=Path,
        help="Path to the file containing a list of rows.",
    )
    parser.add_argument(
        "--target-dir",
        type=Path,
        default=Path.cwd(),
        help="Directory containing files to evaluate for removal (default: current working directory).",
    )
    parser.add_argument(
        "--output-dir",
        type=Path,
        default=Path.cwd() / "output_secure",
        help="Directory to create for further processing (default: ./output_secure).",
    )
    return parser.parse_args()


def safe_read_lines(path: Path) -> Set[str]:
    if not path.is_file():
        raise FileNotFoundError(f"File not found: {path}")
    if not os.access(path, os.R_OK):
        raise PermissionError(f"Read permission denied for file: {path}")

    size = path.stat().st_size
    if size > MAX_FILE_SIZE:
        raise ValueError(f"File too large ({size} bytes). Limit is {MAX_FILE_SIZE} bytes: {path}")

    lines: Set[str] = set()
    with path.open("r", encoding="utf-8", errors="ignore") as f:
        for line in f:
            cleaned = line.strip()
            if cleaned:
                lines.add(cleaned)
    return lines


def compute_differences(set_a: Set[str], set_b: Set[str]) -> tuple[Set[str], Set[str]]:
    only_in_a = set_a - set_b
    only_in_b = set_b - set_a
    return only_in_a, only_in_b


def remove_matching_files(target_dir: Path, criteria: Set[str]) -> None:
    if not target_dir.is_dir():
        raise NotADirectoryError(f"Target directory does not exist: {target_dir}")
    for entry in target_dir.iterdir():
        if not entry.is_file() or entry.is_symlink():
            continue
        try:
            if entry.name in criteria:
                entry.unlink()
                logging.info("Removed file: %s", entry)
        except Exception as e:
            logging.warning("Failed to remove %s: %s", entry, str(e))


def create_secure_directory(dir_path: Path) -> None:
    try:
        original_umask = os.umask(0o077)
        try:
            dir_path.mkdir(mode=0o700, parents=True, exist_ok=False)
        finally:
            os.umask(original_umask)
        # Ensure exact permissions regardless of umask race
        os.chmod(dir_path, 0o700)
        logging.info("Created secure directory: %s", dir_path)
    except FileExistsError:
        logging.info("Directory already exists: %s", dir_path)
    except Exception as e:
        raise RuntimeError(f"Unable to create directory {dir_path}: {e}")


def hash_file(path: Path) -> str:
    sha256 = hashlib.sha256()
    with path.open("rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            sha256.update(chunk)
    return sha256.hexdigest()


def process_remaining_files(target_dir: Path, excluded: Set[str]) -> None:
    for entry in target_dir.iterdir():
        if entry.is_file() and not entry.is_symlink() and entry.name not in excluded:
            try:
                file_hash = hash_file(entry)
                logging.info("Processed %s - SHA256: %s", entry.name, file_hash)
            except Exception as e:
                logging.warning("Could not process %s: %s", entry.name, str(e))


def main() -> None:
    configure_logging()
    try:
        args = parse_arguments()

        # Ensure output directory stays within the current working directory
        resolved_output = args.output_dir.resolve()
        if not resolved_output.is_relative_to(Path.cwd().resolve()):
            raise ValueError(f"Output directory must be within the current working directory: {resolved_output}")

        columns = safe_read_lines(args.columns_file)
        rows = safe_read_lines(args.rows_file)

        only_in_columns, only_in_rows = compute_differences(columns, rows)

        logging.info("Items only in columns file: %d", len(only_in_columns))
        logging.info("Items only in rows file: %d", len(only_in_rows))

        removal_criteria = only_in_columns

        remove_matching_files(args.target_dir, removal_criteria)

        create_secure_directory(args.output_dir)

        process_remaining_files(args.target_dir, removal_criteria)

    except Exception as exc:
        logging.error("An error occurred: %s", str(exc))
        sys.exit(1)


if __name__ == "__main__":
    main()

