import os
import re
import sqlite3
import logging
from typing import Any, Dict, Optional

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

_identifier_regex = re.compile(r"^[A-Za-z_][A-Za-z0-9_]*$")

_MAX_QUERY_LEN = 10_000
_MAX_PARAMS = 100
_ALLOWED_SQL = {"SELECT", "INSERT", "UPDATE", "DELETE", "REPLACE", "UPSERT"}


def _sanitize_identifier(name: str) -> str:
    """Allow only safe SQL identifiers (e.g., table or column names)."""
    if not isinstance(name, str):
        raise ValueError("Identifier must be a string")
    if not _identifier_regex.fullmatch(name):
        raise ValueError(f"Invalid identifier: {name}")
    return name


def _validate_scope(scope: Dict[str, Any]) -> Dict[str, str]:
    """Validate and sanitize identifiers supplied via scope."""
    if not isinstance(scope, dict):
        raise ValueError("Scope must be a dictionary")
    sanitized: Dict[str, str] = {}
    for key, value in scope.items():
        if not isinstance(key, str):
            raise ValueError("Scope keys must be strings")
        sanitized[key] = _sanitize_identifier(str(value))
    return sanitized


def _validate_parameters(params: Dict[str, Any]) -> Dict[str, Any]:
    """Ensure parameters are a dictionary with string keys and reasonable size."""
    if not isinstance(params, dict):
        raise ValueError("Parameters must be a dictionary")
    if len(params) > _MAX_PARAMS:
        raise ValueError(f"Too many parameters (max {_MAX_PARAMS})")
    for k in params.keys():
        if not isinstance(k, str):
            raise ValueError("Parameter keys must be strings")
    return params


def _substitute_identifiers(query_template: str, sanitized_scope: Dict[str, str]) -> str:
    """Safely replace {placeholders} in the query template with sanitized identifiers."""
    pattern = re.compile(r"{(\w+)}")

    def repl(match: re.Match) -> str:
        key = match.group(1)
        if key not in sanitized_scope:
            raise KeyError(f"Placeholder '{key}' not provided in scope")
        return sanitized_scope[key]

    return pattern.sub(repl, query_template)


def _validate_sql_statement(query: str) -> None:
    """Allow only whitelisted SQL statement types."""
    stripped = query.lstrip()
    if not stripped:
        raise ValueError("Query cannot be empty")
    first_word = stripped.split()[0].upper()
    if first_word not in _ALLOWED_SQL:
        raise ValueError(f"Disallowed SQL statement: {first_word}")


def _validate_db_path(db_path: str) -> str:
    """Validate that db_path is either ':memory:' or resides within the current working directory,
    resolving any symlinks."""
    if db_path == ":memory:":
        return db_path
    abs_path = os.path.abspath(db_path)
    real_path = os.path.realpath(abs_path)
    allowed_dir = os.path.realpath(os.getcwd())
    if not real_path.startswith(allowed_dir + os.sep):
        raise ValueError("Database path is outside the allowed directory")
    return real_path


def execute_query(
    query_template: str,
    scope: Dict[str, Any],
    parameters: Dict[str, Any],
    db_path: str = ":memory:",
) -> Optional[Any]:
    """Execute a parametrized SQL query safely.

    :param query_template: SQL statement with optional {placeholders} for identifiers.
    :param scope: Mapping of placeholder names to identifier values (e.g., table names).
    :param parameters: Mapping of parameter names to values for the query.
    :param db_path: Path to the SQLite database file.
    :return: Query result (list of rows) or None for non‑SELECT statements.
    """
    if not isinstance(query_template, str):
        raise ValueError("Query template must be a string")
    if len(query_template) > _MAX_QUERY_LEN:
        raise ValueError(f"Query template too long (max {_MAX_QUERY_LEN} characters)")

    sanitized_scope = _validate_scope(scope)
    safe_query = _substitute_identifiers(query_template, sanitized_scope)

    _validate_sql_statement(safe_query)

    safe_params = _validate_parameters(parameters)

    db_path = _validate_db_path(db_path)

    conn: Optional[sqlite3.Connection] = None
    try:
        conn = sqlite3.connect(
            db_path,
            detect_types=sqlite3.PARSE_DECLTYPES,
            isolation_level=None,
        )
        conn.row_factory = sqlite3.Row
        with conn:
            cur = conn.cursor()
            cur.execute(safe_query, safe_params)
            if cur.description:  # SELECT‑like query
                return [dict(row) for row in cur.fetchall()]
            return None
    except sqlite3.Error:
        logger.error("Database error while executing query")
        if logger.isEnabledFor(logging.DEBUG):
            logger.debug("Failed query: %s with params %s", safe_query, safe_params)
        return None
    finally:
        if conn is not None:
            try:
                conn.close()
            except Exception:
