import re
import json
import ast
import logging

logging.basicConfig(level=logging.ERROR, format='%(asctime)s %(levelname)s %(message)s')
logger = logging.getLogger(__name__)

MAX_ITEMS = 1000      # maximum number of elements in containers
MAX_DEPTH = 10        # maximum nesting depth for containers
MAX_CODE_LENGTH = 200
MAX_JSON_LENGTH = 2000

def _safe_json_repr(obj, max_length=MAX_JSON_LENGTH):
    try:
        s = json.dumps(obj, default=str)
        return s if len(s) <= max_length else s[: max_length - 3] + "..."
    except Exception:
        return "{}"

def _validate_structure(obj, depth=0):
    if depth > MAX_DEPTH:
        raise ValueError("Literal exceeds maximum nesting depth")
    if isinstance(obj, (list, tuple, set)):
        if len(obj) > MAX_ITEMS:
            raise ValueError("Container exceeds maximum size")
        for item in obj:
            _validate_structure(item, depth + 1)
    elif isinstance(obj, dict):
        if len(obj) > MAX_ITEMS:
            raise ValueError("Dictionary exceeds maximum size")
        for key, value in obj.items():
            _validate_structure(key, depth + 1)
            _validate_structure(value, depth + 1)

def modify_instance(instance, code_str):
    """
    Safely assign a literal value to an attribute of the given instance.
    The code string must be of the form: self.<attr> = <literal>
    """
    if not isinstance(code_str, str):
        raise ValueError("code must be a string")
    if len(code_str) > MAX_CODE_LENGTH:
        raise ValueError("code string too long")

    match = re.fullmatch(r'\s*self\.([A-Za-z_]\w*)\s*=\s*(.+)', code_str.strip())
    if not match:
        raise ValueError("code does not match allowed pattern")

    attr_name, value_expr = match.group(1), match.group(2)

    # Disallow magic/dunder attributes
    if attr_name.startswith("__") and attr_name.endswith("__"):
        raise ValueError("Assignment to magic attributes is prohibited")

    try:
        value = ast.literal_eval(value_expr)
    except Exception as exc:
        logger.error("Literal evaluation failed: %s", exc)
        print("Error: execution failed")
        return

    try:
        _validate_structure(value)
    except ValueError as exc:
        logger.error("Literal validation failed: %s", exc)
        print("Error: execution failed")
        return

    try:
        setattr(instance, attr_name, value)
    except Exception as exc:
        logger.error("Attribute assignment failed: %s", exc)
        print("Error: execution failed")
        return

    # Minimal safe output; avoid leaking sensitive data
    logger.debug("Attribute '%s' set on instance of %s", attr_name, type(instance).__name__)

import argparse
import os
import re
import shutil
import sys
import shlex
import urllib.parse
from pathlib import Path
from typing import List

# nosec: B404
import subprocess

class KickstartSetupError(Exception):
    """Custom exception for kickstart setup failures."""
    pass


def validate_hostname(hostname: str) -> str:
    """Validate hostname according to RFC 1123."""
    if not hostname:
        raise KickstartSetupError("Hostname cannot be empty")
    if len(hostname) > 255:
        raise KickstartSetupError("Hostname too long")
    if not re.fullmatch(
        r"(?!-)[A-Za-z0-9-]{1,63}(?<!-)(\.(?!-)[A-Za-z0-9-]{1,63}(?<!-))*",
        hostname,
    ):
        raise KickstartSetupError("Invalid hostname format")
    return hostname


def _normalize_path(path: str) -> str:
    """Normalize a URL path to prevent encoded traversal."""
    # Repeatedly unquote to handle double‑encoding
    previous = None
    current = path
    while previous != current:
        previous = current
        current = urllib.parse.unquote_plus(current)
    # Resolve any ".." segments
    return os.path.normpath(current)


def validate_basedir(basedir: str) -> str:
    """Validate basedir as either an absolute filesystem path or a safe HTTPS URL."""
    basedir = basedir.strip()
    parsed = urllib.parse.urlparse(basedir)

    # Allow only HTTPS URLs
    if parsed.scheme == "https":
        if not parsed.netloc:
            raise KickstartSetupError("Basedir URL must have a network location")
        # Disallow URLs with user info or port (optional, adjust as needed)
        if parsed.username or parsed.password:
            raise KickstartSetupError("Basedir URL must not contain credentials")
        normalized_path = _normalize_path(parsed.path)
        if ".." in normalized_path.split("/"):
            raise KickstartSetupError("Basedir URL path contains prohibited traversal")
        return basedir

    # Treat as a filesystem path
    path = Path(basedir).resolve()
    if not path.is_absolute():
        raise KickstartSetupError("Basedir must be an absolute path")
    if path.is_symlink():
        raise KickstartSetupError("Basedir must not be a symlink")
    if ".." in path.parts:
        raise KickstartSetupError("Basedir contains prohibited path traversal")
    return str(path)


def load_valid_timezones() -> List[str]:
    """Load timezone identifiers from the system zoneinfo directory."""
    tz_dir = Path("/usr/share/zoneinfo")
    if not tz_dir.is_dir():
        return []
    timezones = []
    for root, _, files in os.walk(tz_dir):
        for name in files:
            if name.startswith('.'):
                continue
            tz_path = Path(root) / name
            rel = tz_path.relative_to(tz_dir).as_posix()
            timezones.append(rel)
    return timezones


def validate_timezone(tz: str) -> str:
    """Validate timezone against system zoneinfo database."""
    tz = tz.strip()
    valid = load_valid_timezones()
    if tz not in valid:
        raise KickstartSetupError(f"Invalid timezone: {tz}")
    return tz


MAX_FILE_SIZE = 10 * 1024 * 1024  # 10 MiB


def _sanitize_for_shell(value: str) -> str:
    """Escape a string for safe inclusion in shell scripts."""
    return shlex.quote(value)


def _sanitize_plain(value: str) -> str:
    """Return a plain value for non‑shell contexts."""
    return value


def replace_placeholders(file_path: Path, hostname: str, basedir: str, timezone: str) -> None:
    """Replace placeholders in the file with sanitized values."""
    if file_path.stat().st_size > MAX_FILE_SIZE:
        raise KickscoreSetupError(f"File too large to process safely: {file_path}")

    try:
        content = file_path.read_text(encoding="utf-8")
    except (UnicodeDecodeError, OSError) as e:
        # Skip non‑text or unreadable files
        return

    # Choose appropriate sanitisation based on file type
    if file_path.suffix == ".sh":
        esc = _sanitize_for_shell
    else:
        esc = _sanitize_plain

    safe_hostname = esc(hostname)
    safe_basedir = esc(basedir)
    safe_timezone = esc(timezone)

    content = content.replace("{{HOSTNAME}}", safe_hostname)
    content = content.replace("{{BASEDIR}}", safe_basedir)
    content = content.replace("{{TIMEZONE}}", safe_timezone)

    try:
        file_path.write_text(content, encoding="utf-8")
    except OSError as e:
        raise KickstartSetupError(f"Unable to write file: {file_path}") from e


def copy_files(src_dir: Path, dst_dir: Path) -> None:
    """Copy all regular files from src_dir to dst_dir with restrictive permissions."""
    if not src_dir.is_dir():
        raise KickstartSetupError(f"Source directory does not exist: {src_dir}")
    dst_dir.mkdir(parents=True, exist_ok=True)

    for item in src_dir.iterdir():
        if item.is_symlink():
            continue  # skip symlinks for security
        if item.is_file():
            dest_file = dst_dir / item.name
            try:
                # Copy file data manually to enforce mode 0o640 at creation
                with item.open("rb") as src_f, os.open(
                    dest_file,
                    os.O_WRONLY | os.O_CREAT | os.O_TRUNC,
                    0o640,
                ) as fd:
                    with os.fdopen(fd, "wb") as dst_f:
                        shutil.copyfileobj(src_f, dst_f)
                # Preserve timestamps
                shutil.copystat(item, dest_file, follow_symlinks=False)
            except OSError as e:
                raise KickstartSetupError(f"Failed to copy {item} to {dest_file}") from e


def process_kickstart_files(dst_dir: Path, hostname: str, basedir: str, timezone: str) -> None:
    """Iterate over kickstart files and scripts to inject configuration."""
    for file_path in dst_dir.rglob("*"):
        if file_path.is_file() and file_path.suffix in {".ks", ".sh", ".cfg", ".txt"}:
            replace_placeholders(file_path, hostname, basedir, timezone)


def set_file_permissions(dst_dir: Path) -> None:
    """Set restrictive permissions on all files, preserving executability for scripts."""
    for file_path in dst_dir.rglob("*"):
        if file_path.is_file():
            try:
                if file_path.suffix == ".sh":
                    file_path.chmod(0o750)  # executable script
                else:
                    file_path.chmod(0o640)  # non‑executable
            except OSError as e:
                raise KickstartSetupError(f"Failed to set permissions on {file_path}") from e


def main() -> None:
    parser = argparse.ArgumentParser(description="Setup CentOS 7 kickstart configuration")
    parser.add_argument("--src", required=True, help="Source directory containing kickstart files")
    parser.add_argument("--dst", required=True, help="Destination directory for processed files")
    parser.add_argument("--hostname", required=True, help="Hostname to embed in configuration")
    parser.add_argument("--basedir", required=True, help="Base directory URL or absolute path of the kickstart server")
    parser.add_argument("--timezone", required=True, help="Timezone identifier (e.g., UTC, America/New_York)")

    args = parser.parse_args()

    try:
        src_dir = Path(args.src).resolve()
        if src_dir.is_symlink():
            raise KickstartSetupError("Source directory must not be a symlink")
        dst_dir = Path(args.dst).resolve()
        if dst_dir.is_symlink():
            raise KickstartSetupError("Destination directory must not be a symlink")
        hostname = validate_hostname(args.hostname.strip())
        basedir = validate_basedir(args.basedir.strip())
        timezone = validate_timezone(args.timezone.strip())
    except KickstartSetupError as e:
        sys.stderr.write(f"Input validation error: {e}\n")
        sys.exit(1)

    try:
        copy_files(src_dir, dst_dir)
        process_kickstart_files(dst_dir, hostname, basedir, timezone)
        set_file_permissions(dst_dir)
    except KickstartSetupError as e:
        sys.stderr.write(f"Setup failed: {e}\n")
        sys.exit(1)


if __name__ == "__main__":
    main()

