import logging
from typing import Any, Dict, Optional, Set, Union, List

import requests
from requests.exceptions import RequestException, Timeout
from urllib.parse import urlparse

# Trusted workspace hostnames
_TRUSTED_HOSTS: Set[str] = {"api.trusteddomain.com"}

# Configure logger (no sensitive data)
logger = logging.getLogger("ai_workspace_client")
if not logger.handlers:
    handler = logging.StreamHandler()
    formatter = logging.Formatter("%(asctime)s - %(levelname)s - %(message)s")
    handler.setFormatter(formatter)
    logger.addHandler(handler)
    logger.setLevel(logging.INFO)


def _sanitize_message(message: str, max_length: int = 2000) -> str:
    if not isinstance(message, str):
        raise ValueError("Message must be a string.")
    sanitized = message.strip()
    if not sanitized:
        raise ValueError("Message cannot be empty after stripping.")
    if len(sanitized) > max_length:
        sanitized = sanitized[:max_length]
    return sanitized


def _build_headers(api_key: str) -> Dict[str, str]:
    return {
        "Authorization": f"Bearer {api_key}",
        "Content-Type": "application/json",
        "Accept": "application/json",
    }


def _is_valid_json_primitive(value: Any) -> bool:
    return isinstance(value, (str, int, float, bool)) or value is None


def _validate_context(
    ctx: Dict[str, Any],
    max_items: int = 100,
    max_depth: int = 5,
    _current_depth: int = 0,
) -> Dict[str, Any]:
    if not isinstance(ctx, dict):
        raise ValueError("Context must be a dictionary.")
    if len(ctx) > max_items:
        raise ValueError("Context contains too many items.")
    if _current_depth > max_depth:
        raise ValueError("Context nesting depth exceeds limit.")

    validated: Dict[str, Any] = {}
    for key, value in ctx.items():
        if not isinstance(key, str):
            raise ValueError("Context keys must be strings.")
        if isinstance(value, dict):
            validated[key] = _validate_context(
                value,
                max_items=max_items,
                max_depth=max_depth,
                _current_depth=_current_depth + 1,
            )
        elif isinstance(value, list):
            if len(value) > max_items:
                raise ValueError("Context list exceeds maximum size.")
            validated_list: List[Any] = []
            for item in value:
                if isinstance(item, dict):
                    validated_list.append(
                        _validate_context(
                            item,
                            max_items=max_items,
                            max_depth=max_depth,
                            _current_depth=_current_depth + 1,
                        )
                    )
                elif _is_valid_json_primitive(item):
                    validated_list.append(item)
                else:
                    raise ValueError("Context list contains unsupported value type.")
            validated[key] = validated_list
        elif _is_valid_json_primitive(value):
            validated[key] = value
        else:
            raise ValueError("Context contains unsupported value type.")
    return validated


def _validate_workspace_url(url: str) -> None:
    if not isinstance(url, str):
        raise ValueError("workspace_url must be a string.")
    parsed = urlparse(url)
    if parsed.scheme != "https":
        raise ValueError("workspace_url must use HTTPS scheme.")
    if not parsed.hostname or parsed.hostname.lower() not in _TRUSTED_HOSTS:
        raise ValueError("workspace_url hostname is not trusted.")


def send_message(
    workspace_url: str,
    message: str,
    context: Optional[Dict[str, Any]] = None,
    api_key: Optional[str] = None,
    timeout: int = 10,
    max_retries: int = 5,
) -> Dict[str, Any]:
    _validate_workspace_url(workspace_url)

    if api_key is None:
        api_key = os.getenv("AI_WORKSPACE_API_KEY")
    if not api_key:
        raise ValueError("API key is required (parameter or AI_WORKSPACE_API_KEY env var).")

    sanitized_message = _sanitize_message(message)

    payload: Dict[str, Any] = {"message": sanitized_message}
    if isinstance(context, dict):
        payload["context"] = _validate_context(context)

    headers = _build_headers(api_key)

    attempt = 0
    backoff = 1  # seconds

    while attempt < max_retries:
        try:
            response = requests.post(
                workspace_url,
                headers=headers,
                json=payload,
                timeout=timeout,
                verify=True,
            )
            response.raise_for_status()
            try:
                data = response.json()
            except json.JSONDecodeError:
                logger.warning("Received non-JSON response from AI workspace.")
                raise RuntimeError("Invalid response format.")
            if not isinstance(data, dict) or "response" not in data:
                logger.warning("Unexpected response structure.")
                raise RuntimeError("Missing expected response content.")
            return data
        except (RequestException, Timeout, RuntimeError) as exc:
            logger.info(f"Attempt {attempt + 1}/{max_retries} failed, retrying...")
            attempt += 1
            time.sleep(backoff)
            backoff = min(backoff * 2, 30)

    raise RuntimeError("Failed to obtain a valid response after multiple attempts.")

