import os
import sys
import gzip
import urllib.parse
import io
from pathlib import Path
from typing import Dict, Iterable, TextIO

# Limits for safety
MAX_FILE_SIZE = 100 * 1024 * 1024          # 100 MiB input size limit
MAX_UNCOMPRESSED_SIZE = 500 * 1024 * 1024  # 500 MiB after decompression
MAX_LINE_COUNT = 2_000_000                # 2 million lines

class GFF3ConversionError(Exception):
    """Custom exception for GFF3 to GTF conversion errors."""
    pass

def _is_gzip(path: Path) -> bool:
    """Check if a file is gzip-compressed by magic number."""
    try:
        with path.open('rb') as f:
            return f.read(2) == b'\x1f\x8b'
    except OSError as exc:
        raise GFF3ConversionError("Unable to read input file.") from exc

def _secure_open_read(path: Path) -> TextIO:
    """
    Open a file for reading securely, avoiding symlink races.
    Returns a text-mode file object.
    """
    fd = os.open(
        str(path),
        os.O_RDONLY | os.O_NOFOLLOW,
    )
    try:
        # Binary file object, then wrap for text decoding
        raw = os.fdopen(fd, "rb")
        return io.TextIOWrapper(raw, encoding="utf-8", errors="replace")
    except Exception:
        os.close(fd)
        raise

def _secure_open_write(path: Path) -> TextIO:
    """
    Open a file for writing securely, avoiding symlink races.
    Returns a text-mode file object.
    """
    fd = os.open(
        str(path),
        os.O_WRONLY | os.O_CREAT | os.O_TRUNC | os.O_NOFOLLOW,
        0o644,
    )
    try:
        raw = os.fdopen(fd, "wb")
        return io.TextIOWrapper(raw, encoding="utf-8", errors="replace")
    except Exception:
        os.close(fd)
        raise

def _open_input(path: Path) -> TextIO:
    """Open a file safely, handling gzip if needed, and enforce size limits."""
    try:
        if path.stat().st_size > MAX_FILE_SIZE:
            raise GFF3ConversionError("Input file exceeds maximum allowed size.")
        if _is_gzip(path):
            # gzip.open returns a binary file; open in text mode for consistency
            gz = gzip.open(path, mode="rt", encoding="utf-8", errors="replace")
            # Wrap to enforce uncompressed size limit via read checks
            return _LimitedReader(gz, MAX_UNCOMPRESSED_SIZE)
        else:
            return _secure_open_read(path)
    except OSError as exc:
        raise GFF3ConversionError("Failed to open input file.") from exc

class _LimitedReader(io.TextIOBase):
    """
    Wrapper around a text file object that aborts if the total number of
    bytes read exceeds a specified limit.
    """
    def __init__(self, base: TextIO, max_bytes: int):
        self._base = base
        self._remaining = max_bytes

    def __iter__(self):
        return self

    def __next__(self):
        line = self._base.readline()
        if not line:
            raise StopIteration
        self._consume(len(line.encode(self._base.encoding or "utf-8")))
        return line

    def read(self, size=-1):
        data = self._base.read(size)
        self._consume(len(data.encode(self._base.encoding or "utf-8")))
        return data

    def _consume(self, byte_count: int):
        self._remaining -= byte_count
        if self._remaining < 0:
            raise GFF3ConversionError("Uncompressed data exceeds allowed size.")

    def close(self):
        self._base.close()

def _sanitize_path(p: str) -> Path:
    """Validate and resolve a filesystem path."""
    if not isinstance(p, str) or not p.strip():
        raise GFF3ConversionError("Invalid path string.")
    try:
        path = Path(p).expanduser().resolve(strict=False)
    except Exception as exc:
        raise GFF3ConversionError("Path resolution failed.") from exc
    home = Path.home().resolve()
    try:
        # Python 3.9+: is_relative_to ensures proper prefix checking
        if not path.is_relative_to(home):
            raise GFF3ConversionError("Path outside allowed directory.")
    except AttributeError:
        # Fallback for older Python versions
        if home not in path.parents and path != home:
            raise GFF3ConversionError("Path outside allowed directory.")
    return path

def _sanitize_attribute_value(val: str) -> str:
    """Remove problematic control characters from attribute values."""
    # Replace newlines, carriage returns, tabs with space; strip null bytes
    return val.replace("\r", " ").replace("\n", " ").replace("\t", " ").replace("\0", "")

def _parse_attributes(attr_str: str) -> Dict[str, str]:
    """Parse GFF3 attribute column into a dict with sanitisation."""
    attrs = {}
    for part in filter(None, attr_str.split(";")):
        if "=" not in part:
            continue
        key, val = part.split("=", 1)
        key = key.strip()
        val = urllib.parse.unquote(val.strip())
        val = _sanitize_attribute_value(val)
        attrs[key] = val
    return attrs

def _format_gtf_attributes(attrs: Dict[str, str], dialect: str) -> str:
    """Convert attribute dict to GTF attribute string."""
    key_map = {}
    if dialect == "ensembl":
        key_map = {
            "ID": "gene_id",
            "Parent": "transcript_id",
        }
    formatted = []
    for k, v in attrs.items():
        out_key = key_map.get(k, k)
        sanitized = _sanitize_attribute_value(v)
        escaped = sanitized.replace('"', '\\"')
        formatted.append(f'{out_key} "{escaped}";')
    return " ".join(formatted)

def gff3_to_gtf(input_path: str, output_path: str, dialect: str = "default") -> None:
    """
    Convert a GFF3 file (optionally gzipped) to GTF format.
    """
    try:
        src = _sanitize_path(input_path)
        dst = _sanitize_path(output_path)

        if not src.is_file():
            raise GFF3ConversionError("Source file does not exist.")
        if dst.exists() and not dst.is_file():
            raise GFF3ConversionError("Destination path is not a regular file.")

        with _open_input(src) as fin, _secure_open_write(dst) as fout:
            line_count = 0
            for line in fin:
                if not line or line.startswith("#"):
                    continue
                line_count += 1
                if line_count > MAX_LINE_COUNT:
                    raise GFF3ConversionError("Input file exceeds maximum line count.")
                fields = line.rstrip("\n").split("\t")
                if len(fields) != 9:
                    continue  # Skip malformed lines safely
                seqid, source, feature_type, start, end, score, strand, phase, attributes = fields
                attr_dict = _parse_attributes(attributes)
                gtf_attrs = _format_gtf_attributes(attr_dict, dialect)
                gtf_line = "\t".join(
                    [seqid, source, feature_type, start, end, score, strand, phase, gtf_attrs]
                )
                fout.write(gtf_line + "\n")
    except GFF3ConversionError:
        raise
    except Exception as exc:
        sys.stderr.write("An error occurred during conversion.\n")
        raise GFF3ConversionError("Conversion failed.") from exc

