import os
import sys
import pickle
from pathlib import Path
from typing import Any, Dict, List

import numpy as np
from PIL import Image, UnidentifiedImageError

# Configure logger – do not expose internal details
logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s - %(levelname)s - %(message)s",
    handlers=[logging.StreamHandler(sys.stdout)],
)
logger = logging.getLogger(__name__)

# Constants for validation
MAX_JSON_SIZE = 10 * 1024 * 1024  # 10 MiB
MAX_IMAGE_SIZE = 20 * 1024 * 1024  # 20 MiB
MAX_ANNOTATIONS = 10_000
MAX_PIXELS = 50_000_000  # 50 MP
ALLOWED_IMAGE_EXTENSIONS = {".jpg", ".jpeg", ".png", ".bmp", ".tiff"}

# ---------- Secure pickle loading ----------
class RestrictedUnpickler(pickle.Unpickler):
    safe_builtins = {
        "builtins": {
            "list",
            "dict",
            "tuple",
            "set",
            "frozenset",
            "int",
            "float",
            "str",
            "bytes",
        },
    }

    def find_class(self, module: str, name: str) -> Any:
        if module == "numpy" and name == "ndarray":
            import numpy

            return numpy.ndarray
        if module in self.safe_builtins and name in self.safe_builtins[module]:
            return getattr(__builtins__, name)
        raise pickle.UnpicklingError(f"Attempted to unpickle unsafe class {module}.{name}")


def safe_load_pickle(file_path: Path) -> Any:
    try:
        with file_path.open("rb") as f:
            data = RestrictedUnpickler(f).load()
    except (pickle.UnpicklingError, EOFError, AttributeError, ImportError, IndexError) as e:
        logger.error("Failed to load pickle file safely.")
        raise RuntimeError("Corrupt or unsafe pickle data.") from e

    if isinstance(data, np.ndarray):
        if data.dtype == object or not np.issubdtype(data.dtype, np.number):
            raise pickle.UnpicklingError("Object‑dtype or non‑numeric arrays are not allowed")
    return data


# ---------- Input validation ----------
def validate_file_path(path_str: str) -> Path:
    p = Path(path_str).expanduser().resolve()
    if not p.is_file():
        raise FileNotFoundError(f"File not found: {p}")
    return p


def validate_json_file(json_path: Path) -> Dict:
    if json_path.stat().st_size > MAX_JSON_SIZE:
        raise ValueError("JSON file exceeds maximum allowed size.")
    try:
        with json_path.open("r", encoding="utf-8") as f:
            data = json.load(f)
    except json.JSONDecodeError as e:
        raise ValueError("Invalid JSON format.") from e

    if not isinstance(data, (list, dict)):
        raise ValueError("JSON must contain a list or dict of annotations.")

    # Normalize to list for counting
    entries = data if isinstance(data, list) else [data]
    if len(entries) > MAX_ANNOTATIONS:
        raise ValueError(f"Number of annotation entries exceeds limit ({MAX_ANNOTATIONS}).")
    return data


def validate_image_file(img_path: Path) -> Path:
    if img_path.suffix.lower() not in ALLOWED_IMAGE_EXTENSIONS:
        raise ValueError(f"Unsupported image extension: {img_path.suffix}")
    if img_path.stat().st_size > MAX_IMAGE_SIZE:
        raise ValueError("Image file exceeds maximum allowed size.")
    return img_path


# ---------- Feature extraction ----------
def extract_image_features(image_path: Path, vocab: np.ndarray) -> np.ndarray:
    """
    Load an image, compute a simple normalized RGB histogram (256 bins per channel),
    flatten it, then project onto the vocabulary matrix.
    """
    try:
        with Image.open(image_path) as img:
            img = img.convert("RGB")
            width, height = img.size
            if width * height > MAX_PIXELS:
                raise ValueError("Image dimensions exceed allowed pixel count.")
            histogram = np.concatenate(
                [
                    np.array(img.histogram()[i * 256 : (i + 1) * 256], dtype=np.float32)
                    for i in range(3)
                ]
            )
    except (UnidentifiedImageError, OSError, ValueError) as e:
        raise ValueError(f"Unable to process image {image_path.name}: {e}")

    if histogram.sum() == 0:
        normalized_hist = histogram
    else:
        normalized_hist = histogram / histogram.sum()

    if vocab.ndim != 2 or vocab.shape[1] != normalized_hist.shape[0]:
        raise ValueError("Vocabulary dimensions do not match feature vector size.")

    return vocab @ normalized_hist


# ---------- Main processing ----------
def process_dataset(
    annotations_path: Path,
    vocab_path: Path,
    image_root: Path,
) -> List[Dict[str, Any]]:
    """
    Returns a list where each entry corresponds to an image and contains:
        - 'image_path': original relative path
        - 'features': extracted feature vector (list of floats)
        - any annotation data associated with the image
    """
    annotations = validate_json_file(annotations_path)
    vocab = safe_load_pickle(vocab_path)

    if not isinstance(vocab, np.ndarray):
        raise TypeError("Vocabulary must be a NumPy ndarray.")

    results: List[Dict[str, Any]] = []

    if isinstance(annotations, dict):
        annotations = [annotations]

    for entry in annotations:
        if not isinstance(entry, dict) or "filename" not in entry:
            logger.warning("Skipping malformed annotation entry.")
            continue

        img_rel_path = entry["filename"]
        try:
            img_path = (image_root / img_rel_path).resolve()
            # Ensure the resolved path stays within the image_root directory
            try:
                img_path.relative_to(image_root)
            except ValueError:
                raise ValueError(f"Image path escapes allowed directory: {img_path}")

            validate_image_file(img_path)
            feats = extract_image_features(img_path, vocab)
            results.append(
                {
                    "image_path": img_rel_path,
                    "features": feats.tolist(),
                    "annotation": entry,
                }
            )
        except Exception as e:
            # Log only the relative path to avoid leaking full filesystem details
            logger.error(f"Failed processing image {img_rel_path}: {e}")
            continue

    return results


def main() -> None:
    parser = argparse.ArgumentParser(description="Process image dataset securely.")
    parser.add_argument(
        "--annotations",
        required=True,
        type=str,
        help="Path to JSON file with image annotations.",
    )
    parser.add_argument(
        "--vocab",
        required=True,
        type=str,
        help="Path to pickled NumPy vocabulary.",
    )
    parser.add_argument(
        "--image-dir",
        required=True,
        type=str,
        help="Root directory containing images referenced in annotations.",
    )
    parser.add_argument(
        "--output",
        required=False,
        type=str,
        default="features_output.json",
        help="File to write extracted features (JSON).",
    )

    args = parser.parse_args()

    try:
        annotations_path = validate_file_path(args.annotations)
        vocab_path = validate_file_path(args.vocab)
        image_root = Path(args.image_dir).expanduser().resolve()
        if not image_root.is_dir():
            raise FileNotFoundError(f"Image directory not found: {image_root}")
    except Exception as e:
        logger.error(f"Input validation error: {e}")
        sys.exit(1)

    try:
        features = process_dataset(annotations_path, vocab_path, image_root)
        output_path = Path(args.output).expanduser().resolve()
        with output_path.open("w", encoding="utf-8") as f:
            json.dump(features, f, ensure_ascii=False, indent=2)
        logger.info(f"Feature extraction completed. Results saved to {output_path}")
    except Exception as e:
        logger.error(f"Processing failed: {e}")
        sys.exit(1)


