PREDEFINED_FASTA: Final[Path] = Path("/opt/ref/predefined.fasta").resolve()
PREDEFINED_GTF: Final[Path] = Path("/opt/ref/predefined.gtf").resolve()

# Directory where target files are allowed to reside
