def _is_safe_path(path: Path) -> bool:
    """Return True if *path* is an existing regular file and not a symlink."""
    try:
        return path.is_file() and not path.is_symlink()
    except Exception:
        return False


def _ensure_target_safe(dst: Path) -> None:
    """Validate that *dst* is within SAFE_BASE and is not a directory or symlink."""
    if dst.is_dir():
        raise ValueError("Target path must be a file, not a directory.")
    if dst.is_symlink():
        raise ValueError("Destination path must not be a symlink.")
    try:
        resolved = dst.resolve(strict=False)
    except Exception:
        raise ValueError("Unable to resolve target path.")
    if not resolved.is_relative_to(SAFE_BASE):
        raise ValueError("Target path is outside the permitted directory.")
    if not resolved.parent.is_dir():
        raise FileNotFoundError(f"Parent directory does not exist: {resolved.parent}")


def _open_destination(dst: Path):
    """Open *dst* for appending securely, rejecting symlinks atomically."""
    flags = os.O_WRONLY | os.O_CREAT | os.O_APPEND | os.O_NOFOLLOW | os.O_CLOEXEC
    mode = 0o660
    try:
        fd = os.open(str(dst), flags, mode)
    except OSError as exc:
        logger.error("Failed to open destination file.")
        raise
    return os.fdopen(fd, "ab")


def _append_file_secure(source: Path, destination: Path) -> None:
    """Append contents of *source* to *destination* using secure file handling."""
    try:
        with source.open("rb") as src, _open_destination(destination) as dst:
            while True:
                chunk = src.read(8192)
                if not chunk:
                    break
                dst.write(chunk)
    except OSError:
        logger.error("Failed to append file securely.")
        raise


def append_reference_files(gtf_path: str, fasta_path: str) -> None:
    """
    Append the predefined FASTA and GTF files to the user‑provided files.

    Parameters
    ----------
    gtf_path : str
        Path to the target GTF file.
    fasta_path : str
        Path to the target FASTA file.
    """
    try:
        target_gtf = Path(gtf_path)
        target_fasta = Path(fasta_path)
    except Exception:
        logger.error("Invalid input path supplied.")
        raise ValueError("Provided path is invalid.") from None

    # Ensure targets are within the allowed directory and safe
    for dst in (target_gtf, target_fasta):
        _ensure_target_safe(dst)

    # Validate the predefined source files
    if not _is_safe_path(PREDEFINED_FASTA):
        logger.error("Predefined FASTA file is missing or unsafe.")
        raise FileNotFoundError("Reference FASTA not found.")
    if not _is_safe_path(PREDEFINED_GTF):
        logger.error("Predefined GTF file is missing or unsafe.")
        raise FileNotFoundError("Reference GTF not found.")

    # Perform the secure append operations
    _append_file_secure(PREDEFINED_FASTA, target_fasta)
    _append_file_secure(PREDEFINED_GTF, target_gtf)

