import logging
import multiprocessing
import os
import signal
from types import FunctionType, BuiltinFunctionType, MethodType
from typing import List, Tuple, Any, Callable, Dict

# ----------------------------------------------------------------------
# Configuration
# ----------------------------------------------------------------------
_MAX_TEST_CASES = 10_000
_DEFAULT_TIMEOUT = 5.0  # seconds
_MAX_WORKERS = 4  # limit concurrent child processes
_SEMAPHORE = multiprocessing.Semaphore(_MAX_WORKERS)

# ----------------------------------------------------------------------
# Logging
# ----------------------------------------------------------------------
logging.basicConfig(
    level=logging.ERROR,
    format="%(asctime)s %(levelname)s %(message)s",
    stream=sys.stderr,
)

# ----------------------------------------------------------------------
# Validation helpers
# ----------------------------------------------------------------------
_VALID_NAME_RE = re.compile(r"[A-Za-z_][A-Za-z0-9_]*")
_ALLOWED_RESULT_TYPES = (str, int, float, bool, type(None))

_PROHIBITED_AST_NODES = (
    ast.Import,
    ast.ImportFrom,
    ast.Call,
    ast.Attribute,
)

_PROHIBITED_CALL_NAMES = {
    "open",
    "exec",
    "eval",
    "compile",
    "__import__",
    "system",
    "popen",
    "run",
    "call",
    "check_output",
    "os",
    "sys",
    "subprocess",
    "socket",
    "shutil",
    "pathlib",
}


def _is_valid_name(name: str) -> bool:
    """Validate that the name is a simple identifier."""
    return bool(_VALID_NAME_RE.fullmatch(name))


def _is_safe_callable(func: Callable[[], Any]) -> bool:
    """
    Perform a static AST check for user‑defined functions.
    Built‑in functions and methods are considered safe.
    """
    if isinstance(func, (BuiltinFunctionType, MethodType)):
        return True
    try:
        source = inspect.getsource(func)
    except (OSError, TypeError):
        # Unable to retrieve source – treat as unsafe
        return False
    try:
        tree = ast.parse(source)
    except SyntaxError:
        return False

    for node in ast.walk(tree):
        if isinstance(node, _PROHIBITED_AST_NODES):
            if isinstance(node, ast.Import) or isinstance(node, ast.ImportFrom):
                return False
            if isinstance(node, ast.Call):
                # Detect calls to prohibited functions by name
                if isinstance(node.func, ast.Name) and node.func.id in _PROHIBITED_CALL_NAMES:
                    return False
                if isinstance(node.func, ast.Attribute):
                    attr = node.func.attr
                    if attr in _PROHIBITED_CALL_NAMES:
                        return False
            if isinstance(node, ast.Attribute):
                # Attribute access like os.path, sys.argv, etc.
                if isinstance(node.value, ast.Name) and node.value.id in _PROHIBITED_CALL_NAMES:
                    return False
    return True


def _serialize_result(result: Any) -> str:
    """Serialize a result that is guaranteed to be JSON‑compatible primitive."""
    if not isinstance(result, _ALLOWED_RESULT_TYPES):
        raise TypeError("Result type not allowed")
    return json.dumps(result)


def _deserialize_result(payload: str) -> Any:
    """Deserialize the JSON payload back to a Python primitive."""
    return json.loads(payload)


def _execute_in_process(func: Callable[[], Any], timeout: float) -> Tuple[bool, Any]:
    """
    Execute ``func`` in a separate process with a timeout.
    Communication uses a one‑way Pipe with JSON‑encoded, whitelisted data.
    Returns (True, result) on success, (False, Exception) on failure/timeout.
    """
    def _worker(conn):
        # Create a new process group so we can kill all children if needed
        try:
            os.setsid()
        except Exception:
            pass  # setsid may not be available on some platforms
        try:
            result = func()
            payload = _serialize_result(result)
            conn.send((True, payload))
        except Exception as exc:
            # Send exception information safely (type name and message)
            err_info = {"type": type(exc).__name__, "msg": str(exc)}
            conn.send((False, json.dumps(err_info)))
        finally:
            conn.close()

    parent_conn, child_conn = multiprocessing.Pipe(duplex=False)
    process = multiprocessing.Process(target=_worker, args=(child_conn,))
    process.start()
