import stat
from pathlib import Path

_logger = logging.getLogger(__name__)
_logging_handler = logging.StreamHandler()
_logging_handler.setFormatter(
    logging.Formatter("%(asctime)s - %(levelname)s - %(message)s")
)
_logger.addHandler(_logging_handler)
_logger.setLevel(logging.INFO)

_KEY_PATTERN = re.compile(r"^[A-Za-z_][A-Za-z0-9_]*$")

def _sanitize_key(key: str) -> str:
    key = key.strip()
    if not _KEY_PATTERN.fullmatch(key):
        raise ValueError("Invalid setting key")
    return key

def _sanitize_value(value: str) -> str:
    """
    Basic sanitisation for values.
    - Strips surrounding whitespace.
    - Rejects non‑printable characters (including control chars and NUL).
    """
    value = value.strip()
    if not value.isprintable():
        raise ValueError("Non‑printable characters in setting value")
    return value

def _parse_line(line: str) -> tuple[str, str] | None:
    # Remove comments
    line = line.split("#", 1)[0].strip()
    if not line or "=" not in line:
        return None
    key, value = line.split("=", 1)
    try:
        key = _sanitize_key(key)
        value = _sanitize_value(value)
    except ValueError:
        return None
    return key, value

def _is_path_within_base(path: Path, base: Path) -> bool:
    try:
        base_resolved = base.resolve(strict=True)
        path_resolved = path.resolve(strict=True)
    except Exception:
        return False
    return str(path_resolved).startswith(str(base_resolved) + os.sep)

def _check_file_permissions(path: Path) -> bool:
    try:
        st = path.stat()
    except Exception:
        return False
    # Ensure regular file
    if not stat.S_ISREG(st.st_mode):
        return False
    # Owner must be the current user
    if hasattr(os, "getuid") and st.st_uid != os.getuid():
        return False
    # Disallow group or other read/write/execute permissions
    if st.st_mode & (stat.S_IRWXG | stat.S_IRWXO):
        return False
    return True

def load_settings(file_path: str, defaults: dict, *, base_dir: Path | None = None) -> dict:
    """
    Reads a settings file and returns a dictionary of key/value pairs.
    Missing keys are filled with values from ``defaults``.
    The file must reside inside ``base_dir`` (default: current working directory),
    be a regular file owned by the current user, and have restrictive permissions (0600).
    Errors are handled without leaking sensitive information.
    """
    if not isinstance(file_path, str):
        raise TypeError("file_path must be a string")
    if not isinstance(defaults, dict):
        raise TypeError("defaults must be a dictionary")

    # Resolve the requested path safely
    try:
        path = Path(file_path).expanduser()
        # Resolve without strict to allow existence check later
        path = path.resolve(strict=False)
    except Exception:
        _logger.warning("Unable to resolve settings path")
        return copy.deepcopy(defaults)

    # Determine base directory for restriction
    if base_dir is None:
        base_dir = Path.cwd()
    else:
        if not isinstance(base_dir, Path):
            raise TypeError("base_dir must be a pathlib.Path instance")

    # Enforce path is within the allowed base directory
    if not _is_path_within_base(path, base_dir):
        _logger.warning("Settings file outside allowed directory")
        return copy.deepcopy(defaults)

    # Ensure the file exists and is a regular file with proper permissions
    if not path.is_file() or not _check_file_permissions(path):
        _logger.info("Settings file not found or insecure, using defaults")
        return copy.deepcopy(defaults)

    settings = copy.deepcopy(defaults)

    try:
        with path.open("r", encoding="utf-8") as fh:
            for raw_line in fh:
                parsed = _parse_line(raw_line)
                if parsed is None:
                    continue
                key, value = parsed
                settings[key] = value
    except (OSError, PermissionError):
        _logger.warning("Unable to read settings file")
        return copy.deepcopy(defaults)
    except Exception:
        _logger.error("Unexpected error while processing settings")
        return copy.deepcopy(defaults)

    return settings

