import os
import re
import sys
from pathlib import Path
from typing import Dict, List, Tuple

# Constants for security
MAX_STAT_FILE_SIZE = 5 * 1024 * 1024            # 5 MB
MAX_ALIGNMENT_FILE_SIZE = 20 * 1024 * 1024     # 20 MB
MAX_TOTAL_ALIGNMENT_SIZE = 100 * 1024 * 1024   # 100 MB combined
ALLOWED_ALIGNMENT_EXTENSIONS = {'.fa', '.fasta', '.aln', '.phy'}

# Define safe roots
SAFE_ROOT = Path.cwd().resolve()
SAFE_OUTPUT_ROOT = SAFE_ROOT / "reports"

class ReportGenerationError(Exception):
    """Custom exception for report generation failures without leaking details."""
    pass

def _is_within(root: Path, target: Path) -> bool:
    try:
        target.relative_to(root)
        return True
    except ValueError:
        return False

def _validate_directory(dir_path: Path) -> Path:
    try:
        resolved = dir_path.resolve(strict=True)
    except Exception:
        raise ReportGenerationError("Could not resolve directory.")
    if not resolved.is_dir():
        raise ReportGenerationError("Provided path is not a directory.")
    if not _is_within(SAFE_ROOT, resolved):
        raise ReportGenerationError("Directory is outside the allowed area.")
    return resolved

def _read_statistic_file(stat_path: Path) -> Dict[str, str]:
    if not stat_path.is_file():
        raise ReportGenerationError("Statistic file not found.")
    if not os.access(stat_path, os.R_OK):
        raise ReportGenerationError("Statistic file is not readable.")
    if stat_path.stat().st_size > MAX_STAT_FILE_SIZE:
        raise ReportGenerationError("Statistic file exceeds allowed size.")
    try:
        with stat_path.open('r', encoding='utf-8') as f:
            content = f.read()
    except Exception:
        raise ReportGenerationError("Unable to read statistic file.")
    pattern = re.compile(r'^\s*(Reticulations|Taxa|Increase|Decrease|Outgroup):\s*(.+?)\s*$', re.MULTILINE)
    matches = pattern.findall(content)
    if not matches:
        raise ReportGenerationError("Statistic file format invalid.")
    stats = {key: value for key, value in matches}
    required_keys = {'Reticulations', 'Taxa', 'Increase', 'Decrease', 'Outgroup'}
    if not required_keys.issubset(stats.keys()):
        raise ReportGenerationError("Missing required statistics.")
    return stats

def _resize_values(stats: Dict[str, str], coeff: float) -> Tuple[str, str]:
    try:
        inc = float(stats['Increase'])
        dec = float(stats['Decrease'])
    except ValueError:
        raise ReportGenerationError("Increase/Decrease values must be numeric.")
    inc_resized = f"{inc * coeff:g}"
    dec_resized = f"{dec * coeff:g}"
    return inc_resized, dec_resized

def _gather_alignment_files(base_dir: Path) -> List[Path]:
    alignment_files = []
    total_size = 0
    for entry in base_dir.iterdir():
        # Skip symlinks and non-files
        if not entry.is_file(follow_symlinks=False):
            continue
        if entry.suffix.lower() not in ALLOWED_ALIGNMENT_EXTENSIONS:
            continue
        # Verify the resolved path stays within the base directory
        try:
            resolved = entry.resolve(strict=True)
        except Exception:
            continue
        if not _is_within(base_dir, resolved):
            continue
        # Size checks
        size = resolved.stat().st_size
        if size > MAX_ALIGNMENT_FILE_SIZE:
            continue
        total_size += size
        if total_size > MAX_TOTAL_ALIGNMENT_SIZE:
            raise ReportGenerationError("Total size of alignment files exceeds allowed limit.")
        alignment_files.append(resolved)
    if not alignment_files:
        raise ReportGenerationError("No alignment files found.")
    return alignment_files

def _secure_open_write(file_path: Path):
    flags = os.O_WRONLY | os.O_CREAT | os.O_TRUNC
    # Permissions: owner read/write only (0o600)
    fd = os.open(str(file_path), flags, 0o600)
    return os.fdopen(fd, 'w', encoding='utf-8')

def generate_report(input_dir: str, output_file: str, coefficient: float = 1.0) -> None:
    """
    Generates a report from statistics and alignment files inside input_dir.
    The report is written to output_file.
    """
    try:
        coeff = float(coefficient)
    except ValueError:
        raise ReportGenerationError("Coefficient must be a numeric value.")
    if coeff <= 0:
        raise ReportGenerationError("Coefficient must be positive.")

    base_dir = _validate_directory(Path(input_dir))
    statistic_path = base_dir / "statistics.txt"
    stats = _read_statistic_file(statistic_path)

    inc_resized, dec_resized = _resize_values(stats, coeff)

    alignment_files = _gather_alignment_files(base_dir)

    out_path = Path(output_file).resolve()
    # Ensure output path is within allowed output root
    if not _is_within(SAFE_OUTPUT_ROOT, out_path):
        raise ReportGenerationError("Output file is outside the allowed directory.")
    # Ensure parent directory exists and is writable
    try:
        out_path.parent.mkdir(parents=True, exist_ok=True)
    except Exception:
        raise ReportGenerationError("Could not create output directory.")
    if not os.access(out_path.parent, os.W_OK):
        raise ReportGenerationError("Output directory is not writable.")

    try:
        with _secure_open_write(out_path) as out_f:
            # Write header information
            out_f.write(f"Reticulations: {stats['Reticulations']}\n")
            out_f.write(f"Taxa: {stats['Taxa']}\n")
            out_f.write(f"Increase: {inc_resized}\n")
            out_f.write(f"Decrease: {dec_resized}\n")
            out_f.write(f"Outgroup: {stats['Outgroup']}\n")
            out_f.write("\nConcatenated Alignments:\n")
            # Stream each alignment file directly to the report
            for aln_path in alignment_files:
                if not os.access(aln_path, os.R_OK):
                    continue  # Skip unreadable files
                try:
                    with aln_path.open('r', encoding='utf-8') as aln_f:
                        for line in aln_f:
                            out_f.write(line)
                except Exception:
                    continue  # Skip files that raise errors during read
    except Exception:
        raise ReportGenerationError("Failed to write the report file.")

import hashlib
import copy
from typing import Any, Union


_ALLOWED_ALGORITHMS = {
    'SHA-256': 'sha256',
    'SHA-384': 'sha384',
    'SHA-512': 'sha512',
}


def _validate_algorithm(algorithm: str) -> str:
    if not isinstance(algorithm, str):
        raise TypeError("Algorithm name must be a string")
    algo_key = algorithm.strip().upper()
    if algo_key not in _ALLOWED_ALGORITHMS:
        raise ValueError(f"Unsupported algorithm: {algorithm}")
    return algo_key


def _validate_input(data: Any) -> bytes:
    if isinstance(data, bytes):
        return data
    if isinstance(data, str):
        return data.encode('utf-8')
    raise TypeError("Input data must be a string or bytes")


class HashWrapper:
    def __init__(self, algorithm: str = 'SHA-256'):
        self._algo_name = _validate_algorithm(algorithm)
        self._hasher = hashlib.new(_ALLOWED_ALGORITHMS[self._algo_name])

    def update(self, data: Union[str, bytes]) -> None:
        encoded = _validate_input(data)
        self._hasher.update(encoded)

    def digest(self) -> str:
        return self._hasher.hexdigest()

    def clone(self) -> 'HashWrapper':
        cloned = HashWrapper(self._algo_name)
        cloned._hasher = self._hasher.copy()
        return cloned


def compute_hash(data: Union[str, bytes], algorithm: str = 'SHA-256') -> str:
    wrapper = HashWrapper(algorithm)
    wrapper.update(data)
    return wrapper.digest()

