logger = logging.getLogger(__name__)

_UID_REGEX = re.compile(r"^[0-9a-fA-F]{24}$")  # MongoDB ObjectId format
_TOKEN_REGEX = re.compile(r"^[A-Za-z0-9\-_]{43}$")  # URL‑safe base64 without padding


def _constant_time_compare(val1: str, val2: str) -> bool:
    """Compare two strings in constant time to avoid timing attacks."""
    return hmac.compare_digest(val1, val2)


class BaseResetView:
    """Superclass providing shared functionality for reset related views."""

    login_endpoint: str = "login"

    def _get_login_url(self) -> str:
        """Return absolute login URL using Flask's url_for."""
        try:
            return url_for(self.login_endpoint, _external=True)
        except Exception as exc:  # pragma: no cover
            logger.error("Failed to generate login URL: %s", exc)
            abort(500)

    def _render(self, template_name: str, **context):
        """Render a template safely, ensuring context values are escaped."""
        try:
            safe_context = {
                k: escape(v) if isinstance(v, str) else v for k, v in context.items()
            }
            safe_context["login_url"] = self._get_login_url()
            return render_template(template_name, **safe_context)
        except Exception as exc:  # pragma: no cover
            logger.error("Template rendering error: %s", exc)
            abort(500)

    def _validate_uid(self, uid: str) -> bool:
        return bool(_UID_REGEX.fullmatch(uid))

    def _validate_token(self, token: str) -> bool:
        return bool(_TOKEN_REGEX.fullmatch(token))

    def _verify_token(self, uid: str, token: str, verifier: Callable[[str, str], bool]) -> bool:
        try:
            return verifier(uid, token)
        except Exception as exc:  # pragma: no cover
            logger.warning("Token verification raised an exception")
            return False


class PasswordResetRequestView(BaseResetView):
    """View handling password‑reset link rendering."""

    def register(self, app: Flask):
        if _csrf:
            _csrf.init_app(app)
        if _limiter:
            _limiter.init_app(app)

        @app.route("/reset/<uid>/<token>", methods=["GET"])
        def reset_request(uid: str, token: str):
            if not (self._validate_uid(uid) and self._validate_token(token)):
                logger.info("Invalid UID or token format")
                abort(400)

            if not self._verify_token(uid, token, self._token_verifier):
                flash("Invalid or expired reset link.", "error")
                return redirect(self._get_login_url())

            return self._render("reset_password.html", uid=uid, token=token)

    def _token_verifier(self, uid: str, token: str) -> bool:
        """Secure token verification using stored hash."""
        user_model = current_app.extensions.get("user_model")
        if not user_model:
            logger.error("User model not configured")
            return False
        user = user_model.query.get(uid)
        if not user or not getattr(user, "reset_token_hash", None):
            return False

        # Verify expiration if present
        exp = getattr(user, "reset_token_expiration", None)
        if exp and time.time() > exp:
            return False

        # Use constant‑time compare on hashed token
        token_hash = hashlib.sha256(token.encode()).hexdigest()
        stored_hash = getattr(user, "reset_token_hash")
        return _constant_time_compare(token_hash, stored_hash)


class PasswordResetCompleteView(BaseResetView):
    """View handling password reset form submission."""

    def register(self, app: Flask):
        if _csrf:
            _csrf.init_app(app)
        if _limiter:
            _limiter.init_app(app)

        @app.route("/reset/complete", methods=["POST"])
        def reset_complete():
            uid = (request.form.get("uid", "") or "").strip()
            token = (request.form.get("token", "") or "").strip()
            new_password = (request.form.get("new_password", "") or "").strip()

            if not (self._validate_uid(uid) and self._validate_token(token)):
                logger.info("Invalid UID or token on reset completion")
                abort(400)

            if not self._verify_token(uid, token, self._token_verifier):
                flash("Invalid or expired reset link.", "error")
                return redirect(self._get_login_url())

            if not self._validate_password(new_password):
                flash(
                    "Password does not meet complexity requirements.", "error"
                )
                return redirect(self._get_login_url())

            try:
                self._update_user_password(uid, new_password)
                flash("Your password has been reset successfully.", "success")
                return redirect(self._get_login_url())
            except Exception as exc:  # pragma: no cover
                logger.error("Password reset error for uid %s: %s", uid, exc)
                flash("An unexpected error occurred.", "error")
                return redirect(self._get_login_url())

    def _token_verifier(self, uid: str, token: str) -> bool:
        """Reuse same verification logic as request view."""
        return PasswordResetRequestView()._token_verifier(uid, token)

    def _validate_password(self, pwd: str) -> bool:
        """Enforce password policy."""
        if len(pwd) < 12:
            return False
        if not re.search(r"[A-Z]", pwd):
            return False
        if not re.search(r"[a-z]", pwd):
            return False
        if not re.search(r"[0-9]", pwd):
            return False
        if not re.search(r"[\W_]", pwd):
            return False
        return True

    def _hash_password(self, password: str) -> str:
        """Hash password using Argon2 if available, otherwise fallback to PBKDF2."""
        if _ph:
            return _ph.hash(password)
        from werkzeug.security import generate_password_hash

        return generate_password_hash(password, method="pbkdf2:sha256", salt_length=16)

    def _update_user_password(self, uid: str, new_password: str):
        """Hash the new password and store it securely."""
        user_model = current_app.extensions.get("user_model")
        if not user_model:
            raise RuntimeError("User model not configured")
        user = user_model.query.get(uid)
        if not user:
            raise ValueError("User not found")

        hashed = self._hash_password(new_password)
        user.password_hash = hashed

        # Invalidate any existing reset token
        if hasattr(user, "reset_token_hash"):
            user.reset_token_hash = None
        if hasattr(user, "reset_token_expiration"):
            user.reset_token_expiration = None

        db = current_app.extensions.get("db")
        if not db:
            raise RuntimeError("Database extension not configured")
        db.session.add(user)
        db.session.commit()


def register_reset_views(app: Flask):
    """
    Register password‑reset related views on the given Flask app.
    """
    request_view = PasswordResetRequestView()
    complete_view = PasswordResetCompleteView()
    request_view.register(app)
    complete_view.register(app)

import argparse
import sys
import hashlib
import hmac
import os
import tempfile
from pathlib import Path

# Maximum file size to hash (1 GiB)
MAX_FILE_SIZE = 1 << 30

# Base directory allowed for all file operations (user's home)
ALLOWED_BASE = Path.home().resolve(strict=True)


def open_nofollow(path: Path, mode: str):
    """Open a file without following symlinks."""
    flags = {
        "r": os.O_RDONLY,
        "rb": os.O_RDONLY,
        "w": os.O_WRONLY | os.O_CREAT | os.O_TRUNC,
        "wb": os.O_WRONLY | os.O_CREAT | os.O_TRUNC,
    }.get(mode)
    if flags is None:
        raise ValueError(f"Unsupported mode: {mode}")
    flags |= os.O_NOFOLLOW
    fd = os.open(str(path), flags, 0o600)
    return os.fdopen(fd, mode, encoding="utf-8" if "b" not in mode else None, newline="\n" if "b" not in mode else None)


def compute_sha256(file_path: Path) -> str:
    """Compute SHA-256 hash of file contents with size limit and symlink protection."""
    try:
        st = os.stat(str(file_path), follow_symlinks=False)
    except OSError:
        raise RuntimeError("Unable to stat target file.")
    if st.st_size > MAX_FILE_SIZE:
        raise RuntimeError("File exceeds maximum allowed size.")
    hasher = hashlib.sha256()
    try:
        with open_nofollow(file_path, "rb") as f:
            for chunk in iter(lambda: f.read(8192), b""):
                hasher.update(chunk)
    except OSError:
        raise RuntimeError("Unable to read target file.")
    return hasher.hexdigest()


def read_stored_hash(hash_path: Path) -> str:
    """Read stored hash from file, stripping whitespace, with symlink protection."""
    try:
        with open_nofollow(hash_path, "r") as f:
            return f.read().strip()
    except FileNotFoundError:
        return ""
    except OSError:
        raise RuntimeError("Unable to read hash file.")


def write_stored_hash_atomic(hash_path: Path, hash_value: str) -> None:
    """Write hash to file atomically with restrictive permissions and symlink protection."""
    dir_path = hash_path.parent
    try:
        fd, tmp_path = tempfile.mkstemp(
            dir=str(dir_path),
            prefix=".tmp_hash_",
            text=True,
        )
        os.fchmod(fd, 0o600)
        # Ensure the temporary file is not a symlink
        if os.path.islink(tmp_path):
            os.close(fd)
            os.unlink(tmp_path)
            raise RuntimeError("Temporary file is a symlink.")
        with os.fdopen(fd, "w", encoding="utf-8", newline="\n") as tmp:
            tmp.write(hash_value + "\n")
            tmp.flush()
            os.fsync(tmp.fileno())
        os.replace(tmp_path, str(hash_path))
        os.chmod(str(hash_path), 0o600)
    except OSError:
        raise RuntimeError("Unable to write hash file.")


def secure_path(path_str: str) -> Path:
    """Validate that a path is absolute, exists, is a regular file, and resides within allowed base."""
    p = Path(path_str)
    if not p.is_absolute():
        raise argparse.ArgumentTypeError("Path must be absolute.")
    try:
        resolved = p.resolve(strict=True)
    except FileNotFoundError:
        raise argparse.ArgumentTypeError(f"Path does not exist: {p}")
    if not resolved.is_file():
        raise argparse.ArgumentTypeError(f"Path is not a regular file: {p}")
    try:
        resolved.relative_to(ALLOWED_BASE)
    except ValueError:
        raise argparse.ArgumentTypeError(f"Path is outside allowed directory: {p}")
    return resolved


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Validate and optionally update stored file hash.",
        add_help=False,
    )
    parser.add_argument(
        "--file",
        type=secure_path,
        required=True,
        help="Absolute path to the target file.",
    )
    parser.add_argument(
        "--hash-file",
        type=secure_path,
        required=True,
        help="Absolute path to the stored hash file.",
    )
    parser.add_argument("-h", "--help", action="help", help="Show this help message and exit.")
    return parser.parse_args()


def main() -> None:
    try:
        args = parse_args()
        target_path: Path = args.file
        hash_path: Path = args.hash_file

        current_hash = compute_sha256(target_path)
        stored_hash = read_stored_hash(hash_path)

        if not stored_hash:
            write_stored_hash_atomic(hash_path, current_hash)
            sys.exit(0)

        if hmac.compare_digest(current_hash, stored_hash):
            sys.exit(0)

        write_stored_hash_atomic(hash_path, current_hash)
        sys.exit(0)

    except argparse.ArgumentError as e:
        print(f"Argument error: {e}", file=sys.stderr)
        sys.exit(2)
    except RuntimeError as e:
        print(str(e), file=sys.stderr)
        sys.exit(3)
    except Exception:
        print("Unexpected error.", file=sys.stderr)
        sys.exit(1)


if __name__ == "__main__":
    main()

import math
from typing import Callable, Sequence, Union, Any, Dict, List

import numpy as np
from scipy import stats

# Upper bound for the number of elements to prevent resource exhaustion
_MAX_ELEMENTS = 10_000


def _validate_distribution_name(name: Any) -> str:
    if not isinstance(name, str):
        raise ValueError("Distribution name must be a string.")
    stripped = name.strip().lower()
    if not stripped:
        raise ValueError("Distribution name cannot be empty.")
    return stripped


def _validate_values(values: Any) -> np.ndarray:
    # Reject plain strings, which are Sequences but not numeric collections
    if isinstance(values, (str, bytes)):
        raise ValueError("Values must be a sequence of numbers, not a string.")
    if not isinstance(values, Sequence):
        raise ValueError("Values must be a sequence of numbers.")
    try:
        arr = np.asarray(values, dtype=np.float64)
    except Exception as exc:
        raise ValueError("Values could not be converted to a numeric array.") from exc
    if arr.size == 0:
        raise ValueError("Values sequence is empty.")
    if arr.size > _MAX_ELEMENTS:
        raise ValueError(f"Values sequence exceeds maximum allowed size of {_MAX_ELEMENTS}.")
    if np.isnan(arr).any():
        raise ValueError("Values contain NaN.")
    return arr


def _validate_probability(p: Any) -> float:
    if isinstance(p, (list, tuple, np.ndarray)):
        raise ValueError("Probability must be a single float between 0 and 1.")
    if not isinstance(p, (int, float)):
        raise ValueError("Probability must be a numeric type.")
    prob = float(p)
    if not (0.0 <= prob <= 1.0):
        raise ValueError("Probability must be within [0, 1].")
    return prob


def _validate_method(method: str) -> str:
    allowed = {"auto", "empirical", "native"}
    if method not in allowed:
        raise ValueError(f"Method must be one of {sorted(allowed)}.")
    return method


def _get_distribution(dist_name: str):
    allowed = {
        "norm": stats.norm,
        "expon": stats.expon,
        "uniform": stats.uniform,
        "beta": stats.beta,
        "gamma": stats.gamma,
        "lognorm": stats.lognorm,
        "chi2": stats.chi2,
        "t": stats.t,
        "f": stats.f,
    }
    dist = allowed.get(dist_name)
    if dist is None:
        raise ValueError(f"Unsupported distribution: {dist_name}")
    return dist


def get_percentile_function(
    distribution_name: str,
    values: Sequence[Union[int, float]],
    *,
    dist_params: Dict[str, Any] | None = None,
    method: str = "auto",
) -> Callable[[float], float]:
    """
    Returns a percentile (inverse CDF) function for the specified distribution.
    If the distribution lacks a native `ppf`, an empirical percentile based on
    the provided values is used.
    """
    # Input validation and sanitisation
    dist_name = _validate_distribution_name(distribution_name)
    sample = _validate_values(values)

    if dist_params is None:
        dist_params = {}
    if not isinstance(dist_params, dict):
        raise ValueError("dist_params must be a dictionary if provided.")

    method = _validate_method(method.lower().strip())

    # Prepare empirical percentile function
    sorted_sample = np.sort(sample)

    def _empirical_ppf(q: float) -> float:
        # q has been validated by the wrapper; here we assume 0 ≤ q ≤ 1
        return float(np.percentile(sorted_sample, q * 100.0, method="linear"))

    # Attempt to obtain native distribution
    try:
        dist_cls = _get_distribution(dist_name)
        has_ppf = hasattr(dist_cls, "ppf")
    except Exception:
        has_ppf = False

    use_empirical = False
    if method == "empirical":
        use_empirical = True
    elif method == "native":
        if not has_ppf:
            raise ValueError(f"The distribution '{dist_name}' does not provide a ppf method.")
        use_empirical = False
    else:  # auto
        use_empirical = not has_ppf

    native_ppf = None
    if not use_empirical:
        try:
            native_dist = dist_cls(**dist_params)
            native_ppf = native_dist.ppf
        except Exception:
            use_empirical = True

    if use_empirical:
        return _empirical_ppf

    def ppf_func(q: float) -> float:
        q_val = _validate_probability(q)
        # Clip to domain to avoid returning NaN for out‑of‑range inputs
        q_val = max(0.0, min(1.0, q_val))
        try:
            result = native_ppf(q_val)
            if isinstance(result, np.ndarray):
                result = float(result.item())
            if math.isnan(result):
                return _empirical_ppf(q_val)
            return float(result)
        except Exception:
            return _empirical_ppf(q_val)

    return ppf_func

