        """Validate that the cli_path points to an allowed, trusted executable."""
        if not isinstance(path, str) or not path:
            raise ValueError("cli_path must be a non‑empty string")
        p = pathlib.Path(path).resolve()
        if not p.is_file():
            raise ValueError(f"CLI path does not exist or is not a file: {p}")
        # Require absolute path inside a trusted directory
        trusted_dir = pathlib.Path("/usr/local/bin").resolve()
        if not str(p).startswith(str(trusted_dir)):
            raise ValueError(f"CLI path must reside within {trusted_dir}")
        # Verify file permissions: owned by root and not writable by group/others
        stat = p.stat()
        if stat.st_uid != 0:
