            value_str = str(value)
            if len(value_str) > self._VALUE_MAX_LENGTH:
                raise SecretManagerError(f"Secret value for {key} exceeds maximum length")
            validated[key] = value_str

        self._secrets = validated

    def _sanitized_env(self) -> Dict[str, str]:
        """Create a minimal, sanitized environment for subprocess calls."""
        return {
            "PATH": os.getenv("PATH", "/usr/bin"),
