import traceback
import json
import logging
import multiprocessing as mp
import resource
import os
import signal
from typing import Any, Dict

# Configure logger (to file or secure location as needed)
logging.basicConfig(
    level=logging.ERROR,
    format="%(asctime)s %(levelname)s %(message)s",
    filename="script_executor.log",
    filemode="a",
)

# Safe built‑ins
_SAFE_BUILTINS = {
    "len": len,
    "range": range,
    "min": min,
    "max": max,
    "sum": sum,
    "abs": abs,
    "sorted": sorted,
    "enumerate": enumerate,
    "zip": zip,
    "bool": bool,
    "int": int,
    "float": float,
    "str": str,
    "list": list,
    "dict": dict,
    "set": set,
    "tuple": tuple,
}

# Resource limits (POSIX only)
_CPU_TIME_LIMIT = 5          # seconds
_MEMORY_LIMIT = 50 * 1024 * 1024  # 50 MB


class _SecurityError(Exception):
    """Raised when a script fails security checks."""


def _is_primitive(value: Any) -> bool:
    return isinstance(value, (int, float, str, bool, type(None)))


def _deep_validate(value: Any) -> None:
    if _is_primitive(value):
        return
    if isinstance(value, (list, tuple, set)):
        for item in value:
            _deep_validate(item)
        return
    if isinstance(value, dict):
        for k, v in value.items():
            if not isinstance(k, str):
                raise _SecurityError("Dictionary keys must be strings.")
            _deep_validate(v)
        return
    raise _SecurityError(f"Unsupported type {type(value)} in locals.")


def _validate_locals(locals_dict: Dict[str, Any]) -> None:
    if not isinstance(locals_dict, dict):
        raise _SecurityError("Local variables must be a dictionary.")
    for key, value in locals_dict.items():
        if not isinstance(key, str):
            raise _SecurityError("Local variable names must be strings.")
        _deep_validate(value)


def _validate_script(script: str) -> None:
    if not isinstance(script, str):
        raise _SecurityError("Script must be a string.")
    if len(script) > 100_000:
        raise _SecurityError("Script exceeds size limit.")
    try:
        tree = ast.parse(script, mode="exec")
    except SyntaxError as e:
        raise _SecurityError("Invalid Python syntax.") from e

    for node in ast.walk(tree):
        if isinstance(node, (ast.Import, ast.ImportFrom)):
            raise _SecurityError("Import statements are not allowed.")
        if isinstance(node, ast.Attribute):
            raise _SecurityError("Attribute access is not allowed.")
        if isinstance(node, ast.Call):
            if isinstance(node.func, ast.Name) and node.func.id in {
                "__import__",
                "eval",
                "exec",
                "open",
                "compile",
            }:
                raise _SecurityError(f'Use of "{node.func.id}" is prohibited.')
        if isinstance(node, (ast.Lambda, ast.ListComp, ast.DictComp, ast.SetComp, ast.GeneratorExp)):
            raise _SecurityError("Comprehensions and lambda expressions are not allowed.")


def _sandbox_worker(script: str, init_locals: dict, result_queue: mp.Queue) -> None:
    try:
        # Apply resource limits (only on Unix)
        if hasattr(resource, "setrlimit"):
            resource.setrlimit(resource.RLIMIT_CPU, (_CPU_TIME_LIMIT, _CPU_TIME_LIMIT))
            resource.setrlimit(resource.RLIMIT_AS, (_MEMORY_LIMIT, _MEMORY_LIMIT))

        exec_globals = {"__builtins__": _SAFE_BUILTINS}
        exec_locals = dict(init_locals)
        exec(script, exec_globals, exec_locals)
        result = exec_locals.get("result")
        # Ensure result is JSON‑serialisable to avoid leaking objects
        json.dumps(result)  # will raise TypeError if not serialisable
        result_queue.put(("RESULT", result))
    except Exception:
        tb = traceback.format_exc()
        result_queue.put(("ERROR", tb))


def execute_script(local_vars: dict, script: str, timeout: float = 5.0):
    """
    Execute ``script`` safely with ``local_vars`` as the initial locals.
    The script must assign its output to a variable named ``result``.
    Returns the ``result`` object or ``None`` on error.
    """
    try:
        _validate_locals(local_vars)
        _validate_script(script)
    except _SecurityError as se:
        logging.error("Security validation failed: %s", se)
        return None

    mgr = mp.Manager()
    result_queue = mgr.Queue()
    proc = mp.Process(target=_sandbox_worker, args=(script, local_vars, result_queue))
    proc.start()
    proc.join(timeout)

    if proc.is_alive():
        proc.terminate()
        proc.join()
        logging.error("Script execution timed out after %.2f seconds.", timeout)
        return None

    if not result_queue.empty():
        status, payload = result_queue.get()
        if status == "RESULT":
            return payload
        else:  # "ERROR"
            logging.error("Script raised an exception:\n%s", payload)
            return None

    logging.error("No result returned from sandbox.")
    return None


def _load_script_from_file(path: str) -> str:
    try:
        with open(path, "r", encoding="utf-8") as f:
            return f.read()
    except Exception as e:
        raise _SecurityError(f"Unable to read script file: {e}") from e


if __name__ == "__main__":
    if len(sys.argv) < 2:
        print("Usage: python script_executor.py <primary_script.py> [secondary_script.py]")
        sys.exit(1)

    primary_path = sys.argv[1]
    secondary_path = sys.argv[2] if len(sys.argv) > 2 else None

    try:
        primary_script = _load_script_from_file(primary_path)
        locals_dict = {}
        result = execute_script(locals_dict, primary_script)
        if result is not None:
            print(result)

        if secondary_path:
            secondary_script = _load_script_from_file(secondary_path)
            result = execute_script(locals_dict, secondary_script)
            if result is not None:
                print(result)
    except _SecurityError as e:
        logging.error("Failed to load or validate script: %s", e)
        sys.exit(1)

