import re
from typing import Any, Callable, Dict, List, Tuple, Union

# Whitelisted primitive types for arguments and expected results
_PRIMITIVE_TYPES = (int, float, str, bytes, bool, type(None))
_MAX_ARGS = 1000
_MAX_NESTING_DEPTH = 5


def _validate_method_name(name: str) -> None:
    """Validate that the method name is a safe identifier."""
    if not isinstance(name, str):
        raise TypeError("Method name must be a string")
    if not name.isidentifier():
        raise ValueError(f"Invalid method name: {name}")
    if len(name) > 100:
        raise ValueError("Method name exceeds maximum allowed length")


def _check_nesting(obj: Any, depth: int = 0) -> None:
    """Recursively ensure that nested structures do not exceed depth limits."""
    if depth > _MAX_NESTING_DEPTH:
        raise ValueError("Argument nesting depth exceeds allowed limit")
    if isinstance(obj, (list, tuple, set)):
        for item in obj:
            _check_nesting(item, depth + 1)
    elif isinstance(obj, dict):
        for key, value in obj.items():
            _check_nesting(key, depth + 1)
            _check_nesting(value, depth + 1)


def _sanitize_args(args: List[Any]) -> List[Any]:
    """
    Validate that arguments consist only of whitelisted primitive types
    and modestly sized containers.
    """
    if not isinstance(args, list):
        raise TypeError("Arguments must be provided as a list")
    if len(args) > _MAX_ARGS:
        raise ValueError(f"Argument list exceeds maximum allowed length of {_MAX_ARGS}")

    for arg in args:
        if callable(arg):
            raise ValueError("Callable arguments are not allowed")
        if not isinstance(arg, _PRIMITIVE_TYPES):
            if isinstance(arg, (list, tuple, set, dict)):
                _check_nesting(arg)
            else:
                raise ValueError(
                    f"Argument of type {type(arg).__name__} is not allowed"
                )
    return args


def _validate_expected_result(expected: Any) -> None:
    """Ensure expected result is of a primitive or JSON‑compatible type."""
    if not isinstance(expected, _PRIMITIVE_TYPES):
        if isinstance(expected, (list, tuple, set, dict)):
            _check_nesting(expected)
        else:
            raise ValueError(
                f"Expected result of type {type(expected).__name__} is not allowed"
            )


def test_library_method(library_mock: Any, method_name: str) -> bool:
    """
    Test a method of a library using the provided mock.

    Parameters
    ----------
    library_mock: Any
        An object that provides a ``test_cases`` attribute mapping method names to
        a tuple: (args, expected_result, min_args, max_args).
    method_name: str
        The name of the method to test.

    Returns
    -------
    bool
        True if the test passes; otherwise, an exception is raised.
    """
    if library_mock is None:
        raise ValueError("Library mock must not be None")
    _validate_method_name(method_name)

    test_cases: Dict[
        str, Tuple[List[Any], Any, int, int]
    ] = getattr(library_mock, "test_cases", {})
    if not isinstance(test_cases, dict):
        raise TypeError("Library mock must expose a 'test_cases' dictionary")
    if method_name not in test_cases:
        raise KeyError(f"Test case for method '{method_name}' not found in mock")

    raw_args, expected_result, min_args, max_args = test_cases[method_name]

    # Validate and sanitize inputs
    args = _sanitize_args(raw_args)
    _validate_expected_result(expected_result)

    if not isinstance(min_args, int) or not isinstance(max_args, int):
        raise TypeError("Argument limits must be integers")
    if min_args < 0 or max_args < min_args:
        raise ValueError("Invalid argument limit values")
    if not (min_args <= len(args) <= max_args):
        raise AssertionError(
            f"Argument count ({len(args)}) outside expected bounds "
            f"[{min_args}, {max_args}] for method '{method_name}'"
        )

    # Instantiate the handler
    try:
        handler = PythonHandler(library_mock)  # type: ignore[name-defined]
    except Exception as exc:
        raise RuntimeError("Failed to create PythonHandler") from exc

    method: Callable = getattr(handler, method_name, None)
    if not callable(method):
        raise AttributeError(f"Method '{method_name}' is not callable on handler")

    try:
        result = method(*args)
    except Exception as exc:
        raise RuntimeError(f"Execution of method '{method_name}' failed") from exc

    # Strict result verification
    if type(result) is not type(expected_result) or result != expected_result:
        raise AssertionError(
            f"Method '{method_name}' returned unexpected result. "
            f"Expected ({type(expected_result).__name__}): {expected_result!r}, "
            f"Got ({type(result).__name__}): {result!r}"
        )

    # Defensive re‑assertion of argument constraints after execution
    if not (min_args <= len(args) <= max_args):
        raise AssertionError(
            f"Post‑execution argument count ({len(args)}) violates limits "
            f"[{min_args}, {max_args}] for method '{method_name}'"
        )

    return True

import urllib.request
