from urllib.parse import urlparse
from typing import Dict, Any

MAX_RESPONSE_SIZE = 2 * 1024 * 1024  # 2 MiB


def _is_valid_https_url(url: str) -> bool:
    if not isinstance(url, str):
        return False
    try:
        parsed = urlparse(url)
    except Exception:
        return False
    # Scheme must be https
    if parsed.scheme.lower() != "https":
        return False
    # Disallow userinfo (username/password)
    if parsed.username is not None or parsed.password is not None:
        return False
    host = parsed.hostname
    if not host:
        return False
    # Disallow common unsafe hostnames
    if host.lower() in {"localhost", "127.0.0.1", "::1"}:
        return False
    # If host is an IP address, ensure it is public
    try:
        ip = ipaddress.ip_address(host)
        if ip.is_private or ip.is_loopback or ip.is_reserved or ip.is_link_local:
            return False
    except ValueError:
        # Not an IP address – treat as hostname. Basic sanity check:
        if any(part == "" for part in host.split(".")):
            return False
    return True


def _read_limited(resp: urllib.response.addinfourl) -> bytes:
    data = resp.read(MAX_RESPONSE_SIZE + 1)
    if len(data) > MAX_RESPONSE_SIZE:
        raise RuntimeError(f"Response size exceeds allowed limit of {MAX_RESPONSE_SIZE} bytes")
    return data


def perform_requests(
    url: str,
    post_data: Dict[str, Any],
    delete_param: Dict[str, Any],
    expected_post_msg: str,
    expected_delete_msg: str,
) -> None:
    if not _is_valid_https_url(url):
        raise ValueError("URL must be a valid public https:// address")
    if not isinstance(post_data, dict) or not isinstance(delete_param, dict):
        raise ValueError("post_data and delete_param must be dictionaries")

    post_body = json.dumps(post_data, separators=(",", ":")).encode("utf-8")
    delete_body = json.dumps(delete_param, separators=(",", ":")).encode("utf-8")

    ssl_context = ssl.create_default_context()
    ssl_context.check_hostname = True
    ssl_context.verify_mode = ssl.CERT_REQUIRED

    # -------- POST request ----------
    post_req = urllib.request.Request(url, data=post_body, method="POST")
    post_req.add_header("Content-Type", "application/json")
    try:
        with urllib.request.urlopen(post_req, timeout=10, context=ssl_context) as resp:
            response_bytes = _read_limited(resp)
    except urllib.error.URLError as e:
        raise RuntimeError("Network error during POST request") from e

    try:
        response_json = json.loads(response_bytes)
    except json.JSONDecodeError as e:
        raise RuntimeError("Invalid JSON received from POST request") from e

    if response_json.get("message") != expected_post_msg:
        raise AssertionError("POST response does not contain the expected message")

    # -------- DELETE request ----------
    delete_req = urllib.request.Request(url, data=delete_body, method="DELETE")
    delete_req.add_header("Content-Type", "application/json")
    try:
        with urllib.request.urlopen(delete_req, timeout=10, context=ssl_context) as resp:
            delete_response_bytes = _read_limited(resp)
    except urllib.error.URLError as e:
        raise RuntimeError("Network error during DELETE request") from e

    try:
        delete_response_json = json.loads(delete_response_bytes)
    except json.JSONDecodeError as e:
        raise RuntimeError("Invalid JSON received from DELETE request") from e

    if delete_response_json.get("message") != expected_delete_msg:
        raise AssertionError("DELETE response does not contain the expected message")

import argparse
import logging
import os
import shutil
import stat
import subprocess
import sys
import tempfile
from hashlib import sha256
from pathlib import Path
from random import SystemRandom
from zipfile import ZIP_DEFLATED, ZipFile

# Configure logger
logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s %(levelname)s %(message)s",
    handlers=[logging.StreamHandler(sys.stderr)],
)
logger = logging.getLogger(__name__)

RANDOM = SystemRandom()


def validate_zip_file(zip_path: Path) -> None:
    if not zip_path.is_file():
        raise ValueError(f"Input path '{zip_path}' is not a file.")
    if zip_path.suffix.lower() != ".zip":
        raise ValueError(f"Input file '{zip_path}' does not have a .zip extension.")
    try:
        with zip_path.open("rb") as f:
            signature = f.read(4)
            if signature != b"PK\x03\x04":
                raise ValueError(f"File '{zip_path}' does not appear to be a zip archive.")
    except OSError as e:
        raise ValueError(f"Unable to read '{zip_path}': {e}")


def validate_key(key: str, name: str) -> None:
    if not key.isalnum():
        raise ValueError(f"{name} must be alphanumeric.")
    if len(key) < 16:
        raise ValueError(f"{name} must be at least 16 characters long.")
    categories = sum(bool(any(c.islower() for c in key)),
                     bool(any(c.isupper() for c in key)),
                     bool(any(c.isdigit() for c in key)))
    if categories < 2:
        raise ValueError(f"{name} must contain at least two of: lowercase, uppercase, digits.")


def is_executable(path: Path) -> bool:
    try:
        st = path.stat()
        return stat.S_ISREG(st.st_mode) and bool(st.st_mode & (stat.S_IXUSR | stat.S_IXGRP | stat.S_IXOTH))
    except OSError:
        return False


def run_encryptor(
    encryptor_path: Path,
    input_file: Path,
    key: str,
    output_file: Path,
) -> None:
    # Use environment variable to avoid exposing key on command line
    env = os.environ.copy()
    env["ENCRYPTOR_KEY"] = key

    # Open the binary safely to avoid TOCTOU
    fd = os.open(str(encryptor_path), os.O_RDONLY)
    exec_path = f"/proc/self/fd/{fd}"
    cmd = [
        exec_path,
        "-e",
        "-i",
        str(input_file),
        "-o",
        str(output_file),
    ]
    try:
        result = subprocess.run(
            cmd,
            env=env,
            capture_output=True,
            text=True,
            check=False,
        )
    finally:
        os.close(fd)

    if result.returncode != 0:
        raise RuntimeError(
            f"Encryptor exited with code {result.returncode}: {result.stderr.strip()}"
        )
    logger.info("Encryption completed successfully.")


def create_secondary_key_file(directory: Path, secondary_key: str) -> Path:
    key_file = directory / "secondary_key.txt"
    try:
        with key_file.open("w", encoding="utf-8") as f:
            f.write(secondary_key)
        key_file.chmod(0o600)
    except OSError as e:
        raise RuntimeError(f"Failed to write secondary key file: {e}")
    return key_file


def create_bundle_zip(bundle_path: Path, files: list[Path]) -> None:
    try:
        with ZipFile(bundle_path, "w", compression=ZIP_DEFLATED) as zipf:
            for file_path in files:
                zipf.write(file_path, arcname=file_path.name)
    except OSError as e:
        raise RuntimeError(f"Failed to create bundle zip: {e}")


def overwrite_file(path: Path) -> None:
    try:
        size = path.stat().st_size
        with path.open("r+b") as f:
            f.seek(0)
            f.write(os.urandom(size))
            f.flush()
            os.fsync(f.fileno())
    except Exception:
        pass


def secure_delete(path: Path) -> None:
    overwrite_file(path)
    try:
        path.unlink()
    except Exception as e:
        logger.warning(f"Failed to securely delete {path}: {e}")


def compute_sha256(path: Path) -> str:
    h = sha256()
    try:
        with path.open("rb") as f:
            for chunk in iter(lambda: f.read(8192), b""):
                h.update(chunk)
    except OSError as e:
        raise RuntimeError(f"Failed to compute hash for {path}: {e}")
    return h.hexdigest()


def main() -> None:
    parser = argparse.ArgumentParser(description="Encrypt a zip file and bundle with a secondary key.")
    parser.add_argument("zip_file", type=Path, help="Path to the input zip file.")
    parser.add_argument("primary_key", help="Primary encryption key (alphanumeric, >=16 chars).")
    parser.add_argument("secondary_key", help="Secondary encryption key (alphanumeric, >=16 chars).")
    parser.add_argument(
        "--encryptor",
        type=Path,
        default=Path(os.getenv("ENCRYPTOR_PATH", "/usr/local/bin/encryptor")),
        help="Path to the external encryptor executable.",
    )
    parser.add_argument(
        "--output-dir",
        type=Path,
        default=Path("./encrypted_output"),
        help="Directory to store encrypted artifacts.",
    )
    args = parser.parse_args()

    try:
        validate_zip_file(args.zip_file)
        validate_key(args.primary_key, "Primary key")
        validate_key(args.secondary_key, "Secondary key")
        if not args.encryptor.is_file() or not is_executable(args.encryptor):
            raise ValueError(f"Encryptor binary '{args.encryptor}' is not executable.")
    except ValueError as e:
        logger.error(e)
        sys.exit(1)

    try:
        args.output_dir.mkdir(parents=True, exist_ok=True)
        args.output_dir.chmod(0o700)
    except OSError as e:
        logger.error(f"Failed to create output directory '{args.output_dir}': {e}")
        sys.exit(1)

    with tempfile.TemporaryDirectory() as tmpdir_str:
        tmpdir = Path(tmpdir_str)

        encrypted_file = tmpdir / (args.zip_file.stem + "_enc")
        try:
            run_encryptor(
                encryptor_path=args.encryptor,
                input_file=args.zip_file,
                key=args.primary_key,
                output_file=encrypted_file,
            )
        except RuntimeError as e:
            logger.error(e)
            sys.exit(1)

        try:
            secondary_key_file = create_secondary_key_file(tmpdir, args.secondary_key)
        except RuntimeError as e:
            logger.error(e)
            sys.exit(1)

        bundle_zip = tmpdir / (args.zip_file.stem + "_bundle.zip")
        try:
            create_bundle_zip(bundle_zip, [encrypted_file, secondary_key_file])
        except RuntimeError as e:
            logger.error(e)
            sys.exit(1)

        try:
            destination_zip = args.output_dir / bundle_zip.name
            shutil.move(str(bundle_zip), str(destination_zip))
            hash_val = compute_sha256(destination_zip)
            logger.info(f"Bundle SHA‑256: {hash_val}")
        except OSError as e:
            logger.error(f"Failed to move bundle zip to output directory: {e}")
            sys.exit(1)

        try:
            encrypted_dest = args.output_dir / encrypted_file.name
            secondary_dest = args.output_dir / secondary_key_file.name
            shutil.copyfile(str(encrypted_file), str(encrypted_dest))
            shutil.copyfile(str(secondary_key_file), str(secondary_dest))
            encrypted_dest.chmod(0o600)
            secondary_dest.chmod(0o600)
        except OSError as e:
            logger.error(f"Failed to copy encrypted artifacts: {e}")
            sys.exit(1)

        # Securely wipe temporary files before leaving the temp directory
        for p in (encrypted_file, secondary_key_file):
            secure_delete(p)

    try:
        secure_delete(args.zip_file)
    except Exception as e:
        logger.error(f"Failed to securely delete original zip file: {e}")
        sys.exit(1)

    logger.info("Process completed successfully.")


if __name__ == "__main__":
    main()

import os
import re
import logging
from typing import Any, Dict
import mysql.connector
from mysql.connector import errors

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class SecureDBOperations:
    _REQUIRED_KEYS = {"user", "password", "host", "database"}

    def __init__(self, config: Dict[str, Any]):
        if not self._REQUIRED_KEYS.issubset(config.keys()):
            raise ValueError("Missing required database configuration parameters")
        self._config = {k: config[k] for k in self._REQUIRED_KEYS}
        self._validate_config_values(self._config)

        # Enforce SSL/TLS connection
        ssl_options = {
            "ssl_ca": config.get("ssl_ca"),
            "ssl_cert": config.get("ssl_cert"),
            "ssl_key": config.get("ssl_key"),
            "ssl_verify_cert": config.get("ssl_verify_cert", True),
            "ssl_verify_identity": config.get("ssl_verify_identity", True),
        }
        if not all(ssl_options.values()):
            raise ValueError(
                "SSL parameters (ssl_ca, ssl_cert, ssl_key) must be provided for a secure connection"
            )
        self._validate_ssl_files(
            ssl_options["ssl_ca"], ssl_options["ssl_cert"], ssl_options["ssl_key"]
        )
        self._config.update(ssl_options)
        self._config["autocommit"] = False
        self._config["use_pure"] = True
        self._config["ssl_disabled"] = False

    @staticmethod
    def _validate_config_values(cfg: Dict[str, Any]) -> None:
        for key in SecureDBOperations._REQUIRED_KEYS:
            value = cfg.get(key)
            if not isinstance(value, str) or not value.strip():
                raise ValueError(f"Configuration '{key}' must be a non‑empty string")
        if not re.fullmatch(r"^[A-Za-z0-9_.-]+$", cfg["user"]):
            raise ValueError("Invalid characters in database user")
        if len(cfg["user"]) > 32:
            raise ValueError("Database user name too long")
        if len(cfg["password"]) > 256:
            raise ValueError("Database password too long")
        if not re.fullmatch(r"^[A-Za-z0-9_.-]+$", cfg["host"]):
            raise ValueError("Invalid characters in database host")
        if not re.fullmatch(r"^[A-Za-z0-9_.-]+$", cfg["database"]):
            raise ValueError("Invalid characters in database name")
        if len(cfg["database"]) > 64:
            raise ValueError("Database name too long")

    @staticmethod
    def _validate_ssl_files(ca: str, cert: str, key: str) -> None:
        for path in (ca, cert, key):
            if not os.path.isfile(path):
                raise ValueError(f"SSL file does not exist: {path}")
            if not os.access(path, os.R_OK):
                raise ValueError(f"SSL file not readable: {path}")
            # Ensure the file is not world‑writable
            if os.stat(path).st_mode & 0o002:
                raise ValueError(f"SSL file must not be world‑writable: {path}")

    @staticmethod
    def _validate_lock_name(lock_name: str) -> str:
        if not isinstance(lock_name, str):
            raise ValueError("Lock name must be a string")
        if not re.fullmatch(r"[A-Za-z0-9_]{1,64}", lock_name):
            raise ValueError("Invalid lock name")
        return lock_name

    def _execute_query(self, query: str, params: Any = None) -> None:
        conn = None
        cursor = None
        try:
            conn = mysql.connector.connect(**self._config)
            cursor = conn.cursor()
            cursor.execute(query, params or ())
            conn.commit()
        except mysql.connector.Error as exc:
            if conn:
                conn.rollback()
            logger.error("Database operation failed: %s", exc.__class__.__name__)
            raise RuntimeError("Database operation failed") from exc
        finally:
            if cursor:
                cursor.close()
            if conn:
                conn.close()

    def execute(self, lock_name: str) -> int:
        lock_name = self._validate_lock_name(lock_name)
        rows_affected = 0

        # Step 1‑3: create table, insert initial rows, test duplicate handling
        try:
            conn = mysql.connector.connect(**self._config)
            cursor = conn.cursor()
            cursor.execute(
                """
                CREATE TABLE IF NOT EXISTS secure_test (
                    id INT AUTO_INCREMENT PRIMARY KEY,
                    name VARCHAR(255) NOT NULL UNIQUE
                ) ENGINE=InnoDB
                """
            )
            insert_sql = "INSERT INTO secure_test (name) VALUES (%s)"
            cursor.execute(insert_sql, ("Alice",))
            rows_affected += cursor.rowcount
            cursor.execute(insert_sql, ("Bob",))
            rows_affected += cursor.rowcount

            # Attempt duplicate insert without lock
            try:
                cursor.execute(insert_sql, ("Alice",))
                conn.commit()
                raise RuntimeError("Duplicate insert succeeded without lock")
            except errors.IntegrityError:
                conn.rollback()
                raise RuntimeError("Duplicate insert attempted without lock")
        except mysql.connector.Error as exc:
            logger.error("Error during initial operations: %s", exc.__class__.__name__)
            raise RuntimeError("Database operation failed") from exc
        finally:
            if "cursor" in locals() and cursor:
                cursor.close()
            if "conn" in locals() and conn:
                conn.close()

        # Step 4: acquire lock and perform protected insert
        try:
            conn = mysql.connector.connect(**self._config)
            cursor = conn.cursor()
            cursor.execute("SELECT GET_LOCK(%s, 10)", (lock_name,))
            lock_result = cursor.fetchone()
            if not lock_result or lock_result[0] != 1:
                raise RuntimeError("Failed to acquire named lock")

            protected_sql = """
                INSERT INTO secure_test (name) VALUES (%s)
                ON DUPLICATE KEY UPDATE name = VALUES(name)
            """
            cursor.execute(protected_sql, ("Alice",))
            rows_affected += cursor.rowcount
            conn.commit()
        except mysql.connector.Error as exc:
            logger.error("Error during protected insert: %s", exc.__class__.__name__)
            raise RuntimeError("Database operation failed") from exc
        finally:
            # Release lock and clean up
            if "cursor" in locals() and cursor:
                try:
                    cursor.execute("SELECT RELEASE_LOCK(%s)", (lock_name,))
                    release_result = cursor.fetchone()
                    if not release_result or release_result[0] != 1:
                        logger.warning("Failed to release lock %s", lock_name)
                except mysql.connector.Error as rel_exc:
                    logger.error("Error releasing lock: %s", rel_exc.__class__.__name__)
                finally:
                    cursor.close()
            if "conn" in locals() and conn:
                conn.close()

        return rows_affected

import logging
import urllib.request
import urllib.parse
import urllib.error
import ssl
import re
import ipaddress
import socket
from typing import Dict, Pattern

from cryptography import x509
from cryptography.hazmat.primitives import serialization
from cryptography.hazmat.backends import default_backend

# Configure logger
logging.basicConfig(level=logging.WARNING)
logger = logging.getLogger(__name__)

MAX_PEM_SIZE = 10 * 1024  # 10KB per file

# Simple PEM regex patterns
_CERT_PATTERN: Pattern[bytes] = re.compile(
    rb'-----BEGIN CERTIFICATE-----\r?.+?\r?-----END CERTIFICATE-----',
    re.DOTALL,
)
_KEY_PATTERN: Pattern[bytes] = re.compile(
    rb'-----BEGIN (?:RSA )?PRIVATE KEY-----\r?.+?\r?-----END (?:RSA )?PRIVATE KEY-----',
    re.DOTALL,
)


class CertificateError(Exception):
    """General error for certificate processing."""


def _is_private_ip(host: str) -> bool:
    """Return True if the host resolves to a private or loopback IP address."""
    try:
        ip = ipaddress.ip_address(host)
        return ip.is_private or ip.is_loopback
    except ValueError:
        return False


def _resolve_host(host: str) -> bool:
    """
    Resolve the hostname and ensure none of the resulting IP addresses are private
    or loopback. Returns True if all resolved addresses are public.
    """
    original_timeout = socket.getdefaulttimeout()
    try:
        socket.setdefaulttimeout(5)  # DNS timeout
        addr_info = socket.getaddrinfo(host, None)
    except socket.gaierror:
        return False
    finally:
        socket.setdefaulttimeout(original_timeout)

    for family, _, _, _, sockaddr in addr_info:
        ip_str = sockaddr[0]
        if _is_private_ip(ip_str):
            return False
    return True


def _is_valid_https_url(url: str) -> bool:
    """Validate that the URL is HTTPS, has no user‑info, and does not point to a private IP or localhost."""
    try:
        parsed = urllib.parse.urlparse(url)

        if parsed.scheme.lower() != "https":
            return False

        if not parsed.netloc or parsed.username or parsed.password:
            return False

        host = parsed.hostname
        if not host:
            return False

        if host.lower() == "localhost" or _is_private_ip(host):
            return False

        # Resolve hostname and ensure all IPs are public
        if not _resolve_host(host):
            return False

        return True
    except Exception:
        return False


class _NoRedirect(urllib.request.HTTPRedirectHandler):
    """Prevent automatic following of redirects."""

    def redirect_request(self, req, fp, code, msg, hdrs, newurl):
        return None


def _fetch_pem(url: str) -> bytes:
    if not _is_valid_https_url(url):
        raise CertificateError("Invalid or disallowed URL")

    context = ssl.create_default_context()
    context.check_hostname = True
    context.verify_mode = ssl.CERT_REQUIRED

    opener = urllib.request.build_opener(_NoRedirect)
    try:
        with opener.open(url, context=context, timeout=5) as resp:
            total_data = bytearray()
            while True:
                chunk = resp.read(4096)
                if not chunk:
                    break
                total_data.extend(chunk)
                if len(total_data) > MAX_PEM_SIZE:
                    raise CertificateError("PEM size exceeds limit")
            return bytes(total_data)
    except urllib.error.HTTPError as e:
        logger.warning("HTTP error fetching PEM: status %s", e.code)
        raise CertificateError("Unable to retrieve PEM")
    except urllib.error.URLError as e:
        logger.warning("URL error fetching PEM")
        raise CertificateError("Unable to retrieve PEM")
    except ssl.SSLError:
        logger.warning("TLS verification failed while fetching PEM")
        raise CertificateError("TLS verification failed")


def _validate_pem_content(pem: bytes, expected_pattern: Pattern[bytes], label: str) -> None:
    """Validate PEM header/footer and ensure the PEM can be parsed correctly."""
    if not expected_pattern.search(pem):
        raise CertificateError(f"{label} PEM does not contain a valid header/footer")

    try:
        if label == "Certificate":
            x509.load_pem_x509_certificate(pem, default_backend())
        elif label == "Private key":
            key = serialization.load_pem_private_key(pem, password=None, backend=default_backend())
            if hasattr(key, "key_size"):
                if key.key_size < 2048:
                    raise CertificateError("Private key size is below the minimum of 2048 bits")
        else:
            raise CertificateError("Unknown PEM label for validation")
    except Exception as exc:
        raise CertificateError(f"{label} PEM failed cryptographic validation: {exc}") from exc


def fetch_and_combine_cert(oauth_request: Dict) -> str:
    """
    Extracts certificate and private key URLs from an OAuth request,
    fetches them securely, validates PEM format, and returns a combined PEM string.
    """
    if not isinstance(oauth_request, dict):
        raise CertificateError("OAuth request must be a dict")

    cert_url = oauth_request.get("certificate_url")
    key_url = oauth_request.get("private_key_url")

    if not isinstance(cert_url, str) or not isinstance(key_url, str):
        raise CertificateError("Missing or invalid URL fields")

    cert_pem = _fetch_pem(cert_url).strip()
    key_pem = _fetch_pem(key_url).strip()

    _validate_pem_content(cert_pem, _CERT_PATTERN, "Certificate")
    _validate_pem_content(key_pem, _KEY_PATTERN, "Private key")

    combined = b"\n".join([key_pem, cert_pem]) + b"\n"

    try:
        combined.decode("utf-8")
    except UnicodeDecodeError as exc:
        raise CertificateError("PEM content is not valid UTF-8") from exc

    return combined.decode("utf-8")

