_MEMORY_LIMIT = 100 * 1024 * 1024  # 100 MB


def _is_safe_literal(value: Any) -> bool:
    """Check if value consists only of JSON‑compatible primitive types."""
    if isinstance(value, (str, int, float, bool, type(None))):
        return True
    if isinstance(value, (list, tuple)):
        return all(_is_safe_literal(v) for v in value)
    if isinstance(value, dict):
        return all(isinstance(k, str) and _is_safe_literal(v) for k, v in value.items())
    return False


def _validate_experiment_def(exp: Any) -> Optional[str]:
    """Validate a single experiment definition.

    Expected shape: {'code': <str>}
    Returns error message or None if valid.
    """
    if not isinstance(exp, dict):
        return "Experiment definition must be a dict."
    code = exp.get("code")
    if not isinstance(code, str):
        return "Experiment 'code' must be a string."
    try:
        ast.parse(code, mode="exec")
    except SyntaxError:
        return "Experiment code contains syntax errors."
    return None


def _sandbox_worker(code: str, extra_globals: Optional[Mapping[str, Any]], conn):
    try:
        # Apply resource limits (Unix only)
        resource.setrlimit(resource.RLIMIT_CPU, (_CPU_TIME_LIMIT, _CPU_TIME_LIMIT))
        resource.setrlimit(resource.RLIMIT_AS, (_MEMORY_LIMIT, _MEMORY_LIMIT))

        # Minimal safe builtins
        safe_builtins = {
            "range": range,
            "len": len,
            "int": int,
            "float": float,
            "str": str,
            "bool": bool,
            "dict": dict,
            "list": list,
            "set": set,
            "tuple": tuple,
            "abs": abs,
            "min": min,
            "max": max,
            "sum": sum,
            "enumerate": enumerate,
            "zip": zip,
            "sorted": sorted,
        }

        exec_globals: Dict[str, Any] = {"__builtins__": safe_builtins}
        if extra_globals:
            exec_globals.update(extra_globals)

        exec_locals: Dict[str, Any] = {}
        exec(code, exec_globals, exec_locals)
        conn.send(("result", exec_locals))
    except Exception as e:
        conn.send(("error", repr(e)))
    finally:
        conn.close()


def _run_in_sandbox(code: str, extra_globals: Optional[Mapping[str, Any]]) -> Dict[str, Any]:
    parent_conn, child_conn = multiprocessing.Pipe()
    proc = multiprocessing.Process(
        target=_sandbox_worker,
        args=(code, extra_globals, child_conn),
        daemon=True,
    )
    proc.start()
    if parent_conn.poll(_EXEC_TIMEOUT_SECONDS):
        status, payload = parent_conn.recv()
        proc.join()
        if status == "result":
            return payload
        raise RuntimeError(f"Sandbox execution error: {payload}")
    else:
        proc.terminate()
        proc.join()
        raise TimeoutError("Sandbox execution timed out")


def _safe_exec(code: str, extra_globals: Optional[Mapping[str, Any]] = None) -> Dict[str, Any]:
    """Execute Python code in a hardened sandboxed subprocess."""
    try:
        return _run_in_sandbox(code, extra_globals)
    except Exception:
        if logger.isEnabledFor(logging.DEBUG):
            logger.exception("Error executing experiment code.")
        else:
            logger.error("Error executing experiment code.")
        raise


def _import_dev_func():
    module_name = "dev_module"
    spec = importlib.util.find_spec(module_name)
    if spec is None or spec.origin is None:
        raise ImportError("dev_module not found")

    allowed_dir = os.path.abspath(os.path.dirname(__file__))
    module_path = os.path.abspath(spec.origin)
    if not module_path.startswith(allowed_dir):
        raise ImportError("dev_module is outside the allowed directory")

    module = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(module)  # type: ignore
    if not hasattr(module, "dev_func"):
        raise AttributeError("dev_func not found in dev_module")
    return getattr(module, "dev_func")


def run_experiments(
    experiment_defs: List[Dict[str, Any]],
    input_data: List[Any],
    flags: Optional[List[str]] = None,
) -> Mapping[str, Any]:
    """
    Execute experiment definitions safely and optionally a development function.
    """
    if not isinstance(experiment_defs, list):
        raise ValueError("experiment_defs must be a list.")
    if len(experiment_defs) > _MAX_EXPERIMENTS:
        raise ValueError(f"Too many experiment definitions (max {_MAX_EXPERIMENTS}).")

    if not isinstance(input_data, list):
        raise ValueError("input_data must be a list.")
    if len(input_data) > _MAX_INPUT_ITEMS:
        raise ValueError(f"input_data contains too many items (max {_MAX_INPUT_ITEMS}).")
    if not all(_is_safe_literal(item) for item in input_data):
        raise ValueError("input_data contains unsafe values.")

    flags = flags or []
    result_locals: Dict[str, Any] = {}

    for idx, exp in enumerate(experiment_defs):
        error_msg = _validate_experiment_def(exp)
        if error_msg:
            logger.error("Invalid experiment at index %s: %s", idx, error_msg)
            continue

        code = exp["code"]
        try:
            locals_created = _safe_exec(code, extra_globals={"input_data": input_data})
        except Exception:
            continue

        for key, value in locals_created.items():
            if key not in result_locals:
                result_locals[key] = value

    if "--devmode" in flags:
        try:
            dev_func = _import_dev_func()
        except Exception as e:
            if logger.isEnabledFor(logging.DEBUG):
                logger.exception("Dev function import failed.")
            else:
                logger.error("Dev function could not be imported.")
        else:
            try:
                dev_locals = dev_func(input_data)
                if not isinstance(dev_locals, dict):
                    raise TypeError("dev_func must return a dict.")
                for key, value in dev_locals.items():
                    if key not in result_locals:
                        result_locals[key] = value
            except Exception:
                if logger.isEnabledFor(logging.DEBUG):
                    logger.exception("Error executing dev_func.")
                else:
                    logger.error("Error executing dev_func.")

    return MappingProxyType(result_locals)

