# Constants
CONFIG_DIR = Path("/etc/myapp").resolve()
MAX_CONFIG_SIZE = 1 * 1024 * 1024  # 1 MiB
MAX_LANGUAGES = 100
MAX_LANGUAGE_LEN = 10
PBKDF2_ITERATIONS = 200_000
SALT_SIZE = 16  # bytes


def _is_subpath(path: Path, directory: Path) -> bool:
    try:
        return path.resolve().is_relative_to(directory)
    except AttributeError:
        # Python < 3.9 fallback
        return directory in path.resolve().parents or path.resolve() == directory


def _derive_key(key: str, salt: bytes) -> bytes:
    return hashlib.pbkdf2_hmac("sha256", key.encode("utf-8"), salt, PBKDF2_ITERATIONS)


def _zero_bytearray(barr: bytearray) -> None:
    for i in range(len(barr)):
        barr[i] = 0


@dataclass(frozen=True)
class ConfigData:
    host: str
    port: int
    languages: List[str]
    encryption_key_salt: str  # hex
    encryption_key_hash: str   # hex (derived key)
    db_host: str
    db_name: str
    db_user: bytes
    db_password: bytes


class Config:
    _config: Optional[ConfigData] = None

    _HOST_REGEX = re.compile(
        r"^(?:[a-zA-Z0-9-]{1,63}\.)+[a-zA-Z]{2,63}$|"
        r"^(?:\d{1,3}\.){3}\d{1,3}$"
    )
    _LANG_REGEX = re.compile(r"^[a-z]{2,3}$", re.IGNORECASE)

    @classmethod
    def _validate_string(cls, value: Any, name: str, max_len: int = 255) -> str:
        if not isinstance(value, str):
            raise ValueError(f"Invalid type for {name}")
        value = value.strip()
        if not value or len(value) > max_len:
            raise ValueError(f"Invalid value for {name}")
        return value

    @classmethod
    def _validate_host(cls, value: Any) -> str:
        host = cls._validate_string(value, "host")
        if not cls._HOST_REGEX.fullmatch(host):
            raise ValueError("Invalid host format")
        return host

    @classmethod
    def _validate_port(cls, value: Any) -> int:
        if not isinstance(value, int):
            raise ValueError("Port must be integer")
        if not (1 <= value <= 65535):
            raise ValueError("Port out of range")
        return value

    @classmethod
    def _validate_languages(cls, value: Any) -> List[str]:
        if not isinstance(value, list):
            raise ValueError("Languages must be a list")
        if len(value) == 0 or len(value) > MAX_LANGUAGES:
            raise ValueError(f"Languages list must contain 1‑{MAX_LANGUAGES} items")
        languages: List[str] = []
        for item in value:
            lang = cls._validate_string(item, "language", max_len=MAX_LANGUAGE_LEN)
            if not cls._LANG_REGEX.fullmatch(lang):
                raise ValueError(f"Invalid language code: {lang}")
            languages.append(lang.lower())
        return languages

    @classmethod
    def load_from_file(cls, file_path: str) -> None:
        try:
            path = Path(file_path).resolve()
            if not _is_subpath(path, CONFIG_DIR):
                raise PermissionError("Configuration file must reside within the config directory")
            if not path.is_file():
                raise FileNotFoundError("Configuration file not found")
            stat = path.stat()
            if stat.st_size > MAX_CONFIG_SIZE:
                raise PermissionError("Configuration file exceeds maximum allowed size")
            if (stat.st_mode & 0o777) != 0o600:
                raise PermissionError("Configuration file must have mode 600")
            if stat.st_uid != os.getuid():
                raise PermissionError("Configuration file must be owned by the current user")

            with path.open("r", encoding="utf-8") as f:
                data = json.load(f)

            required_keys = {
                "host",
                "port",
                "languages",
                "encryption_key",
                "db_host",
                "db_name",
                "db_user",
                "db_password",
            }
            missing = required_keys - data.keys()
            if missing:
                raise ValueError(f"Missing configuration fields: {', '.join(missing)}")

            host = cls._validate_host(data["host"])
            port = cls._validate_port(data["port"])
            languages = cls._validate_languages(data["languages"])

            raw_key = cls._validate_string(data["encryption_key"], "encryption_key", max_len=1024)
            salt = os.urandom(SALT_SIZE)
            derived = _derive_key(raw_key, salt)
            # Zero the raw key in memory
            raw_key_bytes = bytearray(raw_key.encode("utf-8"))
            _zero_bytearray(raw_key_bytes)
            del raw_key, raw_key_bytes

            encryption_key_salt = salt.hex()
            encryption_key_hash = derived.hex()

            db_host = cls._validate_host(data["db_host"])
            db_name = cls._validate_string(data["db_name"], "db_name")
            db_user_raw = cls._validate_string(data["db_user"], "db_user")
            db_password_raw = cls._validate_string(data["db_password"], "db_password")

            db_user = db_user_raw.encode("utf-8")
            db_password = db_password_raw.encode("utf-8")

            # Zero the temporary plaintext credential buffers
            db_user_barr = bytearray(db_user)
            db_password_barr = bytearray(db_password)
            _zero_bytearray(db_user_barr)
            _zero_bytearray(db_password_barr)

            cls._config = ConfigData(
                host=host,
                port=port,
                languages=languages,
                encryption_key_salt=encryption_key_salt,
                encryption_key_hash=encryption_key_hash,
                db_host=db_host,
                db_name=db_name,
                db_user=db_user,
                db_password=db_password,
            )
        except (json.JSONDecodeError, OSError) as exc:
            raise RuntimeError("Failed to load configuration") from exc
        except Exception as exc:
            raise RuntimeError("Invalid configuration data") from exc

    @classmethod
    def get_config(cls) -> ConfigData:
        if cls._config is None:
            raise RuntimeError("Configuration has not been loaded")
        return cls._config

