import os
import re
import sys
import sqlite3
import traceback

SAFE_NAME_RE = re.compile(r'^[A-Za-z_][A-Za-z0-9_]*$')
SAFE_TYPE_RE = re.compile(r'^(TEXT|INTEGER|REAL|BLOB)$', re.IGNORECASE)

MAX_NAME_LEN = 64          # Max length for identifiers (db, table, column)
MAX_COLUMNS = 100          # Max number of columns per table
MAX_RECORDS = 10000        # Max number of records to insert at once
MAX_VALUE_LEN = 1024      # Max length for a single column value

def safe_identifier(name: str) -> str:
    if len(name) > MAX_NAME_LEN:
        raise ValueError(f"Identifier too long (max {MAX_NAME_LEN} chars).")
    if not SAFE_NAME_RE.fullmatch(name):
        raise ValueError("Invalid name: must start with a letter or underscore and contain only alphanumerics and underscores.")
    return name

def safe_type(col_type: str) -> str:
    col_type = col_type.strip().upper()
    if not SAFE_TYPE_RE.fullmatch(col_type):
        raise ValueError("Invalid column type: must be TEXT, INTEGER, REAL, or BLOB.")
    return col_type

def get_input(prompt: str) -> str:
    try:
        return input(prompt).strip()
    except EOFError:
        sys.exit("\nInput terminated.")

def main():
    try:
        # ==== Database filename handling ====
        db_name = get_input("Enter SQLite database filename (will be created if not exists, no path): ")
        if len(db_name) > MAX_NAME_LEN:
            raise ValueError(f"Database name too long (max {MAX_NAME_LEN} characters).")
        if os.path.sep in db_name or ".." in db_name:
            raise ValueError("Database name must not contain path separators or traversal components.")
        if not db_name.lower().endswith('.db'):
            db_name += '.db'

        db_path = os.path.abspath(db_name)

        # Prevent symlink attacks and ensure location inside cwd
        cwd = os.path.abspath(os.getcwd())
        if os.path.islink(db_path):
            raise ValueError("Database path resolves to a symbolic link, which is not allowed.")
        real_path = os.path.realpath(db_path)
        if not real_path.startswith(cwd + os.path.sep):
            raise ValueError("Database must reside within the current directory.")

        # ==== Table name ====
        table_name = safe_identifier(get_input("Enter table name: "))

        # ==== Columns configuration ====
        col_count_str = get_input("Enter number of columns: ")
        if not col_count_str.isdigit():
            raise ValueError("Column count must be a positive integer.")
        col_count = int(col_count_str)
        if col_count <= 0 or col_count > MAX_COLUMNS:
            raise ValueError(f"Column count must be between 1 and {MAX_COLUMNS}.")

        columns = []
        for i in range(col_count):
            col_name = safe_identifier(get_input(f"Column {i+1} name: "))
            col_type = safe_type(get_input(f"Column {i+1} type (TEXT/INTEGER/REAL/BLOB): "))
            columns.append((col_name, col_type))

        col_defs = ", ".join(f"{name} {ctype}" for name, ctype in columns)

        # ==== Database connection and table creation ====
        conn = sqlite3.connect(db_path, detect_types=sqlite3.PARSE_DECLTYPES)
        try:
            with conn:
                conn.execute(f"CREATE TABLE IF NOT EXISTS {table_name} ({col_defs});")
        except sqlite3.DatabaseError as e:
            sys.exit(f"Failed to create table: {e}")

        # ==== Optional record insertion ====
        insert_prompt = get_input("Do you want to insert records now? (y/n): ").lower()
        if insert_prompt == 'y':
            record_count_str = get_input("Enter number of records to insert: ")
            if not record_count_str.isdigit():
                raise ValueError("Record count must be a non‑negative integer.")
            record_count = int(record_count_str)
            if record_count < 0 or record_count > MAX_RECORDS:
                raise ValueError(f"Record count must be between 0 and {MAX_RECORDS}.")

            for r in range(record_count):
                values = []
                for name, _ in columns:
                    val = get_input(f"Value for column '{name}' (record {r+1}): ")
                    if len(val) > MAX_VALUE_LEN:
                        raise ValueError(f"Value for column '{name}' exceeds maximum length of {MAX_VALUE_LEN} characters.")
                    values.append(val)
                placeholders = ", ".join("?" for _ in values)
                column_list = ", ".join(name for name, _ in columns)
                sql = f"INSERT INTO {table_name} ({column_list}) VALUES ({placeholders});"
                try:
                    with conn:
                        conn.execute(sql, values)
                except sqlite3.DatabaseError as e:
                    print(f"Failed to insert a record ({e}); continuing.")
        print("Operations completed successfully.")
    except ValueError as ve:
        sys.exit(f"Input error: {ve}")
    except Exception:
        traceback.print_exc()
        sys.exit("An unexpected error occurred.")

