import logging
import sys
import types
import re
import inspect

_logger = logging.getLogger(__name__)
if not _logger.handlers:
    handler = logging.StreamHandler(sys.stderr)
    formatter = logging.Formatter('%(asctime)s %(levelname)s %(message)s')
    handler.setFormatter(formatter)
    _logger.addHandler(handler)
    _logger.setLevel(logging.INFO)

# Allow only printable ASCII characters, space and a limited set of punctuation.
_ALLOWED_PATTERN = re.compile(r'^[\x20-\x7E]*$')


def _sanitize_value(value: str) -> str:
    """Sanitize string inputs using a strict whitelist."""
    if not isinstance(value, str):
        raise TypeError("Value must be a string")
    # Truncate to a reasonable length.
    value = value[:256]
    if not _ALLOWED_PATTERN.fullmatch(value):
        raise ValueError("Input contains disallowed characters")
    return value


def _validate_type(value, expected_type):
    """Validate that value matches the expected type hint."""
    if expected_type is inspect._empty:
        return  # No hint – accept any type.
    if not isinstance(value, expected_type):
        raise TypeError(f"Expected value of type {expected_type.__name__}, got {type(value).__name__}")


def modify_object_methods(obj):
    """
    Replace the object's 'Set*' methods with safe wrappers.

    The object must explicitly opt‑in to this behaviour by defining
    attribute `_wrappable = True`. This prevents accidental monkey‑patching
    of privileged or unrelated objects.
    """
    if obj is None:
        raise ValueError("Object cannot be None")

    if not getattr(obj, "_wrappable", False):
        raise ValueError("Object is not marked as wrappable")

    # Ensure a configuration dictionary exists on the object.
    if not hasattr(obj, "config") or not isinstance(getattr(obj, "config"), dict):
        try:
            setattr(obj, "config", {})
        except Exception as exc:
            _logger.error("Failed to initialise config on the object: %s", exc)
            raise

    config = obj.config

    for attr_name in dir(obj):
        if not attr_name.startswith("Set") or attr_name.startswith("__"):
            continue

        try:
            set_method = getattr(obj, attr_name)
        except Exception:
            _logger.debug("Unable to retrieve attribute %s", attr_name)
            continue

        if not callable(set_method):
            continue

        get_name = "Get" + attr_name[3:]
        try:
            get_method = getattr(obj, get_name)
        except Exception:
            get_method = None

        if not callable(get_method):
            continue

        # Preserve the original setter signature for validation.
        set_sig = inspect.signature(set_method)

        # Expect exactly one parameter besides 'self'.
        params = [p for p in set_sig.parameters.values() if p.kind in (p.POSITIONAL_OR_KEYWORD, p.POSITIONAL_ONLY)]
        if len(params) != 2:  # self + value
            _logger.warning("Skipping %s: unexpected signature", attr_name)
            continue

        value_param = params[1]
        expected_type = value_param.annotation

        def _make_wrapper(original_set, original_get, method_key, exp_type):
            def wrapper(self, *args, **kwargs):
                if kwargs:
                    raise ValueError(f"{method_key} expects positional arguments only")
                if len(args) != 1:
                    raise ValueError(f"{method_key} expects exactly one argument")

                raw_value = args[0]
                _validate_type(raw_value, exp_type)

                safe_value = raw_value
                if isinstance(raw_value, str):
                    safe_value = _sanitize_value(raw_value)

                # Retrieve current value; propagate any exception.
                try:
                    original_get()
                except Exception as exc:
                    _logger.error("Getter %s raised an exception", original_get.__name__)
                    raise

                # Call the original setter with the sanitized/validated value.
                try:
                    result = original_set(safe_value)
                except Exception as exc:
                    _logger.error("Error in original setter %s", original_set.__name__)
                    raise

                # Record successful change in the configuration dictionary.
                config_key = method_key[3:]  # Remove 'Set' prefix.
                try:
                    config[config_key] = safe_value
                except Exception as exc:
                    _logger.debug("Failed to update config for %s: %s", method_key, exc)

                return result
            return wrapper

        try:
            wrapped = _make_wrapper(set_method, get_method, attr_name, expected_type)
            bound = types.MethodType(wrapped, obj)
            setattr(obj, attr_name, bound)
        except Exception as exc:
            _logger.error("Failed to replace method %s", attr_name)
            raise

    return obj

