_ALLOWED_AUTH_METHODS = {"none", "password", "ssh-key"}
_ALLOWED_DEVICE_PREFIX = "/dev/"
_MAX_CRED_LEN = 256


def _validate_device_path(path: str) -> str:
    if not isinstance(path, str):
        raise ValueError("device_path must be a string")
    if "\x00" in path or ".." in path or not path.strip():
        raise ValueError("Invalid device_path content")
    if os.path.islink(path):
        raise ValueError("Symlinks are not allowed for device_path")
    real_path = os.path.realpath(path)
    if not real_path.startswith(_ALLOWED_DEVICE_PREFIX):
        raise ValueError(f"device_path must be under {_ALLOWED_DEVICE_PREFIX}")
    try:
        mode = os.stat(real_path).st_mode
    except FileNotFoundError as exc:
        raise ValueError(f"device_path does not exist: {real_path}") from exc
    if not stat.S_ISBLK(mode):
        raise ValueError(f"device_path is not a block device: {real_path}")
    return real_path


def _validate_qos_spec(qos: Dict[str, Any]) -> Dict[str, int]:
    if not isinstance(qos, dict):
        raise ValueError("qos_specs must be a dictionary")
    required = {"total_bytes_sec", "read_iops_sec"}
    missing = required.difference(qos.keys())
    if missing:
        raise ValueError(f"Missing qos specs: {', '.join(missing)}")
    validated: Dict[str, int] = {}
    for key in required:
        value = qos[key]
        if isinstance(value, int) and value >= 0:
            validated[key] = value
        elif isinstance(value, str) and value.isdigit():
            validated[key] = int(value)
        else:
            raise ValueError(f"Invalid qos value for {key}")
    return validated


def _validate_auth(auth: Dict[str, Any]) -> Dict[str, str]:
    if not isinstance(auth, dict):
        raise ValueError("auth must be a dictionary")
    method = auth.get("method")
    username = auth.get("username", "")
    password = auth.get("password", "")
    if not isinstance(method, str) or method not in _ALLOWED_AUTH_METHODS:
        raise ValueError("Unsupported authentication method")
    if method != "none":
        if not isinstance(username, str) or not isinstance(password, str):
            raise ValueError("Credentials must be strings")
        if not username.strip() or not password.strip():
            raise ValueError("Credentials cannot be empty")
        if len(username) > _MAX_CRED_LEN or len(password) > _MAX_CRED_LEN:
            raise ValueError("Credentials exceed maximum allowed length")
    return {"method": method, "username": username, "password": password}


def _get_libvirt_secret_uuid(username: str) -> str:
    """
    Generate a random UUID for a libvirt secret reference.
    In production, this should be stored and retrieved securely.
    """
    return str(uuid.uuid4())


def create_libvirt_volume_xml(params: Dict[str, Any]) -> str:
    """
    Build a libvirt volume XML definition from validated parameters.
    Expected keys in params:
        - device_path: str
        - qos_specs: dict with 'total_bytes_sec' and 'read_iops_sec'
        - auth: dict with 'method', 'username', 'password'
    Returns:
        XML string.
    Raises:
        ValueError on validation failures.
    """
    try:
        device_path = _validate_device_path(params.get("device_path", ""))
        qos = _validate_qos_spec(params.get("qos_specs", {}))
        auth = _validate_auth(params.get("auth", {}))
    except Exception as exc:
        raise ValueError(f"Parameter validation failed: {exc}") from exc

    volume = ET.Element("volume", type="block")
    target = ET.SubElement(volume, "target")
    ET.SubElement(target, "path").text = device_path

    qos_elem = ET.SubElement(volume, "qos")
    ET.SubElement(qos_elem, "total_bytes_sec").text = str(qos["total_bytes_sec"])
    ET.SubElement(qos_elem, "read_iops_sec").text = str(qos["read_iops_sec"])

    auth_elem = ET.SubElement(volume, "auth")
    ET.SubElement(auth_elem, "method").text = auth["method"]
    if auth["method"] != "none":
        credentials = ET.SubElement(auth_elem, "credentials")
        ET.SubElement(credentials, "username").text = auth["username"]
        secret_uuid = _get_libvirt_secret_uuid(auth["username"])
        ET.SubElement(
            credentials,
            "secret",
            type="password",
            uuid=secret_uuid,
        )

    return ET.tostring(volume, encoding="unicode")

