import argparse
import configparser
import logging
import os
import re
import stat
import sys
import threading
from pathlib import Path
from typing import Any, Callable, Dict, List, Tuple

# Secure logging configuration
logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s %(levelname)s %(message)s",
    handlers=[logging.StreamHandler(sys.stderr)],
)

# Regular expression for validating configuration keys (alphanumeric + underscore)
_KEY_PATTERN = re.compile(r"^[A-Za-z_][A-Za-z0-9_]*$")

# Internal structures
_ConfigEntry = Tuple[Any, str]  # (value, source)
_config: Dict[str, _ConfigEntry] = {}
_config_lock = threading.Lock()
_initialized = False

_handlers: List[Callable[[str, Any], None]] = []
_handlers_lock = threading.Lock()

# Allowed directories for configuration files
_ALLOWED_CONFIG_DIRS = [
    Path("/etc/myapp").resolve(),
    (Path.home() / ".myapp").resolve(),
]
_DEFAULT_CONFIG_PATH = Path("/etc/myapp/config.ini").resolve()


def _validate_key(key: str) -> None:
    """Validate configuration key name."""
    if not isinstance(key, str) or not _KEY_PATTERN.fullmatch(key):
        raise ValueError(f"Invalid configuration key: {key!r}")


def _load_cli_args() -> Dict[str, str]:
    """Parse and sanitize command‑line arguments of the form --key=value."""
    parser = argparse.ArgumentParser(add_help=False)
    parser.add_argument(
        "--config",
        action="append",
        default=[],
        help="Configuration overrides in key=value format",
    )
    try:
        args, _ = parser.parse_known_args()
    except SystemExit:
        return {}

    cli_config: Dict[str, str] = {}
    for item in args.config:
        if "=" not in item:
            continue
        key, value = item.split("=", 1)
        try:
            _validate_key(key)
            cli_config[key] = value
        except ValueError:
            logging.warning("Ignored invalid CLI configuration key: %s", key)
    return cli_config


def _is_path_allowed(path: Path) -> bool:
    """Return True if path is absolute and resides within an allowed directory."""
    if not path.is_absolute():
        return False
    try:
        resolved = path.resolve(strict=True)
    except FileNotFoundError:
        return False
    for allowed_dir in _ALLOWED_CONFIG_DIRS:
        if resolved == allowed_dir or allowed_dir in resolved.parents:
            return True
    return False


def _load_config_file() -> Dict[str, str]:
    """Load configuration from a file, performing safe open and validation."""
    env_path = os.getenv("MYAPP_CONFIG_FILE")
    if env_path and os.geteuid() != 0:  # Only honour env var for non‑root processes
        candidate = Path(env_path)
        if _is_path_allowed(candidate):
            config_path = candidate.resolve()
        else:
            logging.warning(
                "Ignored untrusted config file path from environment: %s", env_path
            )
            config_path = _DEFAULT_CONFIG_PATH
    else:
        config_path = _DEFAULT_CONFIG_PATH

    try:
        # Open file without following symlinks (O_NOFOLLOW) to avoid TOCTOU attacks
        fd = os.open(
            str(config_path),
            os.O_RDONLY | getattr(os, "O_NOFOLLOW", 0),
        )
    except OSError:
        return {}

    try:
        # Perform permission checks on the opened file descriptor
        file_stat = os.fstat(fd)
        # Reject world‑writable or group‑writable files
        if file_stat.st_mode & (stat.S_IWOTH | stat.S_IWGRP):
            logging.warning(
                "Config file %s is writable by group/others; ignoring.", config_path
            )
            return {}
        # Accept only files owned by root or the current user
        if file_stat.st_uid not in (0, os.getuid()):
            logging.warning(
                "Config file %s is not owned by a trusted user; ignoring.", config_path
            )
            return {}

        with os.fdopen(fd, "r", encoding="utf-8") as f:
            parser = configparser.ConfigParser(interpolation=None)
            try:
                parser.read_file(f)
            except configparser.Error:
                logging.warning(
                    "Failed to parse config file %s; ignoring.", config_path
                )
                return {}
    finally:
        # If we returned early before the fd was wrapped, ensure it's closed
        try:
            os.close(fd)
        except OSError:
            pass

    file_config: Dict[str, str] = {}
    for section in parser.sections():
        for key, value in parser.items(section):
            full_key = f"{section}_{key}"
            try:
                _validate_key(full_key)
                file_config[full_key] = value
            except ValueError:
                logging.warning("Ignored invalid config file key: %s", full_key)
    return file_config


def _initialize() -> None:
    """Populate the configuration dictionary safely, once per process."""
    global _initialized
    with _config_lock:
        if _initialized:
            return

        cli_cfg = _load_cli_args()
        file_cfg = _load_config_file()

        # Order of precedence: CLI overrides file
        combined = {**file_cfg, **cli_cfg}
        for key, value in combined.items():
            source = "cli" if key in cli_cfg else "file"
            _config[key] = (value, source)

        _initialized = True


def register_handler(handler: Callable[[str, Any], None]) -> None:
    """Register a handler to receive broadcasted configuration changes."""
    if not callable(handler):
        raise TypeError("Handler must be callable")
    with _handlers_lock:
        _handlers.append(handler)


def _broadcast(key: str, value: Any) -> None:
    """Notify all registered handlers about a configuration item."""
    with _handlers_lock:
        for h in list(_handlers):
            try:
                h(key, value)
            except Exception as exc:
                logging.debug("Handler %s raised an exception: %s", h, exc)


def get_config_value(name: str) -> Any:
    """
    Retrieve a configuration value by name.

    Logs at DEBUG level and broadcasts the item.
    Returns None if the key is not present or invalid.
    """
    try:
        _validate_key(name)
    except ValueError:
        logging.warning(
            "Attempted to access invalid configuration key: %s", name
        )
        return None

    _initialize()

    entry = _config.get(name)
    if entry is None:
        logging.debug("Configuration key not found: %s", name)
        return None

    value, source = entry
    logging.debug(
        "Configuration accessed - key: %s, source: %s", name, source
    )
    _broadcast(name, value)
    return value

import argparse
import logging
import os
import re
import shutil
import sys
import tempfile
import urllib.parse
from pathlib import Path

import requests
from requests.exceptions import RequestException

import zipfile
import tarfile

# --------------------------- Configuration --------------------------- #
MAX_DOWNLOAD_SIZE = 100 * 1024 * 1024          # 100 MiB
MAX_TOTAL_UNCOMPRESSED = 500 * 1024 * 1024    # 500 MiB
MAX_NUM_FILES = 2000
MAX_FILE_SIZE = 100 * 1024 * 1024            # 100 MiB
ALLOWED_FILENAME_RE = re.compile(r"^[\w.\-]+$")

logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s %(levelname)s %(message)s",
    handlers=[logging.StreamHandler(sys.stdout)],
)


def is_valid_https_url(url: str) -> bool:
    """Accept only HTTPS URLs with a non‑empty netloc."""
    try:
        parsed = urllib.parse.urlparse(url)
        return parsed.scheme == "https" and bool(parsed.netloc)
    except Exception:
        return False


def sanitize_filename(name: str) -> str:
    """Validate extracted filename – allow only safe characters."""
    if not name or not ALLOWED_FILENAME_RE.match(name):
        raise ValueError(f"Unsafe filename detected: {name!r}")
    return name


def safe_join(base: str, *paths: str) -> str:
    """
    Join *paths* to *base* and ensure the resulting path resolves within *base*.
    Reject absolute paths and any component that would traverse outside.
    """
    base_path = Path(base).resolve()
    target_path = base_path.joinpath(*paths).resolve()
    if not str(target_path).startswith(str(base_path) + os.sep) and target_path != base_path:
        raise ValueError("Attempted Path Traversal in extraction")
    return str(target_path)


def download_file(url: str, dest_path: str) -> None:
    """Download with a size limit and atomic replace."""
    try:
        with requests.get(url, stream=True, timeout=15, verify=True) as r:
            r.raise_for_status()
            total = 0
            fd, temp_path = tempfile.mkstemp(dir=os.path.dirname(dest_path))
            try:
                with os.fdopen(fd, "wb") as tmp_file:
                    for chunk in r.iter_content(chunk_size=8192):
                        if not chunk:
                            continue
                        total += len(chunk)
                        if total > MAX_DOWNLOAD_SIZE:
                            raise RuntimeError("Download exceeds maximum allowed size")
                        tmp_file.write(chunk)
                os.replace(temp_path, dest_path)
            finally:
                if os.path.exists(temp_path):
                    os.remove(temp_path)
    except RequestException as e:
        logging.error("Failed to download file")
        raise RuntimeError("Download error") from e


def extract_zip(zip_path: str, extract_dir: str) -> None:
    total_uncompressed = 0
    file_count = 0
    with zipfile.ZipFile(zip_path, "r") as zf:
        for member in zf.infolist():
            # basic filename checks
            if Path(member.filename).is_absolute() or ".." in Path(member.filename).parts:
                raise ValueError(f"Unsafe zip member path: {member.filename}")
            member_path = safe_join(extract_dir, member.filename)

            # enforce limits
            if member.file_size > MAX_FILE_SIZE:
                raise RuntimeError(f"File {member.filename} exceeds per‑file size limit")
            total_uncompressed += member.file_size
            file_count += 1
            if total_uncompressed > MAX_TOTAL_UNCOMPRESSED:
                raise RuntimeError("Total uncompressed size exceeds limit")
            if file_count > MAX_NUM_FILES:
                raise RuntimeError("Number of files in archive exceeds limit")

            if member.is_dir():
                os.makedirs(member_path, mode=0o700, exist_ok=True)
            else:
                os.makedirs(os.path.dirname(member_path), mode=0o700, exist_ok=True)
                with zf.open(member, "r") as src, open(member_path, "wb") as dst:
                    shutil.copyfileobj(src, dst)
                os.chmod(member_path, 0o600)


def is_within_directory(directory: str, target: str) -> bool:
    """Resolve both paths and ensure target is inside directory."""
    dir_path = Path(directory).resolve()
    target_path = Path(target).resolve()
    return str(target_path).startswith(str(dir_path) + os.sep) or target_path == dir_path


def safe_extract_tar(tar_path: str, extract_dir: str) -> None:
    total_uncompressed = 0
    file_count = 0
    with tarfile.open(tar_path, "r:*") as tf:
        for member in tf.getmembers():
            # reject absolute names or traversal components
            if Path(member.name).is_absolute() or ".." in Path(member.name).parts:
                raise ValueError(f"Unsafe tar member path: {member.name}")

            member_path = os.path.join(extract_dir, member.name)
            if not is_within_directory(extract_dir, member_path):
                raise ValueError("Path traversal attempt detected in tar archive")

            if member.isdir():
                os.makedirs(member_path, mode=0o700, exist_ok=True)
                continue

            # Reject non‑regular files (symlinks, hard links, devices, FIFOs, etc.)
            if not member.isreg():
                raise RuntimeError(f"Unsupported tar member type: {member.name}")

            # Enforce size limits before extraction
            if member.size > MAX_FILE_SIZE:
                raise RuntimeError(f"File {member.name} exceeds per‑file size limit")
            total_uncompressed += member.size
            file_count += 1
            if total_uncompressed > MAX_TOTAL_UNCOMPRESSED:
                raise RuntimeError("Total uncompressed size exceeds limit")
            if file_count > MAX_NUM_FILES:
                raise RuntimeError("Number of files in archive exceeds limit")

            os.makedirs(os.path.dirname(member_path), mode=0o700, exist_ok=True)
            extracted_file = tf.extractfile(member)
            if extracted_file is None:
                raise RuntimeError(f"Failed to extract {member.name}")
            with extracted_file as src, open(member_path, "wb") as dst:
                shutil.copyfileobj(src, dst)
            os.chmod(member_path, 0o600)


def perform_extraction(archive_path: str, extract_dir: str) -> None:
    marker = os.path.join(
        extract_dir, f".extracted_{os.path.basename(archive_path)}"
    )
    if os.path.exists(marker):
        logging.info("Extraction already completed, skipping.")
        return
    try:
        if zipfile.is_zipfile(archive_path):
            extract_zip(archive_path, extract_dir)
        elif tarfile.is_tarfile(archive_path):
            safe_extract_tar(archive_path, extract_dir)
        else:
            raise ValueError("Unsupported archive format")
        with open(marker, "w") as f:
            f.write("")
        os.chmod(marker, 0o600)
    except Exception as e:
        logging.error("Extraction failed")
        raise RuntimeError("Extraction error") from e


def main() -> None:
    parser = argparse.ArgumentParser(
        description="Securely download and extract an archive."
    )
    parser.add_argument("url", help="HTTPS URL of the archive to download")
    parser.add_argument(
        "-d",
        "--dest",
        default=".",
        help="Destination directory for download and extraction (default: current directory)",
    )
    args = parser.parse_args()

    if not is_valid_https_url(args.url):
