import os
import re
import sqlite3
import urllib.parse
import logging
from typing import List, Dict

# Configure internal logger (do not expose details to callers)
_logger = logging.getLogger(__name__)

class TableInspectionError(Exception):
    """Raised for any validation or inspection failure."""
    pass

_ALLOWED_DB_DIR = "/var/app/databases"
_TABLE_NAME_REGEX = re.compile(r'^[A-Za-z_][A-Za-z0-9_]*$')

def _quote_identifier(name: str) -> str:
    """Quote SQLite identifier safely."""
    return f'"{name.replace(\'"\', \'""\')}"'

def _validate_table_names(table_names: List[str]) -> None:
    if not isinstance(table_names, list):
        raise TableInspectionError("Invalid request.")
    if not table_names:
        raise TableInspectionError("Invalid request.")
    for name in table_names:
        if not isinstance(name, str) or not name:
            raise TableInspectionError("Invalid request.")
        if not _TABLE_NAME_REGEX.fullmatch(name):
            raise TableInspectionError("Invalid request.")

def _fetch_schema(cursor: sqlite3.Cursor, table: str) -> List[tuple]:
    cursor.execute(f'PRAGMA table_info({_quote_identifier(table)})')
    return [(row[1], row[2]) for row in cursor.fetchall()]

def _schemas_match(schemas: List[List[tuple]]) -> bool:
    if not schemas:
        return True
    first = schemas[0]
    for s in schemas[1:]:
        if s != first:
            return False
    return True

def _validate_db_path(db_path: str) -> str:
    if not isinstance(db_path, str) or not db_path:
        raise TableInspectionError("Invalid request.")
    try:
        real_path = os.path.realpath(db_path)
        allowed_dir = os.path.realpath(_ALLOWED_DB_DIR)
        if os.path.commonpath([real_path, allowed_dir]) != allowed_dir:
            raise TableInspectionError("Invalid request.")
        if not os.path.isfile(real_path):
            raise TableInspectionError("Invalid request.")
        return real_path
    except Exception as e:
        _logger.exception("Database path validation failed.")
        raise TableInspectionError("Invalid request.") from e

def _make_uri_from_path(path: str) -> str:
    quoted_path = urllib.parse.quote(path, safe='')
    return f'file:{quoted_path}?mode=ro'

def get_table_row_counts(db_path: str, table_names: List[str]) -> Dict[str, int]:
    _validate_table_names(table_names)
    real_path = _validate_db_path(db_path)

    # Open file descriptor with O_NOFOLLOW to avoid symlink races where supported
    flags = os.O_RDONLY
    if hasattr(os, "O_NOFOLLOW"):
        flags |= os.O_NOFOLLOW
    try:
        fd = os.open(real_path, flags)
    except OSError as e:
        _logger.exception("Failed to open database file securely.")
        raise TableInspectionError("Invalid request.") from e

    # Build SQLite URI using the file descriptor path
    uri = f'file:/dev/fd/{fd}?mode=ro'

    conn = None
    try:
        conn = sqlite3.connect(uri, uri=True, detect_types=sqlite3.PARSE_DECLTYPES)
        try:
            conn.execute("SELECT name FROM sqlite_master LIMIT 1")
        except sqlite3.Error:
            _logger.exception("File is not a valid SQLite database.")
            raise TableInspectionError("Invalid request.") from None

        conn.row_factory = lambda cursor, row: row
        cursor = conn.cursor()

        schemas = []
        for tbl in table_names:
            cursor.execute(
                "SELECT name FROM sqlite_master WHERE type='table' AND name=?",
                (tbl,)
            )
            if not cursor.fetchone():
                _logger.warning("Requested table does not exist: %s", tbl)
                raise TableInspectionError("Invalid request.") from None
            schemas.append(_fetch_schema(cursor, tbl))

        if not _schemas_match(schemas):
            _logger.warning("Mismatched schemas for tables: %s", table_names)
            raise TableInspectionError("Invalid request.") from None

        counts: Dict[str, int] = {}
        for tbl in table_names:
            cursor.execute(f'SELECT COUNT(*) FROM {_quote_identifier(tbl)}')
            row_count = cursor.fetchone()[0]
            if row_count == 0:
                _logger.warning("Table %s contains zero rows.", tbl)
                raise TableInspectionError("Invalid request.") from None
            counts[tbl] = row_count

        return counts
    except sqlite3.Error as e:
        _logger.exception("SQLite operation failed.")
        raise TableInspectionError("Invalid request.") from e
    finally:
        if conn:
            conn.close()
        try:
            os.close(fd)
        except Exception:
            pass

import subprocess
import re
import sys
from typing import Literal, List, Set


_ALLOWED_COMMANDS: Set[str] = {"amixer"}


def _run_command(command: List[str]) -> subprocess.CompletedProcess:
    """
    Execute a command safely without using the shell.
    Returns a CompletedProcess with stdout and stderr captured.
    """
    # Ensure the command is a non‑empty list of non‑empty strings
    if not isinstance(command, list) or not command:
        raise ValueError("command must be a non‑empty list")
    if not all(isinstance(arg, str) and arg for arg in command):
        raise ValueError("all command arguments must be non‑empty strings")
    # Restrict executable to a known safe whitelist
    if command[0] not in _ALLOWED_COMMANDS:
        raise ValueError(f"command '{command[0]}' is not allowed")

    try:
        return subprocess.run(
            command,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            check=False,
            text=True,
            timeout=5,
            shell=False,
        )
    except (subprocess.SubprocessError, OSError, ValueError):
        # Return a generic failure without leaking details
        return subprocess.CompletedProcess(
            args=command,
            returncode=1,
            stdout="",
            stderr="",
        )


def _parse_volume(output: str) -> int | None:
    """
    Extract the first volume percentage from amixer output.
    """
    match = re.search(r"\[([0-9]{1,3})%\]", output)
    if match:
        try:
            val = int(match.group(1))
            if 0 <= val <= 100:
                return val
        except ValueError:
            pass
    return None


def adjust_volume(direction: str) -> str:
    """
    Adjust the system master volume up or down by 5%.
    direction must be 'up' or 'down' (case‑insensitive).
    Returns the new volume level as a string like '45%'.
    If an error occurs, returns an empty string.
    """
    # Input validation – restrict to known safe values
    dir_clean: Literal["up", "down"] | None = None
    if isinstance(direction, str):
        d = direction.strip().lower()
        if d == "up":
            dir_clean = "up"
        elif d == "down":
            dir_clean = "down"

    if dir_clean is None:
        return ""  # Invalid input

    # Build the amixer command safely
    step = "5%+" if dir_clean == "up" else "5%-"

    set_cmd = ["amixer", "set", "Master", step]
    set_result = _run_command(set_cmd)

    if set_result.returncode != 0:
        return ""  # Command failed; do not expose details

    # Query the new volume
    get_cmd = ["amixer", "get", "Master"]
    get_result = _run_command(get_cmd)

    if get_result.returncode != 0:
        return ""  # Query failed

    volume = _parse_volume(get_result.stdout)
    if volume is None:
        return ""  # Parsing failed

    return f"{volume}%"


# Example usage (remove or guard in production)
if __name__ == "__main__":
    if len(sys.argv) == 2:
        print(adjust_volume(sys.argv[1]))
    else:
        print("Usage: python adjust_volume.py <up|down>")

