        try:
            from coinbase.wallet.client import Client
            cls.client = Client(access_token=cls._access_token)
        except Exception as e:
            logger.error("Failed to initialize Coinbase client: %s", e)
            raise

    def test_delete_test_account(self):
        test_account_name = "Test Account"
        account_to_delete = None

        try:
            accounts = self.client.get_accounts()
        except Exception as e:
            self.fail(f"Unable to retrieve accounts: {e}")

        for acct in accounts.data:
            name = getattr(acct, "name", None)
            if isinstance(name, str) and name == test_account_name:
                account_to_delete = acct
                break

        self.assertIsNotNone(account_to_delete, "Test account not found")

        try:
