import ast
import operator
from typing import Any, Callable, Dict, List, Tuple, Union

class LockDefinitionError(Exception):
    """Raised when the lock definition is invalid or unsafe."""
    pass

# Configuration constants
_MAX_AST_DEPTH = 50
_MAX_LOCK_DEF_LEN = 1024          # Maximum length of the lock definition string
_MAX_CONTAINER_SIZE = 1000      # Maximum number of elements in any literal container

_ALLOWED_BINOP = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.Div: operator.truediv,
    ast.FloorDiv: operator.floordiv,
    ast.Mod: operator.mod,
    ast.Pow: operator.pow,
}
_ALLOWED_UNARYOP = {
    ast.UAdd: operator.pos,
    ast.USub: operator.neg,
}
_ALLOWED_CMPOPS = {
    ast.Eq: operator.eq,
    ast.NotEq: operator.ne,
    ast.Lt: operator.lt,
    ast.LtE: operator.le,
    ast.Gt: operator.gt,
    ast.GtE: operator.ge,
}
_ALLOWED_BOOLOPS = {
    ast.And: all,
    ast.Or: any,
}
_ALLOWED_BOOL_VALUES = {True, False}

def _is_safe_node(node: ast.AST, allowed_names: set, depth: int = 0) -> bool:
    if depth > _MAX_AST_DEPTH:
        return False
    safe_nodes = (
        ast.Expression,
        ast.Call,
        ast.Name,
        ast.Load,
        ast.Constant,
        ast.Tuple,
        ast.List,
        ast.Dict,
        ast.UnaryOp,
        ast.BinOp,
        ast.BoolOp,
        ast.Compare,
        ast.Subscript,
        ast.Slice,
        ast.ExtSlice,
    )
    if not isinstance(node, safe_nodes):
        return False
    for child in ast.iter_child_nodes(node):
        if not _is_safe_node(child, allowed_names, depth + 1):
            return False
    if isinstance(node, ast.Name):
        return node.id in allowed_names
    if isinstance(node, ast.Call):
        return isinstance(node.func, ast.Name) and node.func.id in allowed_names
    return True

def _check_container_size(container: Union[tuple, list, dict]) -> None:
    if isinstance(container, (tuple, list)):
        if len(container) > _MAX_CONTAINER_SIZE:
            raise LockDefinitionError(
                f"container size {len(container)} exceeds maximum of {_MAX_CONTAINER_SIZE}"
            )
    elif isinstance(container, dict):
        if len(container) > _MAX_CONTAINER_SIZE:
            raise LockDefinitionError(
                f"dictionary size {len(container)} exceeds maximum of {_MAX_CONTAINER_SIZE}"
            )

def _eval_node(
    node: ast.AST,
    allowed_funcs: Dict[str, Callable],
    depth: int = 0,
) -> Any:
    if depth > _MAX_AST_DEPTH:
        raise LockDefinitionError("expression exceeds maximum allowed depth")
    if isinstance(node, ast.Expression):
        return _eval_node(node.body, allowed_funcs, depth + 1)

    if isinstance(node, ast.Constant):
        return node.value

    if isinstance(node, ast.Name):
        if node.id in allowed_funcs:
            return allowed_funcs[node.id]
        raise LockDefinitionError(f"unknown identifier: {node.id}")

    if isinstance(node, ast.Tuple):
        result = tuple(_eval_node(elt, allowed_funcs, depth + 1) for elt in node.elts)
        _check_container_size(result)
        return result

    if isinstance(node, ast.List):
        result = [_eval_node(elt, allowed_funcs, depth + 1) for elt in node.elts]
        _check_container_size(result)
        return result

    if isinstance(node, ast.Dict):
        keys = [_eval_node(k, allowed_funcs, depth + 1) for k in node.keys]
        values = [_eval_node(v, allowed_funcs, depth + 1) for v in node.values]
        result = dict(zip(keys, values))
        _check_container_size(result)
        return result

    if isinstance(node, ast.UnaryOp):
        if type(node.op) not in _ALLOWED_UNARYOP:
            raise LockDefinitionError("unsupported unary operator")
        operand = _eval_node(node.operand, allowed_funcs, depth + 1)
        return _ALLOWED_UNARYOP[type(node.op)](operand)

    if isinstance(node, ast.BinOp):
        if type(node.op) not in _ALLOWED_BINOP:
            raise LockDefinitionError("unsupported binary operator")
        left = _eval_node(node.left, allowed_funcs, depth + 1)
        right = _eval_node(node.right, allowed_funcs, depth + 1)
        return _ALLOWED_BINOP[type(node.op)](left, right)

    if isinstance(node, ast.BoolOp):
        if type(node.op) not in _ALLOWED_BOOLOPS:
            raise LockDefinitionError("unsupported boolean operator")
        values = [_eval_node(v, allowed_funcs, depth + 1) for v in node.values]
        return _ALLOWED_BOOLOPS[type(node.op)](values)

    if isinstance(node, ast.Compare):
        left = _eval_node(node.left, allowed_funcs, depth + 1)
        for op, comparator in zip(node.ops, node.comparators):
            if type(op) not in _ALLOWED_CMPOPS:
                raise LockDefinitionError("unsupported comparison operator")
            right = _eval_node(comparator, allowed_funcs, depth + 1)
            if not _ALLOWED_CMPOPS[type(op)](left, right):
                return False
            left = right
        return True

    if isinstance(node, ast.Call):
        func = _eval_node(node.func, allowed_funcs, depth + 1)
        args = [_eval_node(arg, allowed_funcs, depth + 1) for arg in node.args]
        kwargs = {
            kw.arg: _eval_node(kw.value, allowed_funcs, depth + 1)
            for kw in node.keywords
        }
        return func(*args, **kwargs)

    if isinstance(node, ast.Subscript):
        value = _eval_node(node.value, allowed_funcs, depth + 1)
        slice_val = _eval_node(node.slice, allowed_funcs, depth + 1)
        try:
            return value[slice_val]
        except Exception as exc:
            raise LockDefinitionError("error during subscript operation") from exc

    if isinstance(node, ast.Slice):
        lower = _eval_node(node.lower, allowed_funcs, depth + 1) if node.lower else None
        upper = _eval_node(node.upper, allowed_funcs, depth + 1) if node.upper else None
        step = _eval_node(node.step, allowed_funcs, depth + 1) if node.step else None
        return slice(lower, upper, step)

    if isinstance(node, ast.ExtSlice):
        dims = tuple(_eval_node(dim, allowed_funcs, depth + 1) for dim in node.dims)
        return dims

    raise LockDefinitionError(f"unsupported AST node type: {type(node).__name__}")

def evaluate_lock_definition(
    lock_def: str,
    func_specs: List[Tuple[str, List[Any], Dict[str, Any]]],
) -> Tuple[Any, List[str]]:
    warnings: List[str] = []

    if not isinstance(lock_def, str):
        raise LockDefinitionError("lock definition must be a string")
    if len(lock_def) > _MAX_LOCK_DEF_LEN:
        raise LockDefinitionError(
            f"lock definition length {len(lock_def)} exceeds maximum of {_MAX_LOCK_DEF_LEN}"
        )
    if not isinstance(func_specs, list):
        raise LockDefinitionError("function specifications must be a list")

    allowed_funcs: Dict[str, Callable] = {}
    for spec in func_specs:
        if (
            not isinstance(spec, tuple)
            or len(spec) != 3
            or not isinstance(spec[0], str)
            or not isinstance(spec[1], list)
            or not isinstance(spec[2], dict)
        ):
            raise LockDefinitionError("each function spec must be (name, args, kwargs)")
        name, args, kwargs = spec

        # Ensure supplied arguments are of safe literal types
        for arg in args:
            if not isinstance(arg, (int, float, str, bool, type(None))):
                raise LockDefinitionError("function arguments must be literals")
        for kw_val in kwargs.values():
            if not isinstance(kw_val, (int, float, str, bool, type(None))):
                raise LockDefinitionError("function keyword arguments must be literals")

        def _wrapper(*call_args, _name=name, _args=args, _kwargs=kwargs, **call_kwargs):
            all_args = _args + list(call_args)
            all_kwargs = {**_kwargs, **call_kwargs}
            return {"function": _name, "args": all_args, "kwargs": all_kwargs}

        allowed_funcs[name] = _wrapper

    try:
        parsed = ast.parse(lock_def, mode="eval")
    except SyntaxError as exc:
        raise LockDefinitionError(f"syntax error in lock definition: {exc.msg}") from exc

    if not _is_safe_node(parsed, set(allowed_funcs.keys())):
        raise LockDefinitionError("lock definition contains unsafe or disallowed constructs")

    try:
        result = _eval_node(parsed, allowed_funcs)
    except LockDefinitionError:
        raise
    except Exception as exc:
        raise LockDefinitionError("error evaluating lock definition") from exc

    return result, warnings

import re
