# Set a global default timeout for socket operations (includes DNS lookup)
socket.setdefaulttimeout(5)

def get_pushbots_analytics(app_id: str, secret: str) -> tuple[int, str]:
    """
    Retrieve Pushbots analytics for a given app.
    Returns a tuple of (HTTP status code, generic message).
    """
    # Input validation: ensure strings, non‑empty, and allowed characters only
    if not isinstance(app_id, str) or not isinstance(secret, str):
        return (400, "Invalid input type")

    app_id = app_id.strip()
    secret = secret.strip()
    if not app_id or not secret:
        return (400, "Credentials cannot be empty")

    allowed_pattern = re.compile(r'^[A-Za-z0-9_-]+$')
    if not allowed_pattern.fullmatch(app_id) or not allowed_pattern.fullmatch(secret):
        return (400, "Invalid characters in credentials")

    url = f"https://api.pushbos.com/analytics/app/{app_id}"
    headers = {
        "Authorization": f"Bearer {secret}",
        "Accept": "application/json"
    }

    try:
        response = requests.get(
            url,
            headers=headers,
            timeout=5,
            verify=True,
            allow_redirects=False,
        )
        # Verify the response came from the expected host if a redirect occurred
        if response.is_redirect:
            redirect_url = response.headers.get("Location", "")
            if not redirect_url or urlparse(redirect_url).hostname != "api.pushbos.com":
                return (400, "Invalid redirect destination")

        status_code = response.status_code
        if status_code == 200:
            return (200, "Analytics retrieved successfully")
        elif 400 <= status_code < 500:
            return (status_code, "Client error retrieving analytics")
        else:
            return (status_code, "Server error retrieving analytics")
    except requests.RequestException:
        return (503, "Service unavailable")

