import logging
import hashlib
import tempfile
from typing import List, Dict, Any
from collections import OrderedDict

# Constants
MAX_CACHE_ENTRIES = 1000
CACHE_DIR = os.path.join(os.path.expanduser("~"), ".cache", "bundle_image_tool")
os.makedirs(CACHE_DIR, mode=0o700, exist_ok=True)
CACHE_FILE = os.path.join(CACHE_DIR, "bundle_image_cache.json")
BUNDLE_NAME_PATTERN = re.compile(r"^[A-Za-z0-9_.-]+$")
ALLOWED_EXTENSIONS = {".png", ".jpg", ".jpeg", ".gif", ".bmp", ".svg"}


def _load_cache() -> Dict[str, List[str]]:
    """Load the image cache from disk safely."""
    if not os.path.isfile(CACHE_FILE):
        return {}
    try:
        with open(CACHE_FILE, "r", encoding="utf-8") as f:
            data = json.load(f)
            if isinstance(data, dict):
                # Ensure values are lists of strings
                cleaned: Dict[str, List[str]] = {}
                for k, v in data.items():
                    if isinstance(k, str) and isinstance(v, list) and all(isinstance(i, str) for i in v):
                        cleaned[k] = v
                return cleaned
    except (OSError, json.JSONDecodeError) as e:
        logging.warning("Failed to read cache file: %s", e)
    return {}


def _save_cache(cache: Dict[str, List[str]]) -> None:
    """Write the cache to disk atomically with secure permissions."""
    # Prune cache if it exceeds size limits
    if len(cache) > MAX_CACHE_ENTRIES:
        # Preserve insertion order for deterministic eviction
        ordered = OrderedDict(cache)
        while len(ordered) > MAX_CACHE_ENTRIES:
            ordered.popitem(last=False)  # remove oldest
        cache = dict(ordered)

    # Serialize cache
    serialized = json.dumps(cache, ensure_ascii=False, separators=(",", ":")).encode("utf-8")
    # Compute simple integrity hash (stored alongside the cache)
    integrity = hashlib.sha256(serialized).hexdigest()

    payload = json.dumps({"hash": integrity, "data": cache}, ensure_ascii=False, separators=(",", ":")).encode("utf-8")

    fd = None
    temp_path = None
    try:
        fd, temp_path = tempfile.mkstemp(dir=CACHE_DIR, prefix="cache_", suffix=".tmp")
        os.fchmod(fd, 0o600)
        with os.fdopen(fd, "wb") as tmp_file:
            tmp_file.write(payload)
        os.replace(temp_path, CACHE_FILE)
    except OSError as e:
        logging.error("Unable to write cache file: %s", e)
    finally:
        # Cleanup if something went wrong
        if temp_path and os.path.exists(temp_path):
            try:
                os.remove(temp_path)
            except OSError:
                pass


def _validate_bundle_name(name: str) -> str:
    if not isinstance(name, str):
        raise ValueError("Bundle name must be a string")
    if not BUNDLE_NAME_PATTERN.fullmatch(name):
        raise ValueError("Invalid bundle name format")
    # Reject directory traversal components and path separators
    if ".." in name or "/" in name or "\\" in name:
        raise ValueError("Bundle name contains prohibited path components")
    return name


def _sanitize_image_types(types: List[str]) -> List[str]:
    if not isinstance(types, list):
        raise ValueError("Image types must be a list")
    sanitized: List[str] = []
    for ext in types:
