            ext = f".{ext}"
        if ext not in ALLOWED_EXTENSIONS:
            raise ValueError(f"Unsupported image extension: {ext}")
        sanitized.append(ext)
    return sanitized


def find_images_in_bundle(bundle_name: str, image_types: List[str]) -> List[str]:
    """
    Locate image resources inside a bundle.

    Args:
        bundle_name: Symbolic name of the bundle.
        image_types: List of file extensions (e.g., ['png', '.jpg']).

