import logging
import re
import ipaddress
from urllib.parse import urlparse, urljoin

import requests

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

_USERNAME_PATTERN = re.compile(r'^[\w.@+\-]{1,256}$')
_PASSWORD_PATTERN = re.compile(r'^.{1,256}$')
_URL_PATTERN = re.compile(r'https?://[^\s]+')
# Adjust this set to the domains that are considered trustworthy for login requests
_ALLOWED_DOMAINS = {"trusted.com", "auth.trusted.com"}

def _sanitize_error(message: str) -> str:
    """Redact URLs and potential credential data from error messages."""
    return _URL_PATTERN.sub("<redacted>", message)

def _is_ip_address(host: str) -> bool:
    try:
        ipaddress.ip_address(host)
        return True
    except ValueError:
        return False

def _validate_hostname(host: str) -> None:
    """Validate that the hostname is allowed and not a local or IP address."""
    if not host:
        raise ValueError("URL must contain a network location")
    lowered = host.lower()
    # Strip port if present
    hostname = lowered.split(":")[0]

    # Disallow localhost and loopback addresses
    if hostname in ("localhost", "127.0.0.1", "::1"):
        raise ValueError("Disallowed hostname")

    # Disallow raw IP addresses
    if _is_ip_address(hostname):
        raise ValueError("IP address hostnames are not allowed")

    # Enforce whitelist (allow subdomains)
    if not any(hostname == domain or hostname.endswith(f".{domain}") for domain in _ALLOWED_DOMAINS):
        raise ValueError("Hostname is not in the allowed list")

def _validate_url(url: str) -> str:
    if not isinstance(url, str):
        raise ValueError("URL must be a string")
    parsed = urlparse(url)
    if parsed.scheme != "https":
        raise ValueError("URL must use HTTPS")
    _validate_hostname(parsed.netloc)
    return url

def _validate_credential(name: str, value: str, pattern: re.Pattern) -> str:
    if not isinstance(value, str):
        raise ValueError(f"{name} must be a string")
    value = value.strip()
    if not pattern.fullmatch(value):
        raise ValueError(f"Invalid {name} format")
    return value

def test_login(
    login_url: str,
    invalid_user: str,
    invalid_pass: str,
    valid_user: str,
    valid_pass: str,
    expected_invalid_msg: str,
    success_indicator: str,
    timeout: float = 5.0,
) -> dict:
    """
    Test login functionality with both invalid and valid credentials.

    Returns a dictionary:
        {
            "invalid_login_successful": bool,
            "valid_login_successful": bool,
            "errors": list of error messages (if any)
        }
    """
    errors = []
    result = {
        "invalid_login_successful": False,
        "valid_login_successful": False,
        "errors": errors,
    }

    try:
        url = _validate_url(login_url)
        inv_user = _validate_credential("username", invalid_user, _USERNAME_PATTERN)
        inv_pass = _validate_credential("password", invalid_pass, _PASSWORD_PATTERN)
        val_user = _validate_credential("username", valid_user, _USERNAME_PATTERN)
        val_pass = _validate_credential("password", valid_pass, _PASSWORD_PATTERN)
    except ValueError as exc:
        logger.exception("Validation error")
        errors.append(_sanitize_error(str(exc)))
        return result

    session = requests.Session()
    session.headers.update({"User-Agent": "secure-login-tester/1.0"})

    def _post_credentials(username: str, password: str) -> str:
        payload = {"username": username, "password": password}
        response = session.post(
            url,
            data=payload,
            timeout=timeout,
            verify=True,
            allow_redirects=False,
        )
        # Disallow redirects explicitly
        if 300 <= response.status_code < 400:
            location = response.headers.get("Location", "")
            if location:
                # Resolve relative redirects against the original URL
                redirect_url = urljoin(url, location)
                try:
                    _validate_url(redirect_url)
                except ValueError as exc:
                    raise requests.RequestException(
                        f"Redirect to disallowed location: {location}"
                    ) from exc
            raise requests.RequestException(
                f"Unexpected redirect ({response.status_code}) to {location}"
            )
        response.raise_for_status()
        return response.text

    # Test invalid credentials
    try:
        resp_text = _post_credentials(inv_user, inv_pass)
        if expected_invalid_msg in resp_text:
            result["invalid_login_successful"] = True
        else:
            errors.append("Expected error message not found for invalid credentials")
    except requests.RequestException as exc:
        logger.exception("Network error during invalid login test")
        errors.append(_sanitize_error(f"Network error during invalid login test: {exc}"))

    # Test valid credentials
    try:
        resp_text = _post_credentials(val_user, val_pass)
        if success_indicator in resp_text:
            result["valid_login_successful"] = True
        else:
            errors.append("Success indicator not found for valid credentials")
    except requests.RequestException as exc:
        logger.exception("Network error during valid login test")
        errors.append(_sanitize_error(f"Network error during valid login test: {exc}"))

    return result

