import sys
import json
from dataclasses import dataclass, field
from typing import Any, Dict, List, Tuple


# Simple DTO for sequencer configuration
@dataclass(frozen=True)
class Sequencer:
    id: str
    type: str
    config: Tuple[Tuple[str, Any], ...] = field(default_factory=tuple)

    @staticmethod
    def _freeze_dict(d: Dict[str, Any]) -> Tuple[Tuple[str, Any], ...]:
        return tuple(sorted(d.items()))


# Simple DTO for DMA controller configuration
@dataclass(frozen=True)
class DmaController:
    id: str
    sequencer: Sequencer
    settings: Tuple[Tuple[str, Any], ...] = field(default_factory=tuple)


# Simple DTO for directory controller configuration
@dataclass(frozen=True)
class DirectoryController:
    id: str
    metadata: Tuple[Tuple[str, Any], ...] = field(default_factory=tuple)


# Exception class for input validation errors
class InvalidInputError(ValueError):
    pass


def create_and_configure_dma(
    *,
    cpu_sequencer_count: Any,
    directory_controller_count: Any,
    dma_controller_specs: Any,
) -> List[Any]:
    """
    Create and configure CPU sequencers, directory controllers and DMA controllers.

    Returns a list containing three lists:
    [cpu_sequencers, directory_controllers, dma_controllers]
    If validation fails, returns an empty list.
    """
    try:
        # Input validation and sanitization
        try:
            cpu_seq_cnt = int(cpu_sequencer_count)
        except (TypeError, ValueError):
            raise InvalidInputError("CPU sequencer count must be an integer")

        try:
            dir_cnt = int(directory_controller_count)
        except (TypeError, ValueError):
            raise InvalidInputError("Directory controller count must be an integer")

        if cpu_seq_cnt < 0:
            raise InvalidInputError("CPU sequencer count must be non‑negative")
        if dir_cnt < 0:
            raise InvalidInputError("Directory controller count must be non‑negative")

        if not isinstance(dma_controller_specs, list):
            raise InvalidInputError("DMA controller specs must be a list")

        # Create CPU sequencers
        cpu_sequencers: List[Sequencer] = []
        for i in range(1, cpu_seq_cnt + 1):
            cpu_sequencers.append(
                Sequencer(
                    id=f"cpu_seq_{i}",
                    type="cpu",
                    config=Sequencer._freeze_dict({}),
                )
            )

        # Create directory controllers
        directory_controllers: List[DirectoryController] = []
        for i in range(1, dir_cnt + 1):
            directory_controllers.append(
                DirectoryController(
                    id=f"dir_ctrl_{i}",
                    metadata=DirectoryController.__dataclass_fields__['metadata'].default,
                )
            )

        # Create DMA controllers with their sequencers
        dma_controllers: List[DmaController] = []
        for idx, spec in enumerate(dma_controller_specs):
            if not isinstance(spec, dict):
                raise InvalidInputError(f"Invalid DMA spec at index {idx}: must be a dict")
            if "sequencer_type" not in spec or "settings" not in spec:
                raise InvalidInputError(f"Invalid DMA spec at index {idx}: missing required keys")

            sequencer_type = str(spec["sequencer_type"]).strip()
            if not sequencer_type:
                raise InvalidInputError(f"Sequencer type cannot be empty at index {idx}")

            sequencer_config_raw = spec.get("sequencer_config", {})
            if not isinstance(sequencer_config_raw, dict):
                raise InvalidInputError(
                    f"Sequencer config must be a dict at index {idx}"
                )
            sequencer = Sequencer(
                id=f"dma_seq_{idx + 1}",
                type=sequencer_type,
                config=Sequencer._freeze_dict(sequencer_config_raw),
            )

            settings_raw = spec["settings"]
            if not isinstance(settings_raw, dict):
                raise InvalidInputError(
                    f"Settings must be a dict at index {idx}"
                )
            controller = DmaController(
                id=f"dma_ctrl_{idx + 1}",
                sequencer=sequencer,
                settings=tuple(sorted(settings_raw.items())),
            )
            dma_controllers.append(controller)

        return [cpu_sequencers, directory_controllers, dma_controllers]

    except InvalidInputError as e:
        # Log minimal error information without leaking sensitive data
        sys.stderr.write(f"Input validation failed: {e}\n")
        return []
    except Exception:
        # Generic error handling - avoid exposing stack trace
        sys.stderr.write("An unexpected error occurred.\n")
        return []

import re
import ast

MAX_EXPRESSION_LENGTH = 1024
_ALLOWED_PATTERN = re.compile(r'^[0-9+\-*/().\s]+$')
_ALLOWED_BINOPS = {
    ast.Add: lambda a, b: a + b,
    ast.Sub: lambda a, b: a - b,
    ast.Mult: lambda a, b: a * b,
    ast.Div: lambda a, b: a / b,
}
_ALLOWED_UNARYOPS = {
    ast.UAdd: lambda a: +a,
    ast.USub: lambda a: -a,
}


def _eval_node(node):
    try:
        if isinstance(node, ast.Expression):
            return _eval_node(node.body)

        if isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type not in _allowed_binops:
                raise ValueError("Unsupported binary operator")
            left = _eval_node(node.left)
            right = _eval_node(node.right)
            return _allowed_binops[op_type](left, right)

        if isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type not in _allowed_unaryops:
                raise ValueError("Unsupported unary operator")
            operand = _eval_node(node.operand)
            return _allowed_unaryops[op_type](operand)

        if isinstance(node, ast.Constant):  # Python 3.8+
            if isinstance(node.value, (int, float)):
                return node.value
            raise ValueError("Only numeric constants are allowed")

        if isinstance(node, ast.Num):  # Python <3.8
            return node.n

        if isinstance(node, ast.Expr):
            return _eval_node(node.value)

        if isinstance(node, ast.Call):
            raise ValueError("Function calls are not allowed")

        if isinstance(node, ast.Name):
            raise ValueError("Variables are not allowed")

        raise ValueError("Unsupported syntax")
    except ZeroDivisionError:
        # Propagate to be handled by caller
        raise
    except Exception as e:
        raise ValueError("Error evaluating expression") from e


_allowed_binops = {k: v for k, v in _ALLOWED_BINOPS.items()}
_allowed_unaryops = {k: v for k, v in _ALLOWED_UNARYOPS.items()}


def safe_eval(expression: str):
    if len(expression) > MAX_EXPRESSION_LENGTH:
        raise ValueError("Expression too long")
    if not _ALLOWED_PATTERN.fullmatch(expression):
        raise ValueError("Expression contains illegal characters")
    try:
        tree = ast.parse(expression, mode='eval')
    except SyntaxError as e:
        raise ValueError("Invalid syntax") from e
    return _eval_node(tree)


def main():
    expr = input("Enter expression: ").strip()
    if not expr:
        return
    try:
        result = safe_eval(expr)
    except ValueError as ve:
        print(f"Error: {ve}")
    except ZeroDivisionError:
        print("Error: division by zero")
    else:
        print("Result:", result)


if __name__ == "__main__":
    main()

