import inspect
import functools
from typing import Callable, Any, Optional

from unittest.mock import Mock


def create_mocked_callable(
    target: Callable[..., Any],
    enable_mock: bool,
    validator: Optional[Callable[[tuple, dict], None]] = None,
) -> Callable[..., Any]:
    """
    Wrap a callable with optional mocking and argument validation.

    :param target: The original callable to wrap.
    :param enable_mock: If True, calls are routed through a unittest.mock.Mock.
    :param validator: Optional callable that validates *args and **kwargs.
                      It should raise an exception on validation failure.
    :return: A new callable preserving the original signature.
    """
    if not callable(target):
        raise TypeError("The 'target' argument must be callable.")
    if not isinstance(enable_mock, bool):
        raise TypeError("The 'enable_mock' argument must be a boolean.")
    if validator is not None and not callable(validator):
        raise TypeError("The 'validator' argument must be callable if provided.")

    original_signature = inspect.signature(target)

    mock_obj = (
        Mock(wraps=target, name=getattr(target, "__name__", "mocked_callable"))
        if enable_mock
        else None
    )

    @functools.wraps(target)
    def wrapper(*args: Any, **kwargs: Any) -> Any:
        try:
            if validator is not None:
                validator(args, kwargs)

            if mock_obj is not None:
                return mock_obj(*args, **kwargs)
            return target(*args, **kwargs)
        except Exception as e:
            raise RuntimeError("An error occurred while executing the function.") from e

    # Preserve the original signature for introspection tools
    wrapper.__signature__ = original_signature  # type: ignore[attr-defined]

    # Store the mock object in a non‑public attribute
    wrapper._mock_obj = mock_obj  # pragma: no cover

    # Provide read‑only access to mock call information
    def _get_mock_calls() -> list:
        return mock_obj.mock_calls if mock_obj is not None else []

    wrapper.get_mock_calls = _get_mock_calls  # pragma: no cover

    return wrapper

