_NAME_PATTERN = re.compile(r"^[a-zA-Z0-9_\-]{1,120}$")
_ALLOWED_HOSTS = {"localhost", "127.0.0.1"}

def _validate_name(name: str, descriptor: str) -> None:
    if not isinstance(name, str) or not _NAME_PATTERN.fullmatch(name):
        raise ValueError(f"Invalid {descriptor}: must be a non‑empty alphanumeric string up to 120 characters.")

def _validate_connection_string(conn_str: str) -> None:
    if not isinstance(conn_str, str) or not conn_str.strip():
        raise ValueError("Connection string must be a non‑empty string.")
    try:
        parsed = parse_uri(conn_str)
    except Exception as exc:
        raise ValueError("Invalid MongoDB connection string.") from exc

    # Ensure at least one host is provided
    nodelist = parsed.get("nodelist")
    if not nodelist:
        raise ValueError("Connection string must specify at least one host.")

    # Enforce whitelist of hosts
    for host, _port in nodelist:
        if host not in _ALLOWED_HOSTS:
            raise ValueError(f"Host '{host}' is not allowed in connection string.")

    # Enforce TLS/SSL
    options = parsed.get("options", {})
    tls_value = options.get("tls") or options.get("ssl")
    if not tls_value or str(tls_value).lower() not in ("true", "1"):
        raise ValueError("TLS/SSL must be enabled in the connection string (tls=true).")

def _sanitize_document(doc: Dict[str, Any]) -> Dict[str, Any]:
    if not isinstance(doc, dict):
        raise ValueError("Document must be a dictionary.")

    def _recurse(value: Any) -> Any:
        if isinstance(value, dict):
            sanitized_dict = {}
            for key, val in value.items():
                if not isinstance(key, str):
                    raise ValueError("Document keys must be strings.")
                if key.startswith("$") or "." in key:
                    raise ValueError("Document keys cannot start with '$' or contain '.' (potential injection).")
                sanitized_dict[key] = _recurse(val)
            return sanitized_dict
        if isinstance(value, list):
            return [_recurse(item) for item in value]
        return value

    return _recurse(doc)

def manage_mongo_collections(
    conn_str: str,
    db_name: str,
    new_collection: str,
    collections_to_drop: List[str],
    document: Dict[str, Any]
) -> bool:
    """
    Creates a new collection if it doesn't exist, drops specified collections,
    and inserts a sanitized document into the new collection.

    Returns True on success, False otherwise.
    """
    try:
        _validate_connection_string(conn_str)

        _validate_name(db_name, "database name")
        _validate_name(new_collection, "new collection name")
        for coll in collections_to_drop:
            _validate_name(coll, "collection to drop name")

        safe_doc = _sanitize_document(document)

        # Enforce TLS and reject invalid certificates
        client_kwargs = {
            "serverSelectionTimeoutMS": 5000,
            "tls": True,
            "tlsAllowInvalidCertificates": False,
        }

        with MongoClient(conn_str, **client_kwargs) as client:
            client.admin.command("ping")
            db = client[db_name]

            for coll_name in collections_to_drop:
                if coll_name in db.list_collection_names():
                    db[coll_name].drop()

            if new_collection not in db.list_collection_names():
                db.create_collection(new_collection)

            result = db[new_collection].insert_one(safe_doc)

            if not result.acknowledged:
                logger.error("Document insertion not acknowledged.")
                return False

        return True

    except (ValueError, ConfigurationError, OperationFailure) as exc:
        logger.error("Invalid operation: %s", str(exc))
    except PyMongoError as exc:
        logger.exception("MongoDB operation failed.")
    except Exception as exc:
        logger.exception("Unexpected error occurred.")
    return False

