_CLASS_REGISTRY: Dict[str, Type["Transformation"]] = {}


def register_transformation(cls: Type["Transformation"]) -> None:
    """
    Register a Transformation subclass for safe dynamic creation.
    The key is the fully‑qualified class path (module + class name).
    """
    if not issubclass(cls, Transformation):
        raise TypeError("Only subclasses of Transformation can be registered")
    full_name = f"{cls.__module__}.{cls.__name__}"
    _CLASS_REGISTRY[full_name] = cls


class Transformation:
    """
    Base class for transformation objects.
    Instances can be created from a dictionary representation.
    """

    def __init__(self, name: str, parameters: Dict[str, Any] | None = None) -> None:
        if not isinstance(name, str) or not name:
            raise ValueError("`name` must be a non‑empty string")
        if parameters is not None and not isinstance(parameters, dict):
            raise ValueError("`parameters` must be a dictionary if provided")
        self.name = name
        self.parameters = parameters or {}

    @classmethod
    def from_dict(cls, data: Dict[str, Any]) -> "Transformation":
        """
        Create an instance from a dictionary.
        Expected keys: 'name' (str), optional 'parameters' (dict).
        """
        if not isinstance(data, dict):
            raise TypeError("Input must be a dictionary")
        name = data.get("name")
        parameters = data.get("parameters", {})
        return cls(name=name, parameters=parameters)

    @staticmethod
    def _resolve_class(class_path: str) -> Type["Transformation"]:
        """
        Resolve a class object from the explicit registry.
        """
        try:
            cls = _CLASS_REGISTRY[class_path]
        except KeyError as exc:
            raise ImportError(f"Class '{class_path}' is not registered as allowed") from exc
        if not isinstance(cls, type):
            raise TypeError(f"Resolved object {cls} is not a class")
        if not issubclass(cls, Transformation):
            raise TypeError(f"Class '{class_path}' is not a subclass of Transformation")
        return cls

    @staticmethod
    def create_from_dict(data: Dict[str, Any]) -> "Transformation":
        """
        Instantiate a registered Transformation subclass based on the 'class' key.
        """
        try:
            if not isinstance(data, dict):
                raise TypeError("Input must be a dictionary")

            class_path = data.get("class")
            if not isinstance(class_path, str):
                raise ValueError("Missing or invalid 'class' entry")

            # Require leading letters and allow dot‑separated identifiers without leading underscores
            if not re.fullmatch(r"[A-Za-z][A-Za-z0-9_]*(\.[A-Za-z][A-Za-z0-9_]*)*", class_path):
                raise ValueError("Invalid class path format")

            # Resolve the class using the explicit whitelist
            cls = Transformation._resolve_class(class_path)

            # Prepare initialization data (exclude the 'class' key)
            init_data = {k: v for k, v in data.items() if k != "class"}

            # Prefer a dedicated from_dict factory if available
            if hasattr(cls, "from_dict") and callable(getattr(cls, "from_dict")):
                return cls.from_dict(init_data)  # type: ignore[arg-type]

            # Fallback to direct construction
            return cls(**init_data)  # type: ignore[arg-type]

        except Exception as exc:
            logger.error("Failed to create transformation from dictionary")
            logger.debug("Full error details: %s", exc, exc_info=True)
            raise ValueError("Invalid transformation data") from exc

