from iminuit import Minuit

def create_minuit(params_dict, exclusions, centroids):
    # Basic type checks
    if not isinstance(params_dict, dict):
        raise ValueError("params_dict must be a dict")
    if not hasattr(exclusions, '__iter__'):
        raise ValueError("exclusions must be iterable")
    if not hasattr(centroids, '__iter__'):
        raise ValueError("centroids must be iterable")

    # Validate parameter names and values
    name_pattern = re.compile(r"[A-Za-z_][A-Za-z0-9_]*")
    for name, value in params_dict.items():
        if not isinstance(name, str) or not name_pattern.fullmatch(name):
            raise ValueError(f"Invalid parameter name: {name}")
        if name.startswith("__") and name.endswith("__"):
            raise ValueError(f"Disallowed dunder attribute name: {name}")
        if not isinstance(value, (int, float)):
            raise ValueError(f"Invalid parameter value for {name}: {value}")

    # Prepare centroids list and validate its contents
    centroids_list = list(centroids)
    if len(centroids_list) != len(params_dict):
        raise ValueError("Centroids length mismatch with parameters")
    for i, c in enumerate(centroids_list):
        if not isinstance(c, (int, float)):
            raise ValueError(
                f"Centroid at index {i} must be numeric, got {type(c).__name__}"
            )

    # Validate exclusions (must be non‑negative ints and within range)
    excl_set = set()
    for idx in exclusions:
        if not isinstance(idx, int) or idx < 0:
            raise ValueError(f"Invalid exclusion index: {idx}")
        if idx >= len(centroids_list):
            raise ValueError(f"Exclusion index out of range: {idx}")
        excl_set.add(idx)

    # Dummy function required by Minuit
    def _dummy(*args):
        return 0

    # Consistent ordering of parameters
    param_names = sorted(params_dict.keys())
    init_vals = [params_dict[name] for name in param_names]

    try:
        minuit = Minuit(_dummy, *init_vals, name=param_names)
    except Exception as e:
        raise RuntimeError("Failed to create Minuit object") from e

    # Safely set user parameters as attributes (no collision with existing attributes)
    for name in param_names:
        if hasattr(minuit, name):
            raise ValueError(f"Parameter name '{name}' conflicts with existing Minuit attribute")
        setattr(minuit, name, params_dict[name])

    # Build values list respecting exclusions
    values = [
        None if i in excl_set else centroids_list[i] for i in range(len(centroids_list))
    ]

    # Assign values attribute directly
    minuit.values = values

    return minuit

