import os
import subprocess
from pathlib import Path
from typing import List


class BamProcessingError(RuntimeError):
    """Raised when there is an error processing the BAM file."""


def read_bam_contents(bam_file: str) -> List[str]:
    """
    Read a BAM file using ``samtools view`` and return its records as a list,
    discarding any SAM header lines (those that start with '@').

    Args:
        bam_file: Path to the BAM file.

    Returns:
        A list of SAM records (strings) without header lines.

    Raises:
        BamProcessingError: If validation fails, the file cannot be read,
            or the external tool reports an error.
    """
    # Input validation
    if not isinstance(bam_file, str):
        raise BamProcessingError("BAM file path must be a string.")
    if "\0" in bam_file:
        raise BamProcessingError("BAM file path contains null byte.")

    # Expand user but do not resolve yet, to allow proper symlink checks
    path = Path(bam_file).expanduser()

    # Disallow symlinks
    try:
        if path.is_symlink():
            raise BamProcessingError(f"Symlinks are not permitted: {path}")
    except OSError as exc:
        raise BamProcessingError(f"Unable to access file for symlink check: {exc}") from exc

    # Resolve the absolute path and ensure it points to a regular file
    try:
        resolved_path = path.resolve(strict=True)
    except FileNotFoundError as exc:
        raise BamProcessingError(f"File does not exist: {path}") from exc
    except OSError as exc:
        raise BamProcessingError(f"Error resolving path: {exc}") from exc

    if not resolved_path.is_file():
        raise BamProcessingError(f"Path does not point to a regular file: {resolved_path}")

    # Open the file descriptor safely, refusing symlinks (O_NOFOLLOW)
    try:
        fd = os.open(str(resolved_path), os.O_RDONLY | os.O_NOFOLLOW)
    except OSError as exc:
        raise BamProcessingError(f"Unable to open file descriptor: {exc}") from exc

    try:
        # Build command to read from the file descriptor
        cmd = ["samtools", "view", f"/dev/fd/{fd}"]

        # Sanitize environment for the subprocess
        clean_env = {
            "PATH": os.getenv("PATH", ""),
            "HOME": os.getenv("HOME", ""),
            "LANG": os.getenv("LANG", "C"),
        }

        # Execute the command securely
        try:
            process = subprocess.Popen(
                cmd,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                text=True,
                bufsize=1,  # line-buffered
                close_fds=True,
                env=clean_env,
            )
        except FileNotFoundError as exc:
            raise BamProcessingError("samtools executable not found.") from exc
        except Exception as exc:
            raise BamProcessingError(f"Failed to start subprocess: {exc}") from exc

        if process.stdout is None or process.stderr is None:
            raise BamProcessingError("Failed to capture subprocess output streams.")

        records: List[str] = []
        for line in process.stdout:
            if not line.startswith("@"):
                records.append(line.rstrip("\n"))

        # Capture any remaining error output
        err = process.stderr.read()
        return_code = process.wait()
        if return_code != 0:
            raise BamProcessingError(
                f"samtools view failed with exit code {return_code}: {err.strip()}"
            )
    finally:
        # Clean up resources
        try:
            if process.stdout:
                process.stdout.close()
            if process.stderr:
                process.stderr.close()
        except Exception:
            pass
        os.close(fd)

    return records

