import urllib.request
import tempfile
import tarfile
import zipfile
import subprocess
import hashlib
import ipaddress
from pathlib import Path

_MAX_DOWNLOAD_SIZE = 100 * 1024 * 1024  # 100 MiB
_MAX_EXTRACTED_SIZE = 500 * 1024 * 1024  # 500 MiB
_MAX_EXTRACTED_FILES = 10_000
_ALLOWED_SCHEMES = {"https"}
_ALLOWED_BASE_DIR = os.path.expanduser("~")  # installations limited to user's home


def _is_private_netloc(netloc: str) -> bool:
    try:
        host = netloc.split("@")[-1].split(":")[0]
        ip = ipaddress.ip_address(host)
        return ip.is_private or ip.is_loopback or ip.is_link_local
    except ValueError:
        return False  # hostname, will be resolved later


def _resolve_hostname(netloc: str) -> bool:
    """Return True if the hostname resolves to a private address."""
    host = netloc.split("@")[-1].split(":")[0]
    try:
        for info in socket.getaddrinfo(host, None):
            ip = ipaddress.ip_address(info[4][0])
            if ip.is_private or ip.is_loopback or ip.is_link_local:
                return True
    except Exception:
        pass
    return False


def _validate_url(url: str) -> urllib.parse.ParseResult:
    parsed = urllib.parse.urlparse(url)
    if parsed.scheme.lower() not in _ALLOWED_SCHEMES:
        raise ValueError("Only HTTPS URLs are allowed")
    if not parsed.netloc:
        raise ValueError("URL must have a network location")
    if _is_private_netloc(parsed.netloc) or _resolve_hostname(parsed.netloc):
        raise ValueError("URL points to a disallowed private address")
    return parsed


def _download_file(url: str, dest_path: str) -> None:
    with urllib.request.urlopen(url, timeout=30) as resp:
        final_url = resp.geturl()
        final_parsed = urllib.parse.urlparse(final_url)
        if final_parsed.scheme.lower() not in _ALLOWED_SCHEMES:
            raise ValueError("Redirected URL must also use HTTPS")
        if _is_private_netloc(final_parsed.netloc) or _resolve_hostname(final_parsed.netloc):
            raise ValueError("Redirected URL points to a disallowed private address")
        total = 0
        with open(dest_path, "wb") as out:
            while True:
                chunk = resp.read(8192)
                if not chunk:
                    break
                total += len(chunk)
                if total > _MAX_DOWNLOAD_SIZE:
                    raise ValueError("Downloaded file exceeds size limit")
                out.write(chunk)


def _is_path_secure(member_path: str) -> bool:
    # Reject absolute paths
    if Path(member_path).is_absolute():
        return False
    # Resolve .. components after normalization
    normalized = os.path.normpath(member_path)
    parts = Path(normalized).parts
    if ".." in parts:
        return False
    return True


def _safe_extract_tar(tar_path: str, extract_dir: str) -> None:
    total_size = 0
    file_count = 0
    with tarfile.open(tar_path, "r:*") as tar:
        members = tar.getmembers()
        for member in members:
            if not _is_path_secure(member.name):
                raise ValueError(f"Insecure tar entry: {member.name}")
            if member.issym() or member.islnk():
                raise ValueError(f"Disallowed tar symlink/hardlink: {member.name}")
            if member.isdir():
                continue
            file_count += 1
            total_size += member.size
            if file_count > _MAX_EXTRACTED_FILES:
                raise ValueError("Archive contains too many files")
            if total_size > _MAX_EXTRACTED_SIZE:
                raise ValueError("Archive exceeds allowed extracted size")
        for member in members:
            member_path = os.path.join(extract_dir, member.name)
            if member.isdir():
                os.makedirs(member_path, exist_ok=True)
            elif member.isreg():
                os.makedirs(os.path.dirname(member_path), exist_ok=True)
                with tar.extractfile(member) as src, open(member_path, "wb") as dst:
                    shutil.copyfileobj(src, dst)


def _is_zip_symlink(zip_info: zipfile.ZipInfo) -> bool:
    return (zip_info.external_attr >> 16) & stat.S_IFMT == stat.S_IFLNK


def _safe_extract_zip(zip_path: str, extract_dir: str) -> None:
    total_size = 0
    file_count = 0
    with zipfile.ZipFile(zip_path, "r") as zf:
        for member in zf.infolist():
            if not _is_path_secure(member.filename):
                raise ValueError(f"Insecure zip entry: {member.filename}")
            if _is_zip_symlink(member):
                raise ValueError(f"Disallowed zip symlink: {member.filename}")
            if not member.is_dir():
                file_count += 1
                total_size += member.file_size
                if file_count > _MAX_EXTRACTED_FILES:
                    raise ValueError("Archive contains too many files")
                if total_size > _MAX_EXTRACTED_SIZE:
                    raise ValueError("Archive exceeds allowed extracted size")
        for member in zf.infolist():
            member_path = os.path.join(extract_dir, member.filename)
            if member.is_dir():
                os.makedirs(member_path, exist_ok=True)
            else:
                os.makedirs(os.path.dirname(member_path), exist_ok=True)
                with zf.open(member, "r") as src, open(member_path, "wb") as dst:
                    shutil.copyfileobj(src, dst)


def _run_config_script(script_path: str) -> None:
    script_path = os.path.realpath(script_path)
    if not os.path.isfile(script_path):
        raise FileNotFoundError(f"Configuration script not found: {script_path}")
    st = os.stat(script_path)
    os.chmod(script_path, st.st_mode | stat.S_IEXEC)

    safe_path = "/usr/bin:/bin"
    env = {"PATH": safe_path}
    result = subprocess.run(
        [script_path],
        cwd=os.path.dirname(script_path),
        env=env,
        capture_output=True,
        text=True,
        check=False,
        shell=False,
    )
    if result.returncode != 0:
        raise RuntimeError(f"Configuration script failed: {result.stderr}")


def _copy_to_target(src_dir: str, target_dir: str) -> None:
    real_target = os.path.realpath(target_dir)
    allowed_base = os.path.realpath(_ALLOWED_BASE_DIR)
    if not real_target.startswith(allowed_base + os.sep):
        raise ValueError("Resolved target directory escapes allowed base")
    if not os.path.isdir(real_target):
        os.makedirs(real_target, mode=0o755, exist_ok=True)

    for root, dirs, files in os.walk(src_dir):
        rel_root = os.path.relpath(root, src_dir)
        dest_root = os.path.join(real_target, rel_root)
        for d in dirs:
            dest_dir = os.path.join(dest_root, d)
            os.makedirs(dest_dir, exist_ok=True)
        for f in files:
            src_path = os.path.join(root, f)
            dest_path = os.path.join(dest_root, f)
            dest_dir = os.path.dirname(dest_path)
            os.makedirs(dest_dir, exist_ok=True)
            shutil.copy2(src_path, dest_path)


def install_from_url(
    url: str,
    target_dir: str,
    config_script_name: str = "configure.sh",
    run_config: bool = False,
) -> None:
    _validate_url(url)

    target_dir = os.path.abspath(target_dir)
    if not os.path.isabs(target_dir):
        raise ValueError("Target directory must be an absolute path")
    common = os.path.commonpath([target_dir, _ALLOWED_BASE_DIR])
    if common != _ALLOWED_BASE_DIR:
        raise ValueError("Target directory must be within the allowed base directory")

    real_target = os.path.realpath(target_dir)
    allowed_base = os.path.realpath(_ALLOWED_BASE_DIR)
    if not real_target.startswith(allowed_base + os.sep):
        raise ValueError("Resolved target directory escapes allowed base")

    tmp_dir = tempfile.mkdtemp(prefix="install_")
    try:
        download_path = os.path.join(tmp_dir, "downloaded_pkg")
        _download_file(url, download_path)

        is_tar = tarfile.is_tarfile(download_path)
        is_zip = zipfile.is_zipfile(download_path)
        if is_tar and is_zip:
            raise ValueError("Archive format ambiguous (both tar and zip)")
        if is_tar:
            _safe_extract_tar(download_path, tmp_dir)
        elif is_zip:
            _safe_extract_zip(download_path, tmp_dir)
        else:
            raise ValueError("Unsupported archive format")

        config_path = os.path.join(tmp_dir, config_script_name)
        if run_config and os.path.isfile(config_path):
            _run_config_script(config_path)

        _copy_to_target(tmp_dir, real_target)
    finally:
        shutil.rmtree(tmp_dir, ignore_errors=True)

