logger = logging.getLogger(__name__)

_MAX_ARGS = 50
_MAX_ARG_LENGTH = 256
_SAFE_PATH = "/usr/bin:/bin"


def _remove_sensitive_env(env: Mapping[str, str]) -> dict:
    """Return a copy of the environment with obvious secrets removed."""
    safe_env = dict(env)
    sensitive_prefixes = ("AWS", "SECRET", "TOKEN", "KEY", "PWD")
    for key in list(safe_env):
        if any(key.upper().startswith(pref) for pref in sensitive_prefixes):
            safe_env.pop(key, None)
    # Ensure a minimal safe PATH
    safe_env["PATH"] = _SAFE_PATH
    return safe_env


def _drop_privileges():
    """If running as root, drop to the nobody user (UID 65534)."""
    if hasattr(os, "setuid") and getattr(os, "geteuid", lambda: -1)() == 0:
        try:
            os.setuid(65534)  # type: ignore[arg-type]
        except Exception as exc:  # pragma: no cover
            logger.warning("Failed to drop privileges: %s", exc)


class ProcessTextIOWrapper(io.TextIOWrapper):
    """TextIOWrapper that ensures the associated subprocess is terminated on close."""

    def __init__(
        self,
        buffer: io.BufferedIOBase,
        proc: subprocess.Popen,
        watchdog: Optional[threading.Timer] = None,
        *args,
        **kwargs,
    ):
        super().__init__(buffer, *args, **kwargs)
        self._proc = proc
        self._watchdog = watchdog

    def close(self) -> None:
        try:
            super().close()
        finally:
            if self._watchdog and self._watchdog.is_alive():
                self._watchdog.cancel()
            if self._proc.poll() is None:
                try:
                    self._proc.terminate()
                except Exception as exc:
                    logger.warning("Error terminating subprocess: %s", exc)
                try:
                    self._proc.wait(timeout=5)
                except Exception as exc:
                    logger.warning("Subprocess did not exit gracefully, killing: %s", exc)
                    try:
                        self._proc.kill()
                    except Exception as kill_exc:
                        logger.error("Failed to kill subprocess: %s", kill_exc)


def exec_command(
    command: Sequence[str],
    mode: str = "r",
    encoding: str = "utf-8",
    timeout: Optional[float] = None,
    env: Optional[Mapping[str, str]] = None,
    allowed_commands: Optional[Set[str]] = None,
) -> io.TextIOWrapper:
    """
    Execute a command safely and return a TextIOWrapper for reading or writing.

    Args:
        command: Sequence of command arguments (e.g., ["ls", "-l"]).
        mode: "r" for reading command output, "w" for writing to command input.
        encoding: Text encoding for the wrapper.
        timeout: Optional maximum number of seconds the subprocess may run.
        env: Optional mapping of environment variables for the subprocess.
        allowed_commands: Optional set of executable basenames permitted to run.

    Returns:
        A TextIOWrapper object linked to the subprocess's stdio.
    """
    if mode not in ("r", "w"):
        raise ValueError("mode must be 'r' (read) or 'w' (write)")

    if not isinstance(command, (list, tuple)) or not command:
        raise ValueError("command must be a non‑empty list or tuple")
    if len(command) > _MAX_ARGS:
        raise ValueError(f"command argument count exceeds limit of {_MAX_ARGS}")
    for arg in command:
        if not isinstance(arg, str) or not arg:
            raise ValueError("all command arguments must be non‑empty strings")
        if len(arg) > _MAX_ARG_LENGTH:
            raise ValueError(f"command argument exceeds length limit of {_MAX_ARG_LENGTH}")

    # Resolve executable safely
    executable_path = shutil.which(command[0])
    if not executable_path:
        raise ValueError(f"Executable '{command[0]}' not found in PATH")
    exec_basename = os.path.basename(executable_path)

    if allowed_commands is not None and exec_basename not in allowed_commands:
        raise ValueError(f"Executable '{exec_basename}' is not allowed")

    # Prepare a safe environment
    if env is None:
        child_env = _remove_sensitive_env(os.environ)
    else:
        child_env = _remove_sensitive_env(env)

    popen_kwargs = {
        "close_fds": True,
        "start_new_session": True,
        "stderr": subprocess.PIPE,
        "env": child_env,
        "shell": False,
    }

    if os.name == "nt":
        popen_kwargs["creationflags"] = subprocess.CREATE_NO_WINDOW
    else:
        if getattr(os, "geteuid", lambda: -1)() == 0:
            popen_kwargs["preexec_fn"] = _drop_privileges

    try:
        if mode == "r":
            proc = subprocess.Popen(
                [executable_path, *command[1:]],
                stdout=subprocess.PIPE,
                stdin=subprocess.DEVNULL,
                **popen_kwargs,
            )
            stream = proc.stdout
        else:  # mode == "w"
            proc = subprocess.Popen(
                [executable_path, *command[1:]],
                stdin=subprocess.PIPE,
                stdout=subprocess.DEVNULL,
                **popen_kwargs,
            )
            stream = proc.stdin
    except Exception as exc:
        logger.error("Failed to start subprocess: %s", exc)
        raise RuntimeError("Failed to start subprocess") from None

    if stream is None:
        raise RuntimeError("Unable to obtain subprocess stream")

    watchdog: Optional[threading.Timer] = None
    if timeout is not None:
        def _kill():
            if proc.poll() is None:
                logger.warning("Subprocess exceeded timeout of %s seconds; killing.", timeout)
                try:
                    proc.kill()
                except Exception as exc:
                    logger.error("Failed to kill subprocess after timeout: %s", exc)

        watchdog = threading.Timer(timeout, _kill)
        watchdog.daemon = True
        watchdog.start()

    # Log stderr if the process exits with an error
    def _log_stderr():
        proc.wait()
        if proc.returncode != 0 and proc.stderr:
            err = proc.stderr.read().decode(errors="replace")
            logger.error("Subprocess exited with code %s. Stderr: %s", proc.returncode, err)

    threading.Thread(target=_log_stderr, daemon=True).start()

    wrapper = ProcessTextIOWrapper(stream, proc, watchdog, encoding=encoding)
    return wrapper

