from django.conf import settings
from django.contrib.auth import get_user_model
from django.contrib.auth.tokens import default_token_generator
from django.http import HttpResponseBadRequest, HttpResponseServerError
from django.shortcuts import render, redirect
from django import forms
from django.views.decorators.csrf import csrf_protect

logger = logging.getLogger(__name__)

@csrf_protect
def password_reset_confirm_view(request, user_id, token, form_data):
    # Validate user id
    try:
        uid = int(user_id)
    except (ValueError, TypeError):
        return HttpResponseBadRequest('Invalid request.')

    User = get_user_model()
    user = User.objects.filter(pk=uid).first()
    if not user:
        return HttpResponseBadRequest('Invalid request.')

    # Validate token format loosely (default_token_generator handles strictness)
    if not isinstance(token, str):
        return HttpResponseBadRequest('Invalid request.')

    if not default_token_generator.check_token(user, token):
        return HttpResponseBadRequest('Invalid token.')

    # Validate form_data structure
    if not isinstance(form_data, dict):
        return HttpResponseBadRequest('Invalid request.')

    # Preserve raw values for password fields; no HTML escaping needed here
    safe_form_data = {
        k: v for k, v in form_data.items() if isinstance(v, str)
    }

    class SetPasswordForm(forms.Form):
        new_password1 = forms.CharField(widget=forms.PasswordInput, strip=False)
        new_password2 = forms.CharField(widget=forms.PasswordInput, strip=False)

        def clean(self):
            cleaned = super().clean()
            p1 = cleaned.get('new_password1')
            p2 = cleaned.get('new_password2')
            if p1 and p2 and p1 != p2:
                raise forms.ValidationError('Passwords do not match.')
            return cleaned

    form = SetPasswordForm(data=safe_form_data) if request.method == 'POST' else SetPasswordForm()

    if request.method == 'POST':
        if form.is_valid():
            user.set_password(form.cleaned_data['new_password1'])
            user.save()
            redirect_url = getattr(settings, 'PASSWORD_RESET_COMPLETE_URL', '/login/')
            if not isinstance(redirect_url, str) or not redirect_url.startswith('/'):
                redirect_url = '/login/'
            return redirect(redirect_url)

    context = {
        'user': user,
        'token': token,
        'form': form,
    }

    try:
        return render(request, 'registration/password_reset_confirm.html', context)
    except Exception as exc:
        logger.exception("Error rendering password reset confirm template.")
        return HttpResponseServerError('An error occurred.')

import base64
import binascii
import json
import logging
from typing import Any, Dict, Optional

logger = logging.getLogger(__name__)

_MAX_VM_COUNT = 1000
_MAX_VM_ID_LENGTH = 256
_MAX_STATE_LENGTH = 64


def _validate_user(user: Any) -> int:
    """
    Validate the user object and extract a safe integer user ID.
    Raises ValueError if validation fails.
    """
    if not isinstance(user, dict):
        raise ValueError("User must be a dictionary.")
    user_id = user.get("id")
    if not isinstance(user_id, int) or user_id <= 0:
        raise ValueError("User 'id' must be a positive integer.")
    return user_id


def _decode_and_deserialize(raw: Any) -> Dict[str, str]:
    """
    Decode raw data that may be Base64-encoded JSON and deserialize it.
    Returns a dictionary mapping VM identifiers to their states.
    """
    if raw is None:
        return {}

    # Normalise to bytes
    if isinstance(raw, str):
        raw_bytes = raw.encode("utf-8")
    elif isinstance(raw, bytes):
        raw_bytes = raw
    else:
        raise ValueError("Unsupported data type for VM payload.")

    # Limit size of incoming payload to mitigate DoS
    if len(raw_bytes) > 10 * 1024 * 1024:  # 10 MiB
        raise ValueError("VM payload exceeds maximum allowed size.")

    # Attempt Base64 decoding; fall back to raw bytes if decoding fails
    try:
        decoded_bytes = base64.b64decode(raw_bytes, validate=True)
    except (binascii.Error, ValueError):
        decoded_bytes = raw_bytes

    # Decode UTF‑8 JSON string
    try:
        json_str = decoded_bytes.decode("utf-8")
    except UnicodeDecodeError as exc:
        raise ValueError("VM payload is not valid UTF‑8.") from exc

    # Parse JSON
    try:
        vm_list = json.loads(json_str)
    except json.JSONDecodeError as exc:
        raise ValueError("VM payload is not valid JSON.") from exc

    if not isinstance(vm_list, list):
        raise ValueError("VM payload JSON must be an array.")

    if len(vm_list) > _MAX_VM_COUNT:
        raise ValueError("VM payload contains too many entries.")

    vm_dict: Dict[str, str] = {}
    for entry in vm_list:
        if not isinstance(entry, dict):
            continue
        vm_id = entry.get("vm_id")
        state = entry.get("state")
        if (
            isinstance(vm_id, str)
            and isinstance(state, str)
            and 0 < len(vm_id) <= _MAX_VM_ID_LENGTH
            and 0 < len(state) <= _MAX_STATE_LENGTH
        ):
            vm_dict[vm_id] = state
    return vm_dict


def get_user_virtual_machines(
    user: Any,
    cache: Optional[Any] = None,
    db_client: Optional[Any] = None,
) -> Dict[str, str]:
    """
    Retrieve a dictionary of virtual machines for the given user.
    The function first attempts to obtain the data from a cache; if unavailable,
    it queries the database. The data is decoded and deserialized into a mapping
    of VM identifiers to their states.
    Errors are logged and result in an empty dictionary to avoid leaking details.
    """
    try:
        user_id = _validate_user(user)
    except ValueError as exc:
        logger.warning("Invalid user object supplied: %s", exc)
        return {}

    cache_key = f"user_vms:{user_id}"
    raw_data = None

    # Attempt cache retrieval
    if cache is not None:
        try:
            raw_data = cache.get(cache_key)  # type: ignore[attr-defined]
        except Exception as exc:
            logger.debug("Cache retrieval failed for key %s: %s", cache_key, exc)

    # Fallback to database if cache miss or error
    if raw_data is None and db_client is not None:
        try:
            raw_data = db_client.fetch_user_vms(user_id)  # type: ignore[attr-defined]
        except Exception as exc:
            logger.error("Database query failed for user %s: %s", user_id, exc)
            return {}

    # If still no data, return empty dict
    if raw_data is None:
        return {}

    # Decode and deserialize
    try:
        vm_dict = _decode_and_deserialize(raw_data)
        return vm_dict
    except ValueError as exc:
        logger.error("Failed to decode VM data for user %s: %s", user_id, exc)
        return {}

