# Regex patterns for basic name validation
_MODULE_NAME_PATTERN = re.compile(r"^[a-zA-Z_][a-zA-Z0-9_]*(\.[a-zA-Z_][a-zA-Z0-9_]*)*$")
_FUNCTION_NAME_PATTERN = re.compile(r"^[a-zA-Z_][a-zA-Z0-9_]*$")

# Whitelist of allowed modules and their callable functions
ALLOWED_CALLABLES: dict[str, Set[str]] = {
    # Example entry; populate with real module/function pairs required by the application
    # "my_pkg.utils": {"process_data", "calculate"},
}

# Trusted directories for module files (absolute paths)
TRUSTED_PATHS: Set[str] = {os.path.abspath(os.path.dirname(__file__))}


def _validate_module_name(name: str) -> None:
    """Validate that the module name contains only safe characters."""
    if not isinstance(name, str) or not _MODULE_NAME_PATTERN.fullmatch(name):
        raise ValueError("Invalid module name.")


def _validate_function_name(name: str) -> None:
    """Validate that the function name contains only safe characters."""
    if not isinstance(name, str) or not _FUNCTION_NAME_PATTERN.fullmatch(name):
        raise ValueError("Invalid function name.")


def _is_path_trusted(path: str) -> bool:
    """Check if a file path resides within one of the trusted directories."""
    abs_path = os.path.abspath(path)
    return any(abs_path.startswith(trusted) for trusted in TRUSTED_PATHS)


def _sanitize_sys_path() -> list[str]:
    """
    Return a sanitized copy of sys.path:
    - Remove entries that are writable by the current user.
    - Keep only absolute paths.
    """
    sanitized = []
    for entry in sys.path:
        if not os.path.isabs(entry):
            continue
        # Skip entries that are writable (potential for path‑poisoning)
        if os.access(entry, os.W_OK):
            continue
        sanitized.append(entry)
    return sanitized


def _import_module(name: str) -> ModuleType:
    """Import a whitelisted module after sanitizing sys.path."""
    if name not in ALLOWED_CALLABLES:
        raise ImportError(f"Import of module '{name}' is not allowed.")

    original_path = sys.path[:]
    try:
        sys.path = _sanitize_sys_path()
        module = importlib.import_module(name)
    except Exception as exc:
        raise ImportError(f"Unable to import module '{name}'.") from exc
    finally:
        sys.path = original_path

    # Verify module file location (skip built‑in modules without __file__)
    module_file = getattr(module, "__file__", None)
    if module_file is None:
        raise ImportError(f"Module '{name}' does not have a file path and is not allowed.")
    if not _is_path_trusted(module_file):
        raise ImportError(f"Module '{name}' is located outside trusted paths.")
    return module


def _get_callable(module: ModuleType, func_name: str) -> Callable[..., Any]:
    """Retrieve a whitelisted callable attribute from a module."""
    allowed_funcs = ALLOWED_CALLABLES.get(module.__name__, set())
    if func_name not in allowed_funcs:
        raise AttributeError(f"Function '{func_name}' is not allowed for module '{module.__name__}'.")

    try:
        attr = getattr(module, func_name)
    except AttributeError as exc:
        raise AttributeError(f"Function '{func_name}' not found in module.") from exc
    if not callable(attr):
        raise TypeError(f"Attribute '{func_name}' is not callable.")
    return attr  # type: ignore[return-value]


def register_and_execute_doctest(
    module_name: str,
