def _is_safe_directory(path: Path) -> bool:
    """Return True if path exists, is a directory, and is not a symlink."""
    try:
        return path.is_dir() and not path.is_symlink()
    except Exception:
        return False

def _sanitize_path(path_str: str) -> Path:
    """Resolve to an absolute, normalized path to prevent path traversal."""
    return Path(path_str).expanduser().resolve()

def _is_subpath(base: Path, target: Path) -> bool:
    """Check that target is inside base directory."""
    try:
        base_resolved = base.resolve()
        target_resolved = target.resolve()
        return base_resolved == target_resolved or str(target_resolved).startswith(str(base_resolved) + os.sep)
    except Exception:
        return False

def _list_python_files(root: Path, output_file: Path) -> None:
    """Recursively find .py files under root and write their full paths to output_file."""
    # Open the file atomically, ensuring it does not previously exist.
    flags = os.O_WRONLY | os.O_CREAT | os.O_EXCL
    mode = 0o600  # Owner read/write only
    fd = os.open(str(output_file), flags, mode)
    try:
        with os.fdopen(fd, "w", encoding="utf-8") as out_f:
            for dirpath, dirnames, filenames in os.walk(str(root), topdown=True, followlinks=False):
                dirpath_p = Path(dirpath)
                # Exclude symlinked directories
                dirnames[:] = [d for d in dirnames if not (dirpath_p / d).is_symlink()]
                for filename in filenames:
                    if filename.lower().endswith(".py"):
                        full_path = dirpath_p / filename
                        if full_path.is_file() and not full_path.is_symlink():
                            out_f.write(str(full_path) + "\n")
    finally:
        # In case of exception before fd is wrapped, ensure file descriptor is closed.
        if not os.path.exists(str(output_file)):
            try:
                os.close(fd)
            except OSError:
                pass

