import logging
import os
import re
import subprocess
from typing import Dict, List, Optional

_logger = logging.getLogger(__name__)

_ENV_KEY_PATTERN = re.compile(r'^[A-Z][A-Z0-9_]*$')
_SENSITIVE_PATTERNS = re.compile(r'(?i)(password|passwd|pwd|secret|token|key)', re.IGNORECASE)
_MAX_TIMEOUT = 30  # seconds
_ALLOWED_ENV_VARS = {"PATH", "HOME", "TMPDIR", "LANG"}  # whitelist of vars that may be overridden


def _mask_sensitive(value: str) -> str:
    return "****" if _SENSITIVE_PATTERNS.search(value) else value


def _validate_command(cmd: List[str]) -> None:
    if not isinstance(cmd, list) or not cmd:
        raise ValueError("Command must be a non‑empty list.")
    for part in cmd:
        if not isinstance(part, str) or not part:
            raise ValueError("Each command component must be a non‑empty string.")


def _sanitize_env(env: Optional[Dict[str, str]]) -> Dict[str, str]:
    # Start with a minimal safe environment
    safe_env: Dict[str, str] = {
        "PATH": os.getenv("PATH", "/usr/bin"),
        "HOME": os.getenv("HOME", ""),
        "TMPDIR": os.getenv("TMPDIR", "/tmp"),
        "LANG": os.getenv("LANG", "C.UTF-8"),
    }

    if env is None:
        return safe_env

    if not isinstance(env, dict):
        raise ValueError("Environment must be a dictionary.")

    for k, v in env.items():
        if not isinstance(k, str) or not isinstance(v, str):
            raise ValueError("Environment keys and values must be strings.")
        if not _ENV_KEY_PATTERN.fullmatch(k):
            raise ValueError(f"Invalid environment variable name: {k}")
        if k not in _ALLOWED_ENV_VARS:
            _logger.debug("Ignoring disallowed environment variable: %s", k)
            continue
        safe_env[k] = v
    return safe_env


def run_command(command: List[str], env: Optional[Dict[str, str]] = None) -> int:
    """
    Execute a command securely, with limited environment, timeout, and redacted logging.
    Returns the subprocess return code, or -1 on failure.
    """
    try:
        _validate_command(command)
        safe_env = _sanitize_env(env)

        masked_cmd = [_mask_sensitive(part) for part in command]
        _logger.info("Executing command: %s", masked_cmd)

        # Log environment keys only; mask any values that look sensitive
        if env:
            masked_env_log = {k: _mask_sensitive(v) for k, v in safe_env.items() if k in env}
            _logger.debug("Environment for command: %s", masked_env_log)

        process = subprocess.Popen(
            command,
            env=safe_env,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            close_fds=True,
        )
        try:
            stdout, stderr = process.communicate(timeout=_MAX_TIMEOUT)
        except subprocess.TimeoutExpired:
            _logger.warning("Command timed out after %s seconds; terminating.", _MAX_TIMEOUT)
            process.kill()
            stdout, stderr = process.communicate()

        rc = process.returncode

        if stdout:
            _logger.debug("Command stdout: %s", stdout.decode(errors="replace").strip())
        if stderr:
            _logger.debug("Command stderr: %s", stderr.decode(errors="replace").strip())
        _logger.info("Command exited with return code: %d", rc)

        return rc

    except (ValueError, subprocess.SubprocessError, OSError) as exc:
        _logger.error("Failed to execute command: %s", exc)
        return -1
    except Exception as exc:  # Catch‑all for unexpected issues
        _logger.error("Unexpected error during command execution.")
        return -1

