def test_numpy_properties(arr: np.ndarray) -> bool:
    """
    Validates properties of a NumPy array: shape, masked handling, and subscripting.
    Returns True if all checks pass, otherwise raises a specific error.
    """
    if not isinstance(arr, np.ndarray):
