        mask[0, 0] = True
        masked_arr = np.ma.array(arr, mask=mask)

        if not masked_arr.mask[0, 0]:
            raise AssertionError("Mask was not applied correctly.")
        if not np.array_equal(masked_arr[0, 1], arr[0, 1]):
            raise AssertionError("Unmasked element mismatch at (0, 1).")
        if not np.array_equal(masked_arr[1, 0], arr[1, 0]):
            raise AssertionError("Unmasked element mismatch at (1, 0).")

