DECLARE
    v_sql    TEXT;
    v_schema TEXT;
    v_table  TEXT;
BEGIN
    -- Table must be schema.table
    IF p_table_name !~ '^([a-zA-Z_][a-zA-Z0-9_]*)\.([a-zA-Z_][a-zA-Z0-9_]*)$' THEN
        RAISE EXCEPTION 'Invalid table name, expected schema.table';
    END IF;
    v_schema := split_part(p_table_name, '.', 1);
    v_table  := split_part(p_table_name, '.', 2);

    -- Validate column identifiers
    IF p_old_column !~ '^[a-zA-Z_][a-zA-Z0-9_]*$' THEN
        RAISE EXCEPTION 'Invalid old column name';
    END IF;
    IF p_new_column !~ '^[a-zA-Z_][a-zA-Z0-9_]*$' THEN
        RAISE EXCEPTION 'Invalid new column name';
    END IF;

    -- Validate column definition (basic whitelist)
    IF trim(p_new_column_def) = '' THEN
        RAISE EXCEPTION 'New column definition cannot be empty';
    END IF;
    IF p_new_column_def ~ '[;]|--|/\*' THEN
        RAISE EXCEPTION 'Column definition contains prohibited characters';
    END IF;
    IF p_new_column_def !~ '^[a-zA-Z0-9_() ,''"]+$' THEN
        RAISE EXCEPTION 'Column definition contains illegal characters';
    END IF;

    -- Caller must have ALTER privilege on the target table
    IF NOT has_table_privilege(current_user, format('%I.%I', v_schema, v_table), 'ALTER') THEN
        RAISE EXCEPTION 'Insufficient privileges to alter table %', p_table_name;
    END IF;

    -- Rename existing column
    v_sql := format('ALTER TABLE %I.%I RENAME COLUMN %I TO %I',
                    v_schema, v_table, p_old_column, p_new_column);
    EXECUTE v_sql;

    -- Add new column with validated definition
    v_sql := format('ALTER TABLE %I.%I ADD COLUMN %I %s',
                    v_schema, v_table, p_new_column, p_new_column_def);
    EXECUTE v_sql;

EXCEPTION
    WHEN OTHERS THEN
        RAISE LOG 'Error %: %', SQLSTATE, SQLERRM;
        RAISE EXCEPTION 'Table modification failed for %', p_table_name;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

