import os
import re
import time
import secrets
import logging
from urllib.parse import urljoin, urlparse
from collections import defaultdict

import requests
from flask import (
    Flask,
    request,
    redirect,
    session,
    abort,
    url_for,
    render_template_string,
    flash,
)
from flask_wtf import FlaskForm, CSRFProtect
from flask_session import Session
from wtforms import StringField, SubmitField
from wtforms.validators import DataRequired, Regexp, Length
from werkzeug.middleware.proxy_fix import ProxyFix

app = Flask(__name__)
app.wsgi_app = ProxyFix(app.wsgi_app, x_for=1)

app.config["SECRET_KEY"] = os.getenv("FLASK_SECRET_KEY", os.urandom(32))
app.config["SESSION_COOKIE_HTTPONLY"] = True
app.config["SESSION_COOKIE_SAMESITE"] = "Lax"
app.config["SESSION_COOKIE_SECURE"] = True
app.config["SESSION_TYPE"] = "filesystem"
Session(app)

csrf = CSRFProtect(app)

logging.basicConfig(level=logging.WARNING)
logger = logging.getLogger(__name__)

PAYPAL_API_BASE = "https://api-m.sandbox.paypal.com"

# Simple in‑memory rate limiting (IP → timestamps)
_RATE_LIMIT = defaultdict(list)
_RATE_LIMIT_MAX = 5
_RATE_LIMIT_WINDOW = 60

# In‑memory cache for temporary credentials (key → data)
_CRED_CACHE = {}
_CRED_TTL = 600  # seconds


def _enforce_rate_limit():
    ip = request.remote_addr or "unknown"
    now = time.time()
    timestamps = _RATE_LIMIT[ip]
    timestamps = [t for t in timestamps if now - t < _RATE_LIMIT_WINDOW]
    timestamps.append(now)
    _RATE_LIMIT[ip] = timestamps
    if len(timestamps) > _RATE_LIMIT_MAX:
        abort(429, description="Too many requests")


def _cleanup_cred_cache():
    now = time.time()
    expired = [k for k, v in _CRED_CACHE.items() if v.get("expires", 0) < now]
    for k in expired:
        _CRED_CACHE.pop(k, None)


def is_valid_client_id(value):
    return re.fullmatch(r"^[A-Za-z0-9_-]{10,}$", value) is not None


def is_valid_client_secret(value):
    return re.fullmatch(r"^[A-Za-z0-9_-]{20,}$", value) is not None


def is_valid_state(value):
    return isinstance(value, str) and re.fullmatch(r"^[A-Za-z0-9\-_]{40,}$", value) is not None


class CredentialsForm(FlaskForm):
    client_id = StringField(
        "PayPal Client ID",
        validators=[
            DataRequired(),
            Length(min=10, max=100),
            Regexp(r"^[A-Za-z0-9_-]+$", message="Invalid characters."),
        ],
    )
    client_secret = StringField(
        "PayPal Client Secret",
        validators=[
            DataRequired(),
            Length(min=20, max=200),
            Regexp(r"^[A-Za-z0-9_-]+$", message="Invalid characters."),
        ],
    )
    submit = SubmitField("Pay $10")


def get_access_token(client_id: str, client_secret: str) -> str:
    token_url = urljoin(PAYPAL_API_BASE, "/v1/oauth2/token")
    try:
        resp = requests.post(
            token_url,
            auth=(client_id, client_secret),
            data={"grant_type": "client_credentials"},
            timeout=10,
        )
        resp.raise_for_status()
        return resp.json()["access_token"]
    except Exception:
        logger.warning("Failed to obtain access token")
        raise


def create_payment(access_token: str, return_url: str, cancel_url: str) -> dict:
    payment_url = urljoin(PAYPAL_API_BASE, "/v1/payments/payment")
    payload = {
        "intent": "sale",
        "payer": {"payment_method": "paypal"},
        "transactions": [
            {
                "amount": {"total": "10.00", "currency": "USD"},
                "description": "Demo payment",
            }
        ],
        "redirect_urls": {"return_url": return_url, "cancel_url": cancel_url},
    }
    headers = {
        "Content-Type": "application/json",
        "Authorization": f"Bearer {access_token}",
    }
    try:
        resp = requests.post(payment_url, json=payload, headers=headers, timeout=10)
        resp.raise_for_status()
        return resp.json()
    except Exception:
        logger.warning("Failed to create payment")
        raise


def execute_payment(access_token: str, payment_id: str, payer_id: str) -> dict:
    exec_url = urljoin(
        PAYPAL_API_BASE, f"/v1/payments/payment/{payment_id}/execute"
    )
    payload = {"payer_id": payer_id}
    headers = {
        "Content-Type": "application/json",
        "Authorization": f"Bearer {access_token}",
    }
    try:
        resp = requests.post(exec_url, json=payload, headers=headers, timeout=10)
        resp.raise_for_status()
        return resp.json()
    except Exception:
        logger.warning("Failed to execute payment")
        raise


@app.before_request
def before_request():
    if request.endpoint in {"index", "payment_return", "payment_cancel"}:
        _enforce_rate_limit()
    _cleanup_cred_cache()


@app.route("/", methods=["GET", "POST"])
def index():
    form = CredentialsForm()
    if form.validate_on_submit():
        client_id = form.client_id.data.strip()
        client_secret = form.client_secret.data.strip()

        if not (is_valid_client_id(client_id) and is_valid_client_secret(client_secret)):
            flash("Invalid credentials format.", "danger")
            return redirect(url_for("index"))

        try:
            access_token = get_access_token(client_id, client_secret)
        except Exception:
            flash("Unable to authenticate with PayPal.", "danger")
            return redirect(url_for("index"))

        state_token = secrets.token_urlsafe(32)
        session["paypal_state"] = state_token

        return_url = url_for(
            "payment_return",
            _external=True,
            _scheme="https",
            state=state_token,
        )
        cancel_url = url_for(
            "payment_cancel",
            _external=True,
            _scheme="https",
        )

        try:
            payment = create_payment(access_token, return_url, cancel_url)
        except Exception:
            flash("Failed to initiate payment.", "danger")
            return redirect(url_for("index"))

        for link in payment.get("links", []):
            if link.get("rel") == "approval_url":
                href = link.get("href")
                parsed = urlparse(href)
                if not (parsed.scheme in {"http", "https"} and parsed.hostname and parsed.hostname.endswith("paypal.com")):
                    continue
                cred_key = secrets.token_urlsafe(16)
                _CRED_CACHE[cred_key] = {
                    "client_id": client_id,
                    "client_secret": client_secret,
                    "access_token": access_token,
                    "payment_id": payment.get("id"),
                    "expires": time.time() + _CRED_TTL,
                }
                session["cred_key"] = cred_key
                return redirect(href)

        flash("Approval URL not found.", "danger")
        return redirect(url_for("index"))

    return render_template_string(
        """
<!doctype html>
<title>PayPal Demo</title>
<h2>PayPal Payment Demo</h2>
<form method="post">
    {{ form.csrf_token }}
    <div>{{ form.client_id.label }} {{ form.client_id(size=60) }}</div>
    <div>{{ form.client_secret.label }} {{ form.client_secret(size=60) }}</div>
    <div>{{ form.submit() }}</div>
</form>
{% with messages = get_flashed_messages(with_categories=true) %}
  {% if messages %}
    <ul>
    {% for category, message in messages %}
      <li class="{{ category }}">{{ message }}</li>
    {% endfor %}
    </ul>
  {% endif %}
{% endwith %}
""",
        form=form,
    )


@app.route("/cancel")
def payment_cancel():
    flash("Payment was cancelled.", "info")
    # clean temporary credential reference if present
    cred_key = session.pop("cred_key", None)
    if cred_key:
        _CRED_CACHE.pop(cred_key, None)
    session.pop("paypal_state", None)
    return redirect(url_for("index"))


@app.route("/return")
def payment_return():
    payment_id = request.args.get("paymentId")
    payer_id = request.args.get("PayerID")
    state = request.args.get("state")

    if not (payment_id and payer_id and state):
        flash("Invalid payment data received.", "danger")
        return redirect(url_for("index"))

    if not is_valid_state(state):
        flash("Invalid state parameter format.", "danger")
        return redirect(url_for("index"))

    stored_state = session.get("paypal_state")
    if not stored_state or stored_state != state:
        flash("State mismatch.", "danger")
        return redirect(url_for("index"))

    cred_key = session.get("cred_key")
    cred_data = _CRED_CACHE.get(cred_key) if cred_key else None
    if not cred_data:
        flash("Missing credential data.", "danger")
        return redirect(url_for("index"))

    if cred_data.get("payment_id") != payment_id:
        flash("Payment ID mismatch.", "danger")
        return redirect(url_for("index"))

    access_token = cred_data.get("access_token")
    if not access_token:
        flash("Missing access token.", "danger")
        return redirect(url_for("index"))

    try:
        result = execute_payment(access_token, payment_id, payer_id)
    except Exception:
        flash("Payment verification failed.", "danger")
        return redirect(url_for("index"))

    if result.get("state") == "approved":
        flash("Payment successful! Thank you.", "success")
    else:
        flash("Payment not approved.", "warning")

    # Clean up session and temporary cache
    for key in ["paypal_state", "cred_key"]:
        session.pop(key, None)
    if cred_key:
        _CRED_CACHE.pop(cred_key, None)

    return redirect(url_for("index"))


if __name__ == "__main__":
    app.run(host="127.0.0.1", port=5000)

import re
import logging
from types import MappingProxyType
from typing import Any, Callable, Dict, Tuple, Optional

logger = logging.getLogger(__name__)

_MAX_ARG_ELEMENTS = 1000
_MAX_ARG_DEPTH = 10

# Internal immutable whitelist
_ALLOWED_FUNCTIONS: Dict[str, Callable] = {}

def register_allowed_function(name: str, func: Callable) -> None:
    """
    Register a function in the internal whitelist after validation.
    """
    if not isinstance(name, str):
        raise TypeError("Function name must be a string.")
    if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", name):
        raise ValueError("Invalid function name format.")
    if not callable(func):
        raise TypeError("Provided object is not callable.")
    dangerous_modules = {"os", "sys", "subprocess", "shutil", "pathlib"}
    if getattr(func, "__module__", None) in dangerous_modules:
        raise ValueError("Functions from dangerous modules cannot be whitelisted.")
    _ALLOWED_FUNCTIONS[name] = func

def _validate_structure(obj: Any) -> None:
    """
    Iteratively validate that the object does not exceed element count
    or nesting depth limits.
    """
    counter = 0
    stack = [(obj, 0)]
    while stack:
        current, depth = stack.pop()
        if depth > _MAX_ARG_DEPTH:
            raise ValueError("Argument nesting depth exceeds allowed limit.")
        if isinstance(current, (list, tuple, set)):
            counter += len(current)
            if counter > _MAX_ARG_ELEMENTS:
                raise ValueError("Total number of argument elements exceeds allowed limit.")
            for item in current:
                stack.append((item, depth + 1))
        elif isinstance(current, dict):
            counter += len(current)
            if counter > _MAX_ARG_ELEMENTS:
                raise ValueError("Total number of argument elements exceeds allowed limit.")
            for k, v in current.items():
                stack.append((k, depth + 1))
                stack.append((v, depth + 1))

def _make_immutable(obj: Any) -> Any:
    """
    Recursively convert built‑in mutable containers to immutable equivalents.
    Raises TypeError for unsupported types.
    """
    if isinstance(obj, (int, float, str, bool, type(None))):
        return obj
    if isinstance(obj, (list, tuple)):
        return tuple(_make_immutable(item) for item in obj)
    if isinstance(obj, set):
        return frozenset(_make_immutable(item) for item in obj)
    if isinstance(obj, dict):
        immut_dict = {
            _make_immutable(k): _make_immutable(v) for k, v in obj.items()
        }
        return MappingProxyType(immut_dict)
    raise TypeError("Unsupported argument type; only built‑in immutable types and containers are allowed.")

def safe_execute_function(
    func_name: str,
    args: Tuple[Any, ...] = (),
    kwargs: Optional[Dict[str, Any]] = None,
) -> Any:
    """
    Execute a whitelisted function with validated and immutable arguments.
    """
    if kwargs is None:
        kwargs = {}

    if not isinstance(func_name, str):
        raise TypeError("Function name must be a string.")
    if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", func_name):
        raise ValueError("Invalid function name format.")
    if func_name not in _ALLOWED_FUNCTIONS:
        raise ValueError("Function not permitted.")

    func = _ALLOWED_FUNCTIONS[func_name]
    if not callable(func):
        raise ValueError("Whitelisted entry must be callable.")

    if not isinstance(args, (list, tuple)):
        raise TypeError("Args must be a list or tuple.")
    if not isinstance(kwargs, dict):
        raise TypeError("Kwargs must be a dict.")

    _validate_structure(args)
    _validate_structure(kwargs)

    safe_args = _make_immutable(args)
    safe_kwargs = _make_immutable(kwargs)

    try:
        result = func(*safe_args, **safe_kwargs)  # type: ignore[arg-type]
    except Exception as exc:
        logger.exception("Error executing function.")
        raise RuntimeError("Function execution failed.") from exc

    return result

def get_authenticated_env(env_vars):
    """
    Validate and sanitize a dictionary of environment variables for authentication.
    Returns a tuple of (sanitized_env_dict, auth_version).

    Supported authentication mechanisms:
    - OpenStack (keys prefixed with OS_)
    - Swift (keys prefixed with ST_)

    Auth version is derived from OS_AUTH_URL when present,
    otherwise defaults to "1.0" for Swift.
    """
    from urllib.parse import urlparse
    import string

    # Limits
    MAX_KEYS = 1000
    MAX_LEN = 4096
    # Allow printable ASCII characters plus space; exclude control chars like \n,\r,\t,\0
    ALLOWED_CHARS = set(string.ascii_letters + string.digits + string.punctuation + " ")

    # Allowed prefixes and required keys per mechanism
    OPENSTACK_PREFIX = "OS_"
    SWIFT_PREFIX = "ST_"
    OPENSTACK_REQUIRED = {"OS_AUTH_URL", "OS_USERNAME", "OS_PASSWORD"}
    SWIFT_REQUIRED = {"ST_AUTH", "ST_USER", "ST_KEY"}

    if not isinstance(env_vars, dict):
        raise TypeError("env_vars must be a dictionary")

    if len(env_vars) > MAX_KEYS:
        raise ValueError(f"Too many environment variables (max {MAX_KEYS})")

    # Sanitize input: ensure strings, strip whitespace, enforce length, and reject control characters
    sanitized = {}
    for key, value in env_vars.items():
        if not isinstance(key, str) or not isinstance(value, str):
            continue
        key = key.strip()
        value = value.strip()
        if not key or not value:
            continue
        if len(key) > MAX_LEN or len(value) > MAX_LEN:
            continue
        if any(ch not in ALLOWED_CHARS for ch in key):
            continue
        if any(ch not in ALLOWED_CHARS for ch in value):
            continue
        sanitized[key] = value

    # Determine mechanism based on prefixes present
    has_openstack = any(k.startswith(OPENSTACK_PREFIX) for k in sanitized)
    has_swift = any(k.startswith(SWIFT_PREFIX) for k in sanitized)

    if has_openstack:
        missing = OPENSTACK_REQUIRED - sanitized.keys()
        if missing:
            raise ValueError(f"Missing required OpenStack keys: {', '.join(sorted(missing))}")

        auth_url = sanitized["OS_AUTH_URL"]
        parsed = urlparse(auth_url)

        # Validate scheme
        if parsed.scheme.lower() not in {"http", "https"} or not parsed.netloc:
            raise ValueError("OS_AUTH_URL must be a valid http or https URL")

        path = parsed.path.lower()
        if "/v3" in path:
            version = "3"
        elif "/v2.0" in path or "/v2" in path:
            version = "2.0"
        else:
            version = "1.0"

        auth_keys = {k: sanitized[k] for k in sanitized if k.startswith(OPENSTACK_PREFIX)}
        return auth_keys, version

    elif has_swift:
        missing = SWIFT_REQUIRED - sanitized.keys()
        if missing:
            raise ValueError(f"Missing required Swift keys: {', '.join(sorted(missing))}")

        version = "1.0"
        auth_keys = {k: sanitized[k] for k in sanitized if k.startswith(SWIFT_PREFIX)}
        return auth_keys, version

    else:
        raise ValueError("No recognized authentication keys found in env_vars")

import logging
import os
import re
import stat
import ipaddress
from pathlib import Path
from typing import Any, Dict, List, Optional

# Configure logger with minimal exposure
logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s %(levelname)s %(message)s",
    handlers=[logging.StreamHandler()],
)
logger = logging.getLogger(__name__)


def _validate_interval(value: Any) -> int:
    if isinstance(value, int) and value > 0:
        return value
    raise ValueError("Task interval must be a positive integer")


def _validate_cli_path(path: Any) -> Path:
    p = Path(path)
    if not p.is_file():
        raise ValueError(f"CLI path does not exist: {p}")
    if p.is_symlink():
        raise PermissionError(f"CLI path must not be a symlink: {p}")
    mode = p.stat().st_mode
    if mode & (stat.S_IWGRP | stat.S_IWOTH):
        raise PermissionError(f"Insecure permissions on CLI path: {p}")
    if not os.access(p, os.X_OK):
        raise PermissionError(f"CLI path is not executable: {p}")
    if not os.access(p, os.R_OK):
        raise PermissionError(f"CLI path is not readable: {p}")
    return p.resolve()


def _validate_ip(address: Any) -> str:
    try:
        ip = ipaddress.ip_address(address)
        return str(ip)
    except ValueError as exc:
        raise ValueError("Invalid IP address") from exc


def _sanitize_alphanum_underscore(value: Any, field_name: str) -> str:
    if not isinstance(value, str):
        raise ValueError(f"{field_name} must be a string")
    if not re.fullmatch(r"[A-Za-z0-9_]+", value):
        raise ValueError(f"{field_name} contains invalid characters")
    return value


def _sanitize_login(login: Any) -> str:
    return _sanitize_alphanum_underscore(login, "Login")


def _sanitize_password(pwd: Any) -> str:
    if not isinstance(pwd, str):
        raise ValueError("Password must be a string")
    if len(pwd) < 12:
        raise ValueError("Password must be at least 12 characters long")
    if re.search(r"\s", pwd):
        raise ValueError("Password must not contain whitespace")
    if not re.search(r"[A-Z]", pwd):
        raise ValueError("Password must contain at least one uppercase letter")
    if not re.search(r"[a-z]", pwd):
        raise ValueError("Password must contain at least one lowercase letter")
    if not re.search(r"\d", pwd):
        raise ValueError("Password must contain at least one digit")
    if not re.search(r"[!@#$%^&*()_+\-=\[\]{};':\"\\|,.<>\/?`~]", pwd):
        raise ValueError("Password must contain at least one special character")
    return pwd


def safe_get(mapping: Dict[str, Any], key: str, default: Optional[Any] = None) -> Any:
    """Securely retrieve a value from a dict without raising KeyError."""
    try:
        return mapping.get(key, default)
    except Exception:
        # Generic catch to avoid leaking internal errors
        return default


class StorageSystem:
    def __init__(self) -> None:
        self._task_interval: Optional[int] = None
        self._cli_path: Optional[Path] = None
        self._ip_address: Optional[str] = None
        self._pool_name: Optional[str] = None
        self._login: Optional[str] = None
        self._password: Optional[str] = None
        self._initiator_auto_register: bool = False
        self._default_timeout: int = 30  # seconds

    def set_task_interval(self, interval: int) -> None:
        self._task_interval = _validate_interval(interval)
        logger.info("Task interval set")

    def configure_cli(self, cli_path: Path, ip_address: str) -> None:
        self._cli_path = _validate_cli_path(cli_path)
        self._ip_address = _validate_ip(ip_address)
        logger.info("CLI configuration set")

    def set_pool(self, pool_name: str) -> None:
        self._pool_name = _sanitize_alphanum_underscore(pool_name, "Pool name")
        logger.info("Pool name set")

    def set_credentials(self, login: str, password: str) -> None:
        self._login = _sanitize_login(login)
        self._password = _sanitize_password(password)
        logger.info("Credentials set")

    def enable_initiator_auto_register(self, enable: bool) -> None:
        self._initiator_auto_register = bool(enable)
        logger.info(
            "Initiator auto‑registration %s",
            "enabled" if self._initiator_auto_register else "disabled",
        )

    def set_default_timeout(self, timeout: int) -> None:
        if not isinstance(timeout, int) or timeout <= 0:
            raise ValueError("Timeout must be a positive integer")
        self._default_timeout = timeout
        logger.info("Default timeout set to %d seconds", timeout)

    def build_naviseccli_command(self, extra_args: Optional[List[str]] = None) -> List[str]:
        if not all([self._cli_path, self._ip_address, self._login, self._password]):
            raise RuntimeError("CLI path, IP, login, or password not configured")
        cmd = [
            str(self._cli_path),
            "-h",
            self._ip_address,
            "-user",
            self._login,
            "-password",
            self._password,
        ]
        if extra_args:
            cmd.extend(extra_args)
        return cmd

    def masked_command_string(self, extra_args: Optional[List[str]] = None) -> str:
        cmd = self.build_naviseccli_command(extra_args)
        # Mask the password for any exposure
        try:
            pwd_index = cmd.index("-password") + 1
            cmd[pwd_index] = "********"
        except ValueError:
            pass
        return " ".join(cmd)


def configure_storage_system(
    task_interval: Any,
    cli_path: Any,
    ip_address: Any,
    pool_name: Any,
    login: Any,
    password: Any,
    initiator_auto_register: Any = False,
    default_timeout: Any = 30,
) -> Dict[str, Any]:
    """
    Configure storage system and return a dictionary with configuration summary.
    All inputs are validated and sanitized.
    """
    storage = StorageSystem()
    try:
        storage.set_task_interval(task_interval)
        storage.configure_cli(cli_path, ip_address)
        storage.set_pool(pool_name)
        storage.set_credentials(login, password)
        storage.enable_initiator_auto_register(initiator_auto_register)
        storage.set_default_timeout(default_timeout)

        test_data = {
            "pool": storage._pool_name,
            "interval": storage._task_interval,
            "auto_register": storage._initiator_auto_register,
            "timeout": storage._default_timeout,
