import json
import logging
import os
from datetime import datetime, timezone
from typing import Any, Dict, List, Optional

import mysql.connector
from mysql.connector import Error as MySQLError, MySQLConnection, cursor

# Constants
MAX_SOLVED_PROBLEMS = 1000
MAX_PROBLEM_RECORDS = 1000
LOG_FILE_PATH = os.getenv("APP_LOG_FILE", "app_user_update.log")

# Configure logger
logger = logging.getLogger(__name__)
if not logger.handlers:
    file_handler = logging.FileHandler(LOG_FILE_PATH)
    formatter = logging.Formatter("%(asctime)s %(levelname)s %(message)s")
    file_handler.setFormatter(formatter)
    logger.addHandler(file_handler)
    logger.setLevel(logging.INFO)


def _validate_int(value: Any, name: str) -> int:
    if isinstance(value, int) and value >= 0:
        return value
    try:
        iv = int(value)
        if iv < 0:
            raise ValueError
        return iv
    except Exception:
        raise ValueError(f"Invalid integer for {name}")


def _validate_str(value: Any, name: str, max_length: Optional[int] = None) -> str:
    if not isinstance(value, str):
        raise ValueError(f"{name} must be a string")
    value = value.strip()
    if max_length and len(value) > max_length:
        raise ValueError(f"{name} exceeds maximum length of {max_length}")
    return value


def _validate_date(value: Any, name: str) -> datetime:
    if isinstance(value, datetime):
        dt = value
    elif isinstance(value, str):
        try:
            dt = datetime.fromisoformat(value)
        except (ValueError, TypeError) as exc:
            raise ValueError(f"Invalid date format for {name}: {exc}") from exc
    else:
        raise ValueError(f"Invalid date format for {name}")

    if dt.tzinfo is None:
        dt = dt.replace(tzinfo=timezone.utc)
    else:
        dt = dt.astimezone(timezone.utc)
    return dt


def _sanitize_user_info(user_info: Dict[str, Any]) -> Dict[str, Any]:
    required_keys = {"user_id", "score", "last_solved"}
    if not required_keys.issubset(user_info.keys()):
        missing = required_keys - user_info.keys()
        raise ValueError(f"Missing required user fields: {missing}")

    sanitized = {
        "user_id": _validate_int(user_info["user_id"], "user_id"),
        "score": _validate_int(user_info["score"], "score"),
        "last_solved": _validate_date(user_info["last_solved"], "last_solved"),
    }

    solved_problems = user_info.get("solved_problems")
    if solved_problems is not None:
        if not isinstance(solved_problems, (list, tuple)):
            raise ValueError("solved_problems must be a list")
        if len(solved_problems) > MAX_SOLVED_PROBLEMS:
            raise ValueError(
                f"Number of solved_problems exceeds maximum of {MAX_SOLVED_PROBLEMS}"
            )
        sanitized["solved_problems"] = [
            _validate_int(p, "solved_problem_id") for p in solved_problems
        ]
    else:
        sanitized["solved_problems"] = []

    return sanitized


def _sanitize_problem_records(records: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    if len(records) > MAX_PROBLEM_RECORDS:
        raise ValueError(
            f"Number of problem records exceeds maximum of {MAX_PROBLEM_RECORDS}"
        )
    sanitized = []
    for rec in records:
        if not {"problem_id", "solved_date"}.issubset(rec.keys()):
            raise ValueError("Each problem record must contain problem_id and solved_date")
        sanitized.append(
            {
                "problem_id": _validate_int(rec["problem_id"], "problem_id"),
                "solved_date": _validate_date(rec["solved_date"], "solved_date"),
            }
        )
    return sanitized


def update_user_and_problems(
    conn: MySQLConnection,
    user_info: Dict[str, Any],
    problem_records: List[Dict[str, Any]],
) -> None:
    """
    Update user summary and per‑problem statistics in a MySQL database.
    """
    cursor_obj: Optional[cursor.MySQLCursor] = None
    try:
        user = _sanitize_user_info(user_info)
        problems = _sanitize_problem_records(problem_records)

        cursor_obj = conn.cursor(prepared=True)

        update_user_sql = """
            UPDATE users
            SET score = %s,
                last_solved = %s,
                solved_problems = %s
            WHERE user_id = %s
        """
        solved_problems_json = json.dumps(user["solved_problems"])
        cursor_obj.execute(
            update_user_sql,
            (
                user["score"],
                user["last_solved"].strftime("%Y-%m-%d %H:%M:%S"),
                solved_problems_json,
                user["user_id"],
            ),
        )

        update_problem_sql = """
            INSERT INTO problem_stats (problem_id, solve_count, last_solved)
            VALUES (%s, 1, %s)
            ON DUPLICATE KEY UPDATE
                solve_count = solve_count + 1,
                last_solved = GREATEST(last_solved, VALUES(last_solved))
        """
        problem_params = [
            (
                p["problem_id"],
                p["solved_date"].strftime("%Y-%m-%d %H:%M:%S"),
            )
            for p in problems
        ]
        cursor_obj.executemany(update_problem_sql, problem_params)

        conn.commit()
        logger.info(
            "User %s and %d problem records updated successfully.",
            user["user_id"],
            len(problems),
        )

    except (ValueError, MySQLError) as exc:
        conn.rollback()
        logger.error("Failed to update database.")
        if logger.isEnabledFor(logging.DEBUG):
            logger.debug("Database update error: %s", exc)
        raise
    finally:
        if cursor_obj is not None:
            try:
                cursor_obj.close()
            except MySQLError as exc:
                logger.warning("Error closing cursor: %s", exc)

import re
import hashlib
import os
import hmac
from typing import Dict

# Configuration
USERNAME_PATTERN = re.compile(r"^[A-Za-z0-9_]{3,30}$")
MIN_PASSWORD_LENGTH = 8
MAX_PASSWORD_LENGTH = 128
SALT_SIZE = 16
HASH_ITERATIONS = 200_000
HASH_ALGORITHM = "sha256"
HASH_FORMAT = "pbkdf2_sha256"

# Load pepper; fail fast if not set
_PEPPER_ENV = os.getenv("PASSWORD_PEPPER")
if not _PEPPER_ENV:
    raise RuntimeError("Environment variable PASSWORD_PEPPER must be set")
PEPPER = _PEPPER_ENV.encode("utf-8")


class RegistrationError(Exception):
    """Raised when registration fails due to policy violation or conflicts."""


def _validate_username(username: str) -> str:
    if not isinstance(username, str):
        raise RegistrationError("Invalid username format.")
    username = username.strip()
    if not USERNAME_PATTERN.fullmatch(username):
        raise RegistrationError(
            "Username must be 3-30 alphanumeric characters or underscores."
        )
    return username


def _validate_password(password: str) -> str:
    if not isinstance(password, str):
        raise RegistrationError("Invalid password format.")
    if len(password) < MIN_PASSWORD_LENGTH:
        raise RegistrationError(
            f"Password must be at least {MIN_PASSWORD_LENGTH} characters long."
        )
    if len(password) > MAX_PASSWORD_LENGTH:
        raise RegistrationError(
            f"Password must be no more than {MAX_PASSWORD_LENGTH} characters long."
        )
    if not re.search(r"[A-Z]", password):
        raise RegistrationError("Password must contain at least one uppercase letter.")
    if not re.search(r"[a-z]", password):
        raise RegistrationError("Password must contain at least one lowercase letter.")
    if not re.search(r"\d", password):
        raise RegistrationError("Password must contain at least one digit.")
    if not re.search(r"[!@#$%^&*(),.?\":{}|<>\\[\\]\\/`~;'\-+=_]", password):
        raise RegistrationError(
            "Password must contain at least one special character."
        )
    return password


def _derive_peppered_password(password: str) -> bytes:
    """
    Derive a pepper‑mixed password using HMAC with the global pepper as key.
    This avoids simple concatenation and integrates the pepper securely.
    """
    return hmac.new(PEPPER, password.encode("utf-8"), hashlib.sha256).digest()


def _hash_password(password: str, salt: bytes = None) -> str:
    if salt is None:
        salt = os.urandom(SALT_SIZE)
    pwd_derived = _derive_peppered_password(password)
    pwd_hash = hashlib.pbkdf2_hmac(
        HASH_ALGORITHM, pwd_derived, salt, HASH_ITERATIONS
    )
    return f"{HASH_FORMAT}${HASH_ITERATIONS}${salt.hex()}${pwd_hash.hex()}"


def _is_username_taken(username: str, store: Dict[str, str]) -> bool:
    return username in store


def register_user(username: str, password: str, user_store: Dict[str, str]) -> str:
    """
    Registers a new user if the username is not already taken.
    Performs password hashing before the username existence check to mitigate timing attacks.
    """
    try:
        clean_username = _validate_username(username)
        clean_password = _validate_password(password)
    except RegistrationError:
        raise RegistrationError("Registration failed.") from None

    # Compute hash irrespective of username availability
    stored_value = _hash_password(clean_password)

    if _is_username_taken(clean_username, user_store):
        # Discard the computed hash and fail
        raise RegistrationError("Registration failed.") from None

    user_store[clean_username] = stored_value
    return "User registered successfully."


def verify_password(stored: str, provided_password: str) -> bool:
    """
    Verify a provided password against the stored hash using constant‑time comparison.
    """
    try:
        algorithm, iterations_str, salt_hex, hash_hex = stored.split("$")
        if algorithm != HASH_FORMAT:
            return False
        iterations = int(iterations_str)
        if iterations <= 0:
            return False
        salt = bytes.fromhex(salt_hex)
        expected_hash = bytes.fromhex(hash_hex)
    except Exception:
        return False

    pwd_derived = _derive_peppered_password(provided_password)
    derived_hash = hashlib.pbkdf2_hmac(
        HASH_ALGORITHM, pwd_derived, salt, iterations
    )
    return hmac.compare_digest(derived_hash, expected_hash)


def test_duplicate_username():
    user_store: Dict[str, str] = {}
    result = register_user("test_user", "StrongPass!23", user_store)
    if result != "User registered successfully.":
        raise AssertionError("First registration failed.")
    try:
        register_user("test_user", "AnotherPass!45", user_store)
    except RegistrationError:
        pass
    else:
        raise AssertionError("Duplicate username did not raise RegistrationError.")


if __name__ == "__main__":
    test_duplicate_username()
    print("All tests passed.")

