import sys
import os
import re
import logging
import argparse
import socket
import ipaddress
from urllib.parse import urlparse

import scrapy
from scrapy.crawler import CrawlerProcess
from scrapy.exceptions import CloseSpider


SAFE_OUTPUT_DIR = os.path.abspath("output")


def is_private_ip(ip_str: str) -> bool:
    try:
        ip = ipaddress.ip_address(ip_str)
        return ip.is_private or ip.is_loopback or ip.is_link_local
    except ValueError:
        return True  # Treat unparsable addresses as unsafe


def is_valid_url(url: str) -> bool:
    """
    Validate URL scheme, netloc and ensure target resolves to a public IP.
    """
    try:
        parsed = urlparse(url)
        if parsed.scheme not in ("http", "https") or not parsed.netloc:
            return False

        hostname = parsed.hostname
        if not hostname:
            return False

        # Resolve hostname and check all returned IPs
        for family, _, _, _, sockaddr in socket.getaddrinfo(hostname, None):
            ip_str = sockaddr[0]
            if is_private_ip(ip_str):
                return False
        return True
    except Exception:
        return False


def sanitize_filename(name: str) -> str:
    """
    Remove path traversal and disallowed characters from filename.
    Keep only alphanumerics, dash, underscore and dot.
    """
    base = os.path.basename(name)
    safe = re.sub(r"[^A-Za-z0-9._-]", "_", base)
    return safe


def ensure_output_directory(path: str) -> None:
    """
    Create the base output directory if it does not exist.
    Do not follow symlinks.
    """
    if os.path.islink(path):
        raise RuntimeError(f"Output directory path {path} is a symlink.")
    os.makedirs(path, mode=0o750, exist_ok=True)


class GenericSpider(scrapy.Spider):
    name = "generic"

    def __init__(self, start_url: str, **kwargs):
        super().__init__(**kwargs)
        self.start_urls = [start_url]

    def parse(self, response):
        title = response.xpath("//title/text()").get(default="").strip()
        yield {"url": response.url, "title": title}


def main():
    parser = argparse.ArgumentParser(description="Scrape a page and save to CSV")
    parser.add_argument("url", help="Target URL to scrape")
    parser.add_argument("output", help="CSV output file name")
    args = parser.parse_args()

    if not is_valid_url(args.url):
        print("Error: Invalid or unsafe URL provided.", file=sys.stderr)
        sys.exit(1)

    # Prepare safe output path
    output_name = sanitize_filename(args.output)
    if not output_name or os.sep in output_name:
        print("Error: Invalid output file name.", file=sys.stderr)
        sys.exit(1)

    try:
        ensure_output_directory(SAFE_OUTPUT_DIR)
    except Exception as e:
        print(f"Error ensuring output directory: {e}", file=sys.stderr)
        sys.exit(1)

    output_path = os.path.abspath(os.path.join(SAFE_OUTPUT_DIR, output_name))

    # Verify the final path resides within the safe directory
    if os.path.commonpath([SAFE_OUTPUT_DIR, output_path]) != SAFE_OUTPUT_DIR:
        print("Error: Output path resolves outside the allowed directory.", file=sys.stderr)
        sys.exit(1)

    # Remove existing file securely (reject symlinks)
    try:
        if os.path.lexists(output_path):
            if os.path.islink(output_path):
                raise RuntimeError("Existing file is a symlink, aborting.")
            os.remove(output_path)
    except Exception as e:
        print(f"Error handling existing output file: {e}", file=sys.stderr)
        sys.exit(1)

    # Atomically create the file to avoid TOCTOU race
    try:
        fd = os.open(output_path, os.O_WRONLY | os.O_CREAT | os.O_EXCL, 0o600)
        os.close(fd)
    except FileExistsError:
        # Very unlikely due to removal above, but handle gracefully
        pass
    except Exception as e:
        print(f"Error creating output file: {e}", file=sys.stderr)
        sys.exit(1)

    # Scrapy settings with explicit TLS verification
    settings = {
        "LOG_LEVEL": "INFO",
        "FEEDS": {
            output_path: {
                "format": "csv",
                "encoding": "utf8",
                "overwrite": True,
            }
        },
        "ROBOTSTXT_OBEY": True,
        "DOWNLOAD_TIMEOUT": 30,
        "RETRY_ENABLED": True,
        "RETRY_TIMES": 2,
        "TLS_VERIFY": True,
        "DOWNLOAD_FAIL_ON_DATALOSS": True,
    }

    process = CrawlerProcess(settings=settings)

    try:
        process.crawl(GenericSpider, start_url=args.url)
        process.start()
    except Exception as e:
        logging.error("Scraping failed: %s", e)
        sys.exit(1)


if __name__ == "__main__":
    main()

