        ctx = ssl.create_default_context()
        ctx.check_hostname = True
        ctx.verify_mode = ssl.CERT_REQUIRED
        self.poolmanager = urllib3.poolmanager.PoolManager(
            num_pools=connections,
            maxsize=maxsize,
            block=block,
            ssl_context=ctx,
            **pool_kwargs,
        )

    def cert_verify(self, conn, url, verify, cert):
        super().cert_verify(conn, url, verify, cert)
        der_cert = conn.sock.getpeercert(binary_form=True)
        sha256 = hashlib.sha256(der_cert).hexdigest()
        if sha256 != self.expected_fingerprint:
            raise requests.exceptions.SSLError(
                "Server certificate fingerprint does not match the pinned fingerprint."
            )


def load_config():
    cfg = configparser.ConfigParser()
    if CONFIG_PATH.is_file():
        try:
            cfg.read(CONFIG_PATH, encoding="utf-8")
        except Exception:
            logging.error("Failed to read configuration file.")
            return {}
    return cfg


def validate_username(username: str) -> bool:
    return bool(USERNAME_PATTERN.fullmatch(username))


def validate_password(password: str) -> bool:
    """Enforce minimum length and complexity."""
    return bool(PASSWORD_PATTERN.fullmatch(password))


def prompt_credentials():
    while True:
        username = input("Enter username: ").strip()
        if not validate_username(username):
            logging.warning(
                "Invalid username format. Allowed: letters, numbers, . _ - (3-30 chars)."
            )
            continue
        password = getpass.getpass("Enter password: ").strip()
        if not password:
            logging.warning("Password cannot be empty.")
            continue
        if not validate_password(password):
            logging.warning(
                "Password must be at least 8 characters long and include uppercase, "
                "lowercase, digits, and special characters."
            )
            continue
        return username, password


def save_credentials(cfg, username, password):
    if "credentials" not in cfg:
        cfg["credentials"] = {}
    cfg["credentials"]["username"] = username
    try:
        with CONFIG_PATH.open("w", encoding="utf-8") as f:
            cfg.write(f)
        os.chmod(CONFIG_PATH, 0o600)
        keyring.set_password(KEYRING_SERVICE, username, password)
    except Exception as e:
        logging.error(f"Unable to store credentials: {e}")
        sys.exit(1)


def retrieve_stored_password(username: str) -> str | None:
    try:
        return keyring.get_password(KEYRING_SERVICE, username)
    except Exception as e:
        logging.warning(f"Could not retrieve password from keyring: {e}")
        return None


def get_api_secrets():
    api_key = os.getenv("API_KEY")
    api_secret = os.getenv("API_SECRET")
    if not api_key or not api_secret:
        logging.error("Missing API_KEY or API_SECRET environment variables.")
        sys.exit(1)
    # Remove secrets from environment as soon as possible
    for var in ("API_KEY", "API_SECRET"):
        try:
            del os.environ[var]
        except KeyError:
            pass
    return api_key, api_secret


def create_session():
    session = requests.Session()
    if EXPECTED_CERT_FINGERPRINT:
        adapter = SSLPinningAdapter(EXPECTED_CERT_FINGERPRINT)
        session.mount("https://api.example.com/", adapter)
    return session


def authenticate(username, password, api_key, api_secret):
    payload = {
        "username": username,
        "password": password,
        "api_key": api_key,
        "api_secret": api_secret,
    }
    session = create_session()
    try:
        response = session.post(
            API_ENDPOINT,
            json=payload,
            timeout=REQUEST_TIMEOUT,
            verify=True,
        )
        if response.status_code == 200:
            return True
        logging.info(f"Authentication failed: HTTP {response.status_code}")
        return False
    except requests.RequestException as e:
        logging.error(f"Network error during authentication: {e}")
        return False


def main():
    cfg = load_config()
    username = None
    password = None

    if cfg.has_section("credentials"):
        stored_user = cfg.get("credentials", "username", fallback="").strip()
        if stored_user and validate_username(stored_user):
            stored_pass = retrieve_stored_password(stored_user)
            if stored_pass:
                username = stored_user
                password = stored_pass

    if not username or not password:
        username, password = prompt_credentials()
        save_credentials(cfg, username, password)

    api_key, api_secret = get_api_secrets()
    success = authenticate(username, password, api_key, api_secret)
    if success:
        print("Authentication successful.")
    else:
        print("Authentication failed.")


if __name__ == "__main__":
    main()

import os
import re
from pathlib import Path

class MetadataError(Exception):
    """Generic error for metadata extraction without leaking sensitive details."""
    pass

# Define a safe base directory for metadata files
_ALLOWED_BASE = Path("/var/app/metadata").resolve(strict=False)

def _is_within_allowed_base(path: Path) -> bool:
    try:
        path.relative_to(_ALLOWED_BASE)
        return True
    except ValueError:
        return False

def load_metadata(file_path: str, dict_name: str) -> dict:
    """
    Reads a text file under a trusted base directory, extracts a version
    number from a line that starts with 'Version:', and returns a metadata
    dictionary containing the provided dict_name and the extracted version.
    """
    # --- Input validation -------------------------------------------------
    if not isinstance(file_path, str) or not isinstance(dict_name, str):
        raise MetadataError("Invalid input.")

    if "\x00" in file_path or "\x00" in dict_name:
        raise MetadataError("Prohibited characters in input.")

    if not re.fullmatch(r"[\w\-]+", dict_name):
        raise MetadataError("Invalid dictionary name format.")

    # Resolve path safely
    try:
        path = Path(file_path).expanduser().resolve(strict=True)
    except (OSError, RuntimeError):
        raise MetadataError("Unable to resolve file path.")

    if not _is_within_allowed_base(path):
        raise MetadataError("File location not permitted.")

    # Verify it's a regular file without following symlinks (TOCTOU safe)
    try:
        fd = os.open(path, os.O_RDONLY | os.O_NOFOLLOW)
    except OSError:
        raise MetadataError("Unable to open file securely.")

    try:
        stat = os.fstat(fd)
        if not Path(fd).is_file():
            raise MetadataError("Specified path is not a regular file.")
        max_size = 5 * 1024 * 1024  # 5 MiB
        if stat.st_size > max_size:
            raise MetadataError("File size exceeds allowed limit.")
        # Read and parse version line with bounded line length
        version_pattern = re.compile(r"^Version:\s*([0-9]+(?:\.[0-9]+)*)\s*$", re.IGNORECASE)
        version = None
        max_line_len = 4096
        with os.fdopen(fd, "r", encoding="utf-8", errors="replace") as f:
            for line in f:
                if len(line) > max_line_len:
                    continue
                match = version_pattern.match(line.strip())
                if match:
                    version = match.group(1)
                    break
        if version is None:
            raise MetadataError("Version information not found.")
    finally:
        # Ensure file descriptor is closed in case of early exit
        try:
            os.close(fd)
        except OSError:
            pass

    return {"name": dict_name, "version": version}

