import os
import hashlib
from pathlib import Path
from typing import Optional, Union

# Allowed strong hash algorithms
_STRONG_HASHES = {"sha256", "sha384", "sha512"}

def _is_relative_to(path: Path, base: Path) -> bool:
    """Compatibility for Path.is_relative_to on Python < 3.9."""
    try:
        return path.is_relative_to(base)  # type: ignore[attr-defined]
    except AttributeError:
        try:
            path.relative_to(base)
            return True
        except ValueError:
            return False

def compute_file_hash(
    file_path: str,
    algorithm: str = "sha256",
    allowed_root: Optional[Union[str, Path]] = None,
) -> Optional[str]:
    """
    Compute the hexadecimal digest of a file using a strong hash algorithm.
    Returns None if the file cannot be read, inputs are invalid, or security checks fail.
    """
    # Validate inputs
    if not isinstance(file_path, str):
        return None
    if algorithm not in _STRONG_HASHES:
        return None

    # Resolve the target path
    try:
        path = Path(file_path).expanduser().resolve(strict=False)
    except Exception:
        return None

    # Optional directory whitelist check
    if allowed_root is not None:
        root = Path(allowed_root).expanduser().resolve(strict=False)
        if not _is_relative_to(path, root):
            return None

    # Ensure the path points to a regular file (symlinks will be rejected by O_NOFOLLOW)
    if not path.is_file():
        return None

    # Prepare hash object
    try:
        hash_obj = hashlib.new(algorithm)
    except Exception:
        return None

    # Open the file atomically, preventing symlink following
    flags = os.O_RDONLY
    if hasattr(os, "O_NOFOLLOW"):
        flags |= os.O_NOFOLLOW

    try:
        fd = os.open(str(path), flags)
        with os.fdopen(fd, "rb") as f:
            for chunk in iter(lambda: f.read(8192), b""):
                hash_obj.update(chunk)
        return hash_obj.hexdigest()
    except (FileNotFoundError, PermissionError, OSError):
        return None

