CREATE OR REPLACE FUNCTION public.manage_row_triggers(
    p_schema TEXT,
    p_table TEXT,
    p_select_sql TEXT,
    p_trigger_prefix TEXT
) RETURNS VOID
LANGUAGE plpgsql
AS $$
DECLARE
    v_rec RECORD;
    v_trigger_name TEXT;
    v_function_name TEXT;
    v_exists BOOLEAN;
    v_lang_oid OID;
BEGIN
    -- Validate identifiers
    IF NOT p_schema ~ '^[a-zA-Z_][a-zA-Z0-9_]*$' THEN
        RAISE EXCEPTION 'Invalid schema name';
    END IF;
    IF NOT p_table ~ '^[a-zA-Z_][a-zA-Z0-9_]*$' THEN
        RAISE EXCEPTION 'Invalid table name';
    END IF;
    IF NOT p_trigger_prefix ~ '^[a-zA-Z_][a-zA-Z0-9_]*$' THEN
        RAISE EXCEPTION 'Invalid trigger prefix';
    END IF;

    -- Basic validation of supplied SELECT
    IF NOT p_select_sql ~* '^\s*SELECT\b' THEN
        RAISE EXCEPTION 'p_select_sql must be a SELECT statement';
    END IF;
    IF p_select_sql ~ ';' THEN
        RAISE EXCEPTION 'p_select_sql must not contain multiple statements';
    END IF;

    -- Ensure plpgsql language exists
    SELECT oid INTO v_lang_oid FROM pg_language WHERE lanname = 'plpgsql';
    IF NOT FOUND THEN
        BEGIN
            EXECUTE 'CREATE LANGUAGE plpgsql';
        EXCEPTION
            WHEN OTHERS THEN
                RAISE EXCEPTION 'Failed to create required language: %', SQLERRM;
        END;
    END IF;

    FOR v_rec IN EXECUTE p_select_sql LOOP
        -- Expect columns trigger_suffix and trigger_body
        IF v_rec.trigger_suffix IS NULL OR v_rec.trigger_body IS NULL THEN
            RAISE EXCEPTION 'SELECT must return non‑null columns "trigger_suffix" and "trigger_body"';
        END IF;

        v_trigger_name := p_trigger_prefix || '_' || v_rec.trigger_suffix;
        v_function_name := v_trigger_name || '_fn';

        IF NOT v_trigger_name ~ '^[a-zA-Z_][a-zA-Z0-9_]*$' THEN
            RAISE EXCEPTION 'Generated trigger name is invalid';
        END IF;
        IF NOT v_function_name ~ '^[a-zA-Z_][a-zA-Z0-9_]*$' THEN
            RAISE EXCEPTION 'Generated function name is invalid';
        END IF;

        -- Validate trigger body against prohibited keywords
        IF v_rec.trigger_body ~* '(EXECUTE|PERFORM|RAISE|DROP|CREATE|ALTER|CALL|dblink|;)' THEN
            RAISE EXCEPTION 'Trigger body contains prohibited keywords';
        END IF;

        -- Drop existing trigger
        EXECUTE format('DROP TRIGGER IF EXISTS %I ON %I.%I',
                       v_trigger_name, p_schema, p_table);

        -- Drop existing zero‑argument function if it exists
        EXECUTE format(
            'SELECT EXISTS (
                SELECT 1 FROM pg_proc p
                JOIN pg_namespace n ON n.oid = p.pronamespace
                WHERE p.proname = %L AND n.nspname = %L AND p.pronargs = 0
            )',
            v_function_name, p_schema
        ) INTO v_exists;

        IF v_exists THEN
            EXECUTE format('DROP FUNCTION IF EXISTS %I.%I()',
                           p_schema, v_function_name);
        END IF;

        -- Create trigger function
        EXECUTE format(
            $func$
            CREATE FUNCTION %I.%I()
            RETURNS trigger
            LANGUAGE plpgsql
            AS $inner$
            BEGIN
                %s
                RETURN NEW;
            END;
            $inner$
            $func$,
            p_schema,
            v_function_name,
            v_rec.trigger_body
        );

        -- Create the trigger
        EXECUTE format(
            'CREATE TRIGGER %I BEFORE INSERT OR UPDATE ON %I.%I FOR EACH ROW EXECUTE FUNCTION %I.%I()',
            v_trigger_name,
            p_schema,
            p_table,
            p_schema,
            v_function_name
        );
    END LOOP;
EXCEPTION
    WHEN OTHERS THEN
        RAISE NOTICE 'manage_row_triggers error: %', SQLERRM;
        RAISE EXCEPTION 'Error managing triggers';
END;
$$;

