import re
import logging

MAX_CONTENT_SIZE = 10 * 1024 * 1024  # 10 MiB
MAX_HEADER_NAME_LENGTH = 256
MAX_HEADER_VALUE_LENGTH = 1024
_HEADER_NAME_PATTERN = re.compile(r"^[A-Za-z0-9-]+$")
_CONTROL_CHAR_PATTERN = re.compile(r"[\x00-\x1F\x7F]")  # all ASCII control chars


def _is_safe_header_name(name: str) -> bool:
    if not isinstance(name, str):
        return False
    if len(name) > MAX_HEADER_NAME_LENGTH:
        return False
    return bool(_HEADER_NAME_PATTERN.fullmatch(name))


def _is_safe_header_value(value: str) -> bool:
    if not isinstance(value, str):
        return False
    if len(value) > MAX_HEADER_VALUE_LENGTH:
        return False
    return not bool(_CONTROL_CHAR_PATTERN.search(value))


def _is_safe_etag(etag: str) -> bool:
    if not isinstance(etag, str):
        return False
    if len(etag) > MAX_HEADER_VALUE_LENGTH:
        return False
    return not bool(_CONTROL_CHAR_PATTERN.search(etag))


def _is_valid_status_code(code: int) -> bool:
    return isinstance(code, int) and 100 <= code <= 599


def handle_get(request, write_func):
    """
    Securely handles a GET request with ETag support.

    Parameters
    ----------
    request : object
        Must provide:
            - method (str)
            - headers (mapping of str -> str)
            - set_status(code: int)
            - add_header(name: str, value: str)
            - output (binary writable stream)
    write_func : callable
        Called with no arguments and must return a dict containing:
            - "etag" (str): the response ETag
            - "content" (bytes): response payload
            - "headers" (dict, optional): additional headers to send
    """
    try:
        # Validate request method
        if not hasattr(request, "method") or request.method != "GET":
            raise ValueError("Invalid request object or method not GET")

        # Safely retrieve request headers (ensure strings) and detect duplicates
        request_headers = {}
        seen_header_names = set()
        for raw_name, raw_value in getattr(request, "headers", {}).items():
            if not isinstance(raw_name, str) or not isinstance(raw_value, str):
                continue
            name = raw_name.strip().lower()
            if name in seen_header_names:
                raise ValueError(f"Duplicate header detected: {raw_name}")
            seen_header_names.add(name)
            request_headers[name] = raw_value.strip()
        request_etag = request_headers.get("if-none-match")

        # Obtain response data without sending it yet
        if not callable(write_func):
            raise ValueError("write_func must be callable")
        response = write_func()
        if not isinstance(response, dict):
            raise ValueError("write_func must return a dict")

        resp_etag = response.get("etag")
        if not _is_safe_etag(resp_etag):
            raise ValueError("Response ETag contains unsafe characters")
        content = response.get("content", b"")
        if not isinstance(content, (bytes, bytearray)):
            raise ValueError("Response content must be bytes")
        if len(content) > MAX_CONTENT_SIZE:
            raise ValueError("Response content exceeds maximum allowed size")
        extra_headers = response.get("headers", {})
        if not isinstance(extra_headers, dict):
            raise ValueError("Response headers must be a dict")

        # Helper to add a header after validation
        def _add_validated_header(name: str, value: str):
            if not (_is_safe_header_name(name) and _is_safe_header_value(value)):
                raise ValueError(f"Unsafe header detected: {name}")
            request.add_header(name, value)

        # Helper to set status after validation
        def _set_status(code: int):
            if not _is_valid_status_code(code):
                raise ValueError(f"Invalid HTTP status code: {code}")
            request.set_status(code)

        # If ETag matches, send 304 Not Modified
        if request_etag is not None and request_etag == resp_etag:
            _set_status(304)
            _add_validated_header("ETag", resp_etag)
            _add_validated_header("Content-Length", "0")
            for raw_name, raw_value in extra_headers.items():
                if isinstance(raw_name, str) and isinstance(raw_value, str):
                    _add_validated_header(raw_name.strip(), raw_value.strip())
            return

        # Otherwise, send full content with 200 OK
        _set_status(200)
        _add_validated_header("ETag", resp_etag)

        for raw_name, raw_value in extra_headers.items():
            if isinstance(raw_name, str) and isinstance(raw_value, str):
                _add_validated_header(raw_name.strip(), raw_value.strip())

        # Ensure Content-Length header exists
        normalized_extra = {n.lower() for n in extra_headers if isinstance(n, str)}
        if "content-length" not in normalized_extra:
            _add_validated_header("Content-Length", str(len(content)))

        # Write content safely
        output_stream = getattr(request, "output", None)
        if not hasattr(output_stream, "write"):
            raise ValueError("Request output stream is not writable")
        output_stream.write(content)
        output_stream.flush()

    except Exception as exc:
