import os
import re
import logging
import subprocess
from typing import Optional
from email.utils import parseaddr
from email.message import EmailMessage

# Configure a minimal logger
logging.basicConfig(level=logging.INFO)
_logger = logging.getLogger(__name__)

# Strict email validation regex
_EMAIL_STRICT_REGEX = re.compile(r"^[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}$")

def _is_valid_email(address: str) -> bool:
    """Validate an email address using strict rules."""
    if not isinstance(address, str):
        return False
    name, addr = parseaddr(address)
    if not addr:
        return False
    # Disallow commas, whitespace, control characters in the address
    if any(c.isspace() or ord(c) < 32 for c in addr):
        return False
    return bool(_EMAIL_STRICT_REGEX.fullmatch(addr))

def _sanitize_header_field(text: str) -> str:
    """Sanitize values that will be placed in email headers."""
    if not isinstance(text, str):
        raise ValueError("Input must be a string")
    # Strip surrounding whitespace
    cleaned = text.strip()
    # Reject CR or LF characters to prevent header injection
    if "\r" in cleaned or "\n" in cleaned:
        raise ValueError("Header fields must not contain CR or LF characters")
    # Allow only printable ASCII characters (32‑126)
    if not all(32 <= ord(ch) <= 126 for ch in cleaned):
        raise ValueError("Header fields contain invalid characters")
    return cleaned

def _sanitize_body(text: str) -> str:
    """Sanitize email body text; allow printable chars and common whitespace."""
    if not isinstance(text, str):
        raise ValueError("Input must be a string")
    allowed = set(chr(i) for i in range(32, 127)) | {"\t", "\r", "\n"}
    return "".join(ch for ch in text if ch in allowed)

def _send_via_django(subject: str, message: str, sender: str, recipient: str) -> None:
    try:
        from django.core.mail import EmailMessage as DjangoEmailMessage
        from django.conf import settings
        if not getattr(settings, "EMAIL_BACKEND", None):
            raise RuntimeError("Django email backend not configured")
        email = DjangoEmailMessage(
            subject=subject,
            body=message,
            from_email=sender,
            to=[recipient],
        )
        email.send(fail_silently=False)
    except Exception as exc:
        _logger.error("Failed to send email via Django: %s", exc)
        raise

def _send_via_cli(subject: str, body: str, sender: str, recipient: str) -> None:
    """Send email using the system's sendmail command with a safely built message."""
    sendmail_path = "/usr/sbin/sendmail"
    if not os.path.isfile(sendmail_path) or not os.access(sendmail_path, os.X_OK):
        raise RuntimeError("sendmail command not available")
    # Build the email using the standard library to avoid manual header injection
    msg = EmailMessage()
    msg["Subject"] = subject
    msg["From"] = sender
    msg["To"] = recipient
    msg.set_content(body)
    raw_message = msg.as_bytes()
    try:
        proc = subprocess.run(
            [sendmail_path, "-f", sender, recipient],
            input=raw_message,
            capture_output=True,
            check=True,
        )
        if proc.stdout:
            _logger.debug("sendmail output: %s", proc.stdout.decode())
    except subprocess.CalledProcessError as exc:
        _logger.error("sendmail failed with code %s", exc.returncode)
        raise

def send_email(subject: str, message: str, sender: str, recipient: str) -> None:
    """
    Send an email using Django if available, otherwise fallback to the system sendmail command.
    Verbosity is logged at DEBUG level when VERBOSITY env var >= 2.
    """
    # Validate input types
    for name, value in (("subject", subject), ("message", message), ("sender", sender), ("recipient", recipient)):
        if not isinstance(value, str):
            raise TypeError(f"{name} must be a string")

    # Validate email addresses
    if not _is_valid_email(sender):
        raise ValueError("Invalid sender email address")
    if not _is_valid_email(recipient):
        raise ValueError("Invalid recipient email address")

    # Sanitize fields
    subject_clean = _sanitize_header_field(subject)
    sender_clean = _sanitize_header_field(sender)
    recipient_clean = _sanitize_header_field(recipient)
    body_clean = _sanitize_body(message)

    # Verbosity handling via logger
    try:
        verbosity = int(os.getenv("VERBOSITY", "0"))
    except ValueError:
        verbosity = 0
    if verbosity >= 2:
        _logger.debug("Recipient: %s\nSubject: %s\nSender: %s", recipient_clean, subject_clean, sender_clean)

    # Try Django first
    sent = False
    try:
        _send_via_django(subject_clean, body_clean, sender_clean, recipient_clean)
        sent = True
    except Exception:
        _logger.info("Django mail not usable, falling back to CLI method.")

    if not sent:
        try:
            _send_via_cli(subject_clean, body_clean, sender_clean, recipient_clean)
        except Exception as exc:
            _logger.error("Unable to send email: %s", exc)
            raise RuntimeError("Email delivery failed") from None

import argparse
import json
import os
import pathlib
import sys
import crypt
import getpass
import re
from typing import Dict

class KickstartModificationError(Exception):
    """Raised when modification of the kickstart file fails."""


def _secure_path(path_str: str) -> pathlib.Path:
    """Validate and resolve a file system path, rejecting symlinks."""
    p = pathlib.Path(path_str).expanduser()
    try:
        st = p.lstat()
    except OSError as e:
        raise KickstartModificationError(f"Unable to access path: {e}")
    if st.st_mode & 0o120000:  # S_IFLNK
        raise KickstartModificationError(f"Symlink paths are not allowed: {p}")
    resolved = p.resolve()
    if not resolved.is_file():
        raise KickstartModificationError(f"Path does not exist or is not a file: {resolved}")
    return resolved


def _validate_params(params: Dict) -> Dict[str, str]:
    """Ensure parameters are a mapping of safe strings to safe strings."""
    if not isinstance(params, dict):
        raise KickstartModificationError("Parameters must be a dictionary.")
    clean: Dict[str, str] = {}
    placeholder_pat = re.compile(r"^[A-Z0-9_]+$")
    for k, v in params.items():
        if not isinstance(k, str) or not isinstance(v, str):
            raise KickstartModificationError("All parameter keys and values must be strings.")
        if not placeholder_pat.fullmatch(k):
            raise KickstartModificationError(f"Invalid placeholder name: {k}")
        if ("\n" in v) or ("\r" in v) or ("%" in v):
            raise KickstartModificationError(f"Disallowed characters in value for {k}")
        clean[k] = v
    return clean


def _check_output_dir_permissions(output_path: pathlib.Path) -> None:
    """Ensure the output directory is owned by the current user and not world‑writable."""
    parent = output_path.parent
    try:
        st = parent.stat()
    except OSError as e:
        raise KickstartModificationError(f"Cannot stat output directory: {e}")
    if st.st_uid != os.getuid():
        raise KickstartModificationError(f"Output directory {parent} is not owned by the current user.")
    if st.st_mode & 0o022:
        raise KickstartModificationError(f"Output directory {parent} is writable by group or others.")


def _read_template(path: pathlib.Path) -> str:
    """Read the kickstart template file as text."""
    try:
        return path.read_text(encoding="utf-8")
    except Exception as e:
        raise KickstartModificationError(f"Failed to read template file: {e}")


def _write_output(content: str, output_path: pathlib.Path) -> None:
    """Atomically write content to a new file with strict permissions."""
    flags = os.O_WRONLY | os.O_CREAT | os.O_EXCL | getattr(os, "O_NOFOLLOW", 0)
    mode = 0o600  # rw------- for the owner
    try:
        fd = os.open(str(output_path), flags, mode)
        with os.fdopen(fd, "w", encoding="utf-8") as f:
            f.write(content)
    except FileExistsError:
        raise KickstartModificationError(f"Output file already exists: {output_path}")
    except OSError as e:
        raise KickstartModificationError(f"Failed to write output file: {e}")


def modify_kickstart(
    template_path: pathlib.Path,
    output_path: pathlib.Path,
    params: Dict[str, str],
    plain_password: str,
) -> None:
    """Create a modified kickstart file based on a template."""
    _check_output_dir_permissions(output_path)

    content = _read_template(template_path)

    # Safe placeholder substitution
    for placeholder, value in params.items():
        # Replace only exact matches to avoid accidental partial replacements
        pattern = re.escape(placeholder)
        content = re.sub(pattern, value, content)

    # Encrypt password using SHA‑512
    salt = crypt.mksalt(method=crypt.METHOD_SHA512)
    encrypted_pw = crypt.crypt(plain_password, salt)

    # Insert encrypted password line at the top of the file
    pw_line = f"rootpw --iscrypted {encrypted_pw}"
    content = f"{pw_line}\n{content}"

    _write_output(content, output_path)


def _parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Modify a Kickstart file with parameters and encrypted password."
    )
    parser.add_argument("template", help="Path to the Kickstart template file.")
    parser.add_argument("output", help="Path where the modified Kickstart will be written.")
    parser.add_argument(
        "--params",
        required=True,
        help='JSON string of placeholder replacements, e.g. \'{"HOSTNAME":"myhost"}\'.',
    )
    return parser.parse_args()


def main() -> None:
    args = _parse_args()
    try:
        template_path = _secure_path(args.template)
        output_path = pathlib.Path(args.output).expanduser().resolve()

        params = _validate_params(json.loads(args.params))

        plain_password = os.getenv("KICKSTART_PASSWORD")
        if plain_password is not None:
            os.environ.pop("KICKSTART_PASSWORD", None)
        else:
            plain_password = getpass.getpass("Enter password to encrypt: ")

        modify_kickstart(template_path, output_path, params, plain_password)
    except (KickstartModificationError, json.JSONDecodeError, OSError) as exc:
        sys.stderr.write(f"Error: {exc}\n")
        sys.exit(1)


if __name__ == "__main__":
    main()

