logging.basicConfig(level=logging.INFO)


class SafeUnpickler(pickle.Unpickler):
    _SAFE_BUILTINS = {
        "list",
        "dict",
        "tuple",
        "set",
        "frozenset",
        "str",
        "int",
        "float",
        "bool",
        "bytes",
    }

    def find_class(self, module: str, name: str):
        if module == "builtins" and name in self._SAFE_BUILTINS:
            return getattr(__builtins__, name)
        if module == "numpy" and name == "ndarray":
            return np.ndarray
        raise pickle.UnpicklingError(f"Unsafe object attempted to be unpickled: {module}.{name}")


def _safe_load_pickle(file_path: pathlib.Path) -> Any:
    with file_path.open("rb") as f:
        data = SafeUnpickler(f).load()

    def _check(obj: Any):
        if isinstance(obj, np.ndarray):
            if obj.dtype == object:
                raise ValueError("Object‑dtype ndarray not allowed")
            if obj.dtype.kind not in ("b", "i", "u", "f", "c"):
                raise ValueError(f"Disallowed ndarray dtype: {obj.dtype}")
        elif isinstance(obj, (list, tuple, set)):
            for item in obj:
                _check(item)
        elif isinstance(obj, dict):
            for value in obj.values():
                _check(value)

    _check(data)
    return data


