logger = logging.getLogger(__name__)

_ALLOWED_SCHEMES = {
    "postgresql",
    "postgresql+psycopg2",
    "mysql",
    "mysql+mysqlconnector",
    "sqlite",
}

# Hosts that are explicitly allowed for network‑based databases.
_ALLOWED_HOSTS = {
    "localhost",
    "127.0.0.1",
}

# Directory that may contain SQLite database files.
_ALLOWED_SQLITE_DIR = Path("/var/lib/myapp/sqlite").resolve()


_URL_PATTERN = re.compile(r"^(?P<scheme>[\w+]+)://")


def _sanitize_url(url: str) -> str:
    """Redact password from a URL for safe logging."""
    parsed = urlparse(url)
    if parsed.password:
        netloc = (
            (parsed.username or "")
            + "@"
            + parsed.hostname
            + (f":{parsed.port}" if parsed.port else "")
        )
        sanitized = parsed._replace(netloc=netloc)
        return urlunparse(sanitized)
    return url


def _validate_db_url(url: str) -> str:
    if not isinstance(url, str):
        raise TypeError("Database URL must be a string")
    if not url:
        raise ValueError("Database URL cannot be empty")

    match = _URL_PATTERN.match(url)
    if not match:
        raise ValueError("Invalid database URL format")
    scheme = match.group("scheme")
    if scheme not in _ALLOWED_SCHEMES:
        raise ValueError(f"Unsupported database scheme: {scheme}")

    parsed = urlparse(url)

    # Disallow embedded credentials for network databases.
    if scheme != "sqlite":
        if parsed.username or parsed.password:
            raise ValueError("Credentials must not be supplied in the URL")
        if parsed.hostname not in _ALLOWED_HOSTS:
            raise ValueError(f"Host not allowed: {parsed.hostname}")

    else:
