        sqlite_path = Path(parsed.path).resolve()
        try:
            sqlite_path.relative_to(_ALLOWED_SQLITE_DIR)
        except Exception:
            raise ValueError(f"Disallowed SQLite file path: {sqlite_path}")

    return url


