                url = _validate_db_url(raw_url)
                engine = create_engine(
                    url,
                    future=True,
                    pool_pre_ping=True,
                    echo=False,
                )
                SessionLocal = sessionmaker(
                    bind=engine,
                    autoflush=False,
                    autocommit=False,
                    future=True,
                )
                session = SessionLocal()
                key = f"db{idx}"
                self._engines[key] = engine
                self._sessions[key] = session
            except Exception as exc:
                safe_url = _sanitize_url(raw_url)
                logger.error(
                    "Failed to initialize engine for database index %s (url=%s): %s",
                    idx,
