    def __exit__(self, exc_type, exc_val, exc_tb):
        self._cleanup()
        return False  # propagate exceptions

    def _cleanup(self):
        for key, session in list(self._sessions.items()):
            try:
                session.close()
            except Exception:
                logger.debug("Error closing session for %s", key)
            finally:
                self._sessions.pop(key, None)
        for key, engine in list(self._engines.items()):
            try:
                engine.dispose()
            except Exception:
                logger.debug("Error disposing engine for %s", key)
            finally:
                self._engines.pop(key, None)


def execute_on_multiple_databases(db_urls: List[str]) -> Dict[str, str]:
    """
    Connects to each database, runs a simple version query, and returns the results.
    All connections are safely closed after the operation.
    """
    results: Dict[str, str] = {}
    with MultiDBConnection(db_urls) as sessions:
        for name, session in sessions.items():
            try:
                version = session.execute(text("SELECT version()")).scalar()
                results[name] = str(version) if version is not None else "unknown"
            except Exception as exc:
                logger.warning("Version query failed for %s: %s", name, exc)
                results[name] = "error"
    return results

