    pass


@dataclass(frozen=True, slots=True)
class Controller:
    """Secure controller representation."""
    id: str = field(default_factory=lambda: str(uuid.uuid4()))
    controller_type: str = field(compare=False)
    sequencer: SequencerABC = field(compare=False)
    system: SystemABC = field(compare=False)

    def start(self) -> None:
        """Start the controller's sequencer safely."""
        if hasattr(self.sequencer, "start") and callable(self.sequencer.start):
            try:
                self.sequencer.start()
                logger.info("Sequencer started for controller %s", self.id)
            except Exception:
                logger.error("Failed to start sequencer for controller %s", self.id)

    def stop(self) -> None:
        """Stop the controller's sequencer safely."""
        if hasattr(self.sequencer, "stop") and callable(self.sequencer.stop):
            try:
                self.sequencer.stop()
                logger.info("Sequencer stopped for controller %s", self.id)
            except Exception:
                logger.error("Failed to stop sequencer for controller %s", self.id)

    def status(self) -> str:
        """Return a sanitized status string."""
        if hasattr(self.sequencer, "status"):
            try:
