def _validate_spec(spec: Dict[str, Any]) -> None:
    """Validate individual specification dictionary."""
    if not isinstance(spec, dict):
        raise ValueError("Each specification must be a dict.")
    if "type" not in spec or "count" not in spec:
        raise ValueError("Specification requires 'type' and 'count' keys.")
    ctype = spec["type"]
    count = spec["count"]
    if not isinstance(ctype, str):
        raise ValueError("Controller 'type' must be a string.")
    if ctype not in _ALLOWED_CONTROLLER_TYPES:
        raise ValueError(f"Controller type '{ctype}' is not allowed.")
    if not isinstance(count, int) or count < 0:
        raise ValueError("Controller 'count' must be a non‑negative integer.")
    if count > MAX_CONTROLLERS_PER_SPEC:
        raise ValueError(
            f"Controller 'count' exceeds maximum allowed per spec ({MAX_CONTROLLERS_PER_SPEC})."
        )


def create_controllers(
    specs: List[Dict[str, Any]],
    sequencer_factory: Callable[[str], SequencerABC],
    system_factory: Callable[[str], SystemABC],
) -> List[Controller]:
    """
    Create a list of Controller objects based on input specifications.

    Args:
        specs: List of dictionaries each containing 'type' (allowed controller type)
               and 'count' (number of controllers to create).
        sequencer_factory: Callable that returns a SequencerABC instance given a controller type.
        system_factory: Callable that returns a SystemABC instance given a controller type.

    Returns:
        List of securely instantiated Controller objects.

    Raises:
        ValueError: If input validation fails.
    """
    if not isinstance(specs, list):
        raise ValueError("Specs must be a list.")
    if not callable(sequencer_factory):
        raise ValueError("Sequencer factory must be callable.")
    if not callable(system_factory):
        raise ValueError("System factory must be callable.")

    controllers: List[Controller] = []

    for spec in specs:
        try:
            _validate_spec(spec)
        except ValueError as ve:
            logger.error("Invalid specification: %s", ve)
            raise

        ctype = spec["type"]
        count = spec["count"]

        for _ in range(count):
            try:
                sequencer = sequencer_factory(ctype)
                system = system_factory(ctype)

                if not isinstance(sequencer, SequencerABC):
                    raise TypeError("Sequencer instance does not implement required interface.")
                if not isinstance(system, SystemABC):
                    raise TypeError("System instance does not implement required interface.")

                controller = Controller(
                    controller_type=ctype,
                    sequencer=sequencer,
                    system=system,
                )
                controllers.append(controller)
                logger.info("Created controller %s of type %s", controller.id, ctype)
            except Exception as e:
                logger.error("Failed to create controller of type %s: %s", ctype, str(e))
                raise ValueError("Controller creation failed.") from None

    return controllers

