            + "}\n"
            "globals_dict = {'__builtins__': allowed}\n"
            "exec(compile(sys.stdin.read(), '<user_code>', 'exec'), globals_dict, {})\n"
        )
        try:
            result = subprocess.run(
                [sys.executable, "-I", "-"],
                input=(bootstrap + "\n" + code).encode("utf-8"),
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                timeout=5,
                env={},  # empty env to avoid accidental leakage
                check=False,
