def _is_sqlite_file(path: str) -> bool:
    """Return True if the file at *path* starts with the SQLite magic header."""
    try:
        with open(path, "rb") as f:
            header = f.read(16)
            return header == b"SQLite format 3\x00"
    except OSError as e:
        logger.debug("Unable to read file header for %s: %s", path, e)
        return False

def get_table_indexes(db_path: str, table_name: str) -> List[Dict[str, Any]]:
    # Validate argument types
    if not isinstance(db_path, str) or not isinstance(table_name, str):
        raise GetTableIndexesError("Both db_path and table_name must be strings.")

    # Resolve absolute paths and enforce allowed directory
    abs_db_path = os.path.abspath(db_path)
    allowed_dir = os.path.abspath(ALLOWED_DB_DIR)
    if os.path.commonpath([allowed_dir, abs_db_path]) != allowed_dir:
        raise GetTableIndexesError("Database path is outside the allowed directory.")

    # Verify file existence and SQLite format
    if not os.path.isfile(abs_db_path):
        raise GetTableIndexesError("Database file does not exist.")
    if not _is_sqlite_file(abs_db_path):
        raise GetTableIndexesError("File is not a valid SQLite database.")

    # Validate table name (SQLite identifiers)
    if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", table_name):
        raise GetTableIndexesError("Invalid table name.")

    # Connect in read‑only mode
    try:
        conn = sqlite3.connect(
            f"file:{abs_db_path}?mode=ro", uri=True, check_same_thread=False
        )
        conn.row_factory = sqlite3.Row
    except sqlite3.Error as e:
        logger.error("Failed to open SQLite database %s: %s", abs_db_path, e)
        raise GetTableIndexesError("Unable to open database.") from e

    indexes: List[Dict[str, Any]] = []
    try:
        cur = conn.cursor()
        # Safe quoting using validated identifiers
        cur.execute(f'PRAGMA index_list("{table_name}")')
        for idx_row in cur.fetchall():
            idx_name = idx_row["name"]
            if not isinstance(idx_name, str) or not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", idx_name):
                continue
            is_unique = bool(idx_row["unique"])
            cur.execute(f'PRAGMA index_info("{idx_name}")')
            cols = [
                col_row["name"]
                for col_row in cur.fetchall()
                if isinstance(col_row["name"], str)
            ]
            indexes.append(
                {"index_name": idx_name, "columns": cols, "unique": is_unique}
            )
    except sqlite3.Error as e:
        logger.error("SQLite query error for database %s: %s", abs_db_path, e)
        raise GetTableIndexesError("Error querying database.") from e
    finally:
        conn.close()

    return indexes

