    record_id = _validate_int(record_id, "record_id")
    aes_key = _validate_bytes(aes_key, "aes_key")
    if len(aes_key) not in (16, 24, 32):
        raise ValueError("aes_key must be 16, 24, or 32 bytes long (128/192/256‑bit)")

    if table_name not in ALLOWED_TABLES:
        raise ValueError("Invalid or unauthorized table name")
    if id_column not in ALLOWED_COLUMNS:
        raise ValueError("Invalid or unauthorized id column name")
    if encrypted_column not in ALLOWED_COLUMNS:
        raise ValueError("Invalid or unauthorized encrypted column name")

