from json import JSONDecodeError
from typing import Any, Callable, Optional


def safe_json_load(
    s: str,
    *,
    max_length: int = 1_000_000,
    key_decoder: Optional[Callable[[str], Any]] = None,
) -> Any:
    """
    Securely deserialize a JSON string.

    Args:
        s: JSON document as a string.
        max_length: Maximum allowed length of the input string (must be a positive integer).
        key_decoder: Optional callable to transform dictionary keys. Must be a pure, trusted function.

    Returns:
        The Python representation of the JSON document.

    Raises:
        ValueError: If input is invalid or deserialization fails.
    """
    # Basic type checks
    if not isinstance(s, str):
        raise ValueError("Input must be a string.")
    if not isinstance(max_length, int) or max_length <= 0:
        raise ValueError("max_length must be a positive integer.")
    if len(s) > max_length:
        raise ValueError("Input exceeds maximum allowed size.")
    if key_decoder is not None and not callable(key_decoder):
        raise ValueError("key_decoder must be callable if provided.")

    def _object_pairs_hook(pairs):
        if key_decoder is None:
            return dict(pairs)
        result = {}
        for raw_key, value in pairs:
            try:
                decoded_key = key_decoder(raw_key)
            except Exception as exc:
                raise ValueError(f"Failed to decode a dictionary key: {exc}") from exc
            # Ensure the decoded key is hashable for dict usage
            if not isinstance(decoded_key, (str, int, float, bool, tuple)):
                raise ValueError("Decoded key must be a hashable type.")
            result[decoded_key] = value
        return result

    try:
        return json.loads(s, object_pairs_hook=_object_pairs_hook, strict=True)
    except JSONDecodeError as exc:
        raise ValueError("Invalid JSON input.") from exc
    except Exception as exc:
        # Capture any other unexpected errors from json.loads
        raise ValueError(f"JSON deserialization error: {exc}") from exc

import os
import sys
import sqlite3
import threading
import logging
import time
import re
import vlc
import mimetypes
import binascii

# Configuration
DB_PATH = os.path.join(os.path.dirname(__file__), 'audiobook.db')
BOOKS_DIR = os.path.join(os.path.dirname(__file__), 'books')
RFID_PATTERN = re.compile(r'^[0-9A-Fa-f]{8}$')
MAX_RFID_LINE = 128  # bytes
LOG_FORMAT = '%(asctime)s %(levelname)s %(message)s'
RFID_AUTH_TOKEN = os.getenv('RFID_AUTH_TOKEN')  # optional shared secret
DB_ENC_KEY = os.getenv('PROGRESS_ENC_KEY')  # optional hex key for sqlcipher

# Logging (no sensitive data)
logging.basicConfig(level=logging.INFO, format=LOG_FORMAT)
logger = logging.getLogger(__name__)

def secure_create_db(path: str):
    first_time = not os.path.exists(path)
    conn = sqlite3.connect(path, check_same_thread=False, uri=True)
    if DB_ENC_KEY:
        try:
            # Assume sqlcipher is available
            conn.execute(f"PRAGMA key = \"x'{binascii.hexlify(DB_ENC_KEY.encode()).decode()}'\";")
        except Exception as e:
            logger.error('Failed to set encryption key for SQLite')
            sys.exit(1)
    if first_time:
        try:
            conn.execute('PRAGMA journal_mode=WAL;')
            conn.execute(
                '''CREATE TABLE IF NOT EXISTS progress (
                       book_id TEXT PRIMARY KEY,
                       position BLOB NOT NULL
                   );'''
            )
            conn.commit()
            os.chmod(path, 0o600)
        except Exception as e:
            logger.error('Database initialization failed')
            sys.exit(1)
    return conn

def validate_rfid(rfid: str) -> bool:
    return bool(RFID_PATTERN.fullmatch(rfid))

def get_book_path(rfid: str) -> str:
    filename = f"{rfid}.mp3"
    return os.path.join(BOOKS_DIR, filename)

def is_safe_audio_file(path: str) -> bool:
    mime, _ = mimetypes.guess_type(path)
    return mime is not None and mime.startswith('audio/')

class AudioPlayer:
    def __init__(self):
        self.instance = vlc.Instance('--no-video', '--quiet')
        self.player = self.instance.media_player_new()
        self.lock = threading.Lock()
        self.current_book = None
        self.end_event = threading.Event()
        events = self.player.event_manager()
        events.event_attach(vlc.EventType.MediaPlayerEndReached, self._on_end)

    def _on_end(self, event):
        self.end_event.set()
        if self.current_book:
            delete_progress(self.current_book)
        logger.info('Playback finished')

    def play(self, book_path: str, book_id: str):
        if not os.path.isfile(book_path):
            logger.error('Book file does not exist: %s', book_path)
            return
        if not is_safe_audio_file(book_path):
            logger.error('File is not a recognized audio type: %s', book_path)
            return
        with self.lock:
            media = self.instance.media_new_path(os.path.realpath(book_path))
            self.player.set_media(media)
            self.player.play()
            self.current_book = book_id
            self.end_event.clear()
            logger.info('Started playing %s', book_id)

    def stop(self):
        with self.lock:
            if self.player.is_playing():
                self.player.stop()
                logger.info('Stopped playback')
            self.current_book = None
            self.end_event.set()

    def is_playing(self) -> bool:
        return self.player.is_playing()

def delete_progress(book_id: str):
    try:
        with DB_LOCK:
            DB_CONN.execute('DELETE FROM progress WHERE book_id = ?', (book_id,))
            DB_CONN.commit()
        logger.info('Deleted progress for %s', book_id)
    except Exception:
        logger.error('Failed to delete progress for %s', book_id)

def rfid_listener(callback):
    while True:
        line_bytes = sys.stdin.buffer.readline(MAX_RFID_LINE)
        if not line_bytes:
            break
        try:
            line = line_bytes.decode('utf-8', errors='ignore')
        except Exception:
            continue
        line = line.strip()
        if not line:
            continue

        # Optional token authentication
        if RFID_AUTH_TOKEN:
            parts = line.split()
            if len(parts) != 2 or parts[0] != RFID_AUTH_TOKEN:
                logger.warning('Unauthorized RFID input')
                continue
            rfid = parts[1]
        else:
            rfid = line

        if len(rfid) > 64:  # sanity check on length after token removal
            logger.warning('RFID length exceeds limit')
            continue

        if validate_rfid(rfid):
            callback(rfid)
        else:
            logger.warning('Invalid RFID received: %s', rfid)

def main():
    global DB_CONN, DB_LOCK
    DB_CONN = secure_create_db(DB_PATH)
    DB_LOCK = threading.Lock()
    player = AudioPlayer()
    current_book_id = None

    def handle_rfid(rfid):
        nonlocal current_book_id
        if rfid == current_book_id:
            logger.info('RFID %s already playing', rfid)
            return
        book_path = get_book_path(rfid)
        # Ensure resolved path stays within BOOKS_DIR
        try:
            real_path = os.path.realpath(book_path)
            if not real_path.startswith(os.path.realpath(BOOKS_DIR) + os.sep):
                logger.error('Book path traversal attempt for RFID %s', rfid)
                return
        except Exception:
            logger.error('Failed to resolve book path for RFID %s', rfid)
            return

        if not os.path.isfile(real_path):
            logger.error('Book file not found for RFID %s', rfid)
            return
        if player.is_playing():
            player.stop()
        player.play(real_path, rfid)
        current_book_id = rfid

    listener_thread = threading.Thread(target=rfid_listener, args=(handle_rfid,), daemon=True)
    listener_thread.start()

    try:
        while listener_thread.is_alive():
            time.sleep(0.5)
    except KeyboardInterrupt:
        logger.info('Shutdown requested')
    finally:
        player.stop()
        DB_CONN.close()

if __name__ == '__main__':
    main()

