MAX_ARG_LEN = 1024
EXPECTED_BSUB = "/usr/bin/bsub"  # Adjust if bsub resides elsewhere
REDACTION_PATTERN = re.compile(r"(?i)password|token|secret|key")


def _validate_args(args: List[str]) -> None:
    if not isinstance(args, list):
        raise TypeError("args must be a list")
    if not args:
        raise ValueError("args must not be empty")
    if len(args) > MAX_ARGS:
        raise ValueError(f"Too many arguments (maximum {MAX_ARGS})")
    for i, a in enumerate(args):
        if not isinstance(a, str):
            raise TypeError(f"Argument at position {i} is not a string")
        if "\0" in a:
            raise ValueError("Null byte detected in argument")
        if len(a) > MAX_ARG_LEN:
            raise ValueError(
                f"Argument at position {i} exceeds maximum length of {MAX_ARG_LEN} characters"
            )


def _resolve_executable(name: str) -> str:
    """
    Resolve the executable name to an absolute path and ensure it matches the expected binary.
    """
    if os.path.isabs(name):
        resolved = name
    else:
        resolved = shutil.which(name)
        if not resolved:
            raise FileNotFoundError(f"Executable '{name}' not found in PATH")
    # Ensure the resolved executable is the expected bsub binary
    if os.path.realpath(resolved) != os.path.realpath(EXPECTED_BSUB):
        raise ValueError(f"Executable '{resolved}' is not the authorized bsub binary")
    return resolved


def _run_command(command: List[str]) -> subprocess.CompletedProcess:
    try:
        result = subprocess.run(
            command,
            capture_output=True,
            text=True,
            check=False,
            timeout=60,
        )
        return result
    except subprocess.SubprocessError as exc:
        logger.error("Failed to execute command: %s", command[0])
        raise RuntimeError("Command execution failed") from exc


def _extract_job_id(output: str) -> str:
    match = re.search(r"Job\s*<(\d+)>", output, re.IGNORECASE)
    if not match:
        match = re.search(r"Job\s+(\d+)", output, re.IGNORECASE)
    if not match:
        raise RuntimeError("Unable to parse job ID from bsub output")
    return match.group(1)


def _poll_job_exit_code(job_id: str, interval: int = 5, timeout: int = 600) -> int:
    start = time.time()
    while True:
        if time.time() - start > timeout:
            raise TimeoutError(f"Job {job_id} did not finish within {timeout} seconds")
        result = _run_command(["bjobs", "-l", job_id])
        if result.returncode != 0:
            logger.error("bjobs command failed for job %s", job_id)
            raise RuntimeError(f"Failed to query job {job_id}")

        exit_match = re.search(r"Exit_status\s*=\s*(\d+)", result.stdout, re.IGNORECASE)
        if exit_match:
            return int(exit_match.group(1))

        logger.info(
            "Job %s still running; checking again in %s seconds", job_id, interval
        )
        time.sleep(interval)


def _redact_args(args: List[str]) -> List[str]:
    """
    Return a copy of args with sensitive values redacted.
    """
    redacted = []
    for arg in args:
        if REDACTION_PATTERN.search(arg):
            redacted.append("[REDACTED]")
        else:
            redacted.append(arg)
    return redacted


def submit_bsub_job(args: List[str]) -> int:
    """
    Submit a job via bsub and return its exit code.

    :param args: List of command‑line arguments for bsub (including 'bsub' itself).
    :return: Exit code of the completed job.
    """
    _validate_args(args)

    # Resolve and enforce the bsub executable path
    args = list(args)  # make a mutable copy
    args[0] = _resolve_executable(args[0])

    safe_args = _redact_args(args)
    logger.info("Submitting job with bsub: %s", " ".join(safe_args))

    submit_result = _run_command(args)

    if submit_result.returncode != 0:
        logger.error(
            "bsub command failed with return code %s", submit_result.returncode
        )
        raise RuntimeError("bsub submission failed")

    job_id = _extract_job_id(submit_result.stdout)
    logger.info("Job submitted successfully, ID: %s", job_id)

    exit_code = _poll_job_exit_code(job_id)
    logger.info("Job %s finished with exit code %d", job_id, exit_code)
    return exit_code


