    except Exception as exc:
        raise ValueError("Failed to resolve directory path.") from exc

    if not resolved.is_dir():
        raise ValueError("Target is not a directory.")

    if _is_prohibited(resolved):
        raise ValueError("Deletion of prohibited directory.")

    # Ensure none of the components are symlinks (pre‑flight check)
    for part in resolved.parents:
        if part.is_symlink():
