import os
import sys
import re
import subprocess

BASE_DIR = os.path.abspath(os.path.join(os.path.dirname(__file__), "data"))
MAX_FILE_SIZE = 10 * 1024 * 1024  # 10 MB


def _safe_int(value):
    """Validate that value is a non‑negative integer."""
    try:
        iv = int(value)
        if iv < 0:
            raise ValueError
        return iv
    except Exception:
        raise ValueError("Invalid integer input")


def _run_date(offset_days):
    """
    Retrieve year month day using the system `date` command.
    offset_days: 0 for today, N for N days ago.
    Returns (year, month, day) as ints.
    """
    try:
        if offset_days == 0:
            cmd = ["date", "+%Y %m %d"]
        else:
            cmd = ["date", "-d", f"-{offset_days} days", "+%Y %m %d"]
        result = subprocess.run(
            cmd, capture_output=True, text=True, check=True
        )
        raw = result.stdout
        if not raw:
            raise RuntimeError("Empty output from date command")
        parts = raw.strip().split()
        if len(parts) != 3:
            raise RuntimeError("Unexpected date format")
        year, month, day = map(int, parts)
        return year, month, day
    except Exception as exc:
        raise RuntimeError("Failed to execute date command") from exc


def _validate_path(file_path):
    """Ensure the provided path points inside BASE_DIR and is safe."""
    if not isinstance(file_path, str):
        raise ValueError("File path must be a string")
    if "\0" in file_path:
        raise ValueError("File path contains null byte")
    # Resolve the path relative to BASE_DIR
    abs_path = os.path.abspath(os.path.join(BASE_DIR, file_path))
    # Ensure the resolved path is within BASE_DIR
    if not (abs_path == BASE_DIR or abs_path.startswith(BASE_DIR + os.sep)):
        raise ValueError("File path is outside the allowed directory")
    if not os.path.isfile(abs_path):
        raise ValueError("Specified file does not exist")
    if os.path.getsize(abs_path) > MAX_FILE_SIZE:
        raise ValueError("File exceeds maximum allowed size")
    return abs_path


def _read_last_entry(file_path):
    """
    Open file, read the last non‑empty line expected in YYYYMMDD format.
    Returns (year, month, day) as ints.
    """
    path = _validate_path(file_path)
    try:
        last_entry = None
        with open(path, "r", encoding="utf-8") as f:
            for line in f:
                line = line.strip()
                if line:
                    last_entry = line
        if last_entry is None:
            raise ValueError("File contains no valid entries")
        if not re.fullmatch(r"\d{8}", last_entry):
            raise ValueError("Entry does not match YYYYMMDD format")
        year = int(last_entry[0:4])
        month = int(last_entry[4:6])
        day = int(last_entry[6:8])
        return year, month, day
    except Exception as exc:
        raise RuntimeError("Failed to read last entry from file") from exc


def main():
    if len(sys.argv) != 3:
        sys.exit("Usage: script.py <days_passed> <file_path>")
    days_passed = _safe_int(sys.argv[1])
    file_path = sys.argv[2]

    # Current date
    cur_year, cur_month, cur_day = _run_date(0)

    # Date offset by given days
    prev_year, prev_month, prev_day = _run_date(days_passed)

    # Extract from file
    ent_year, ent_month, ent_day = _read_last_entry(file_path)

    print(f"Current: {cur_year:04d}-{cur_month:02d}-{cur_day:02d}")
    print(
        f"{days_passed} day(s) ago: {prev_year:04d}-{prev_month:02d}-{prev_day:02d}"
    )
    print(f"Last entry: {ent_year:04d}-{ent_month:02d}-{ent_day:02d}")


if __name__ == "__main__":
    main()

