#!/usr/bin/env python3
import argparse
import json
import logging
import os
import re
import shutil
import stat
import sys
import tempfile
import urllib.parse
import urllib.request
import zipfile
import tarfile
import socket
import ipaddress

# Configure logger
logger = logging.getLogger("secure_builder")
handler = logging.StreamHandler(sys.stderr)
formatter = logging.Formatter("%(asctime)s - %(levelname)s - %(message)s")
handler.setFormatter(formatter)
logger.addHandler(handler)
logger.setLevel(logging.INFO)


def is_safe_product_name(name: str) -> bool:
    return re.fullmatch(r"[A-Za-z0-9._-]+", name) is not None


def is_private_ip(ip: str) -> bool:
    try:
        addr = ipaddress.ip_address(ip)
        return addr.is_private or addr.is_loopback or addr.is_reserved or addr.is_link_local
    except ValueError:
        return True


def is_url_allowed(url: str) -> bool:
    try:
        parsed = urllib.parse.urlparse(url)
        if parsed.scheme not in ("http", "https"):
            return False
        host = parsed.hostname
        if not host:
            return False
        # Resolve host to IPs and ensure none are private/internal
        try:
            infos = socket.getaddrinfo(host, None, family=socket.AF_UNSPEC, type=socket.SOCK_STREAM)
        except socket.gaierror:
            return False
        for family, _, _, _, sockaddr in infos:
            ip = sockaddr[0]
            if is_private_ip(ip):
                return False
        return True
    except Exception:
        return False


def safe_join(base: str, *paths: str) -> str:
    new_path = os.path.abspath(os.path.join(base, *paths))
    base_abs = os.path.abspath(base)
    if not (new_path == base_abs or new_path.startswith(base_abs + os.sep)):
        raise ValueError("Attempted path traversal")
    return new_path


def download_file(url: str, dest_path: str, max_bytes: int = 100 * 1024 * 1024, timeout: int = 10) -> None:
    logger.debug("Downloading %s to %s", url, dest_path)
    try:
        with urllib.request.urlopen(url, timeout=timeout) as response, open(dest_path, "wb") as out_file:
            total = 0
            while True:
                chunk = response.read(8192)
                if not chunk:
                    break
                total += len(chunk)
                if total > max_bytes:
                    raise ValueError("Download exceeds maximum allowed size")
                out_file.write(chunk)
    except Exception as exc:
        logger.error("Failed to download %s", url)
        raise exc


def extract_archive(archive_path: str, extract_to: str) -> None:
    if zipfile.is_zipfile(archive_path):
        with zipfile.ZipFile(archive_path, "r") as zf:
            for member in zf.infolist():
                member_path = member.filename
                if os.path.isabs(member_path) or ".." in member_path.split(os.path.sep):
                    logger.warning("Skipped unsafe member in zip: %s", member_path)
                    continue
                target_path = safe_join(extract_to, member_path)
                os.makedirs(os.path.dirname(target_path), exist_ok=True)
                with zf.open(member, "r") as source, open(target_path, "wb") as target:
                    shutil.copyfileobj(source, target)
                set_secure_permissions(target_path, is_dir=False)
    elif tarfile.is_tarfile(archive_path):
        with tarfile.open(archive_path, "r:*") as tf:
            for member in tf.getmembers():
                member_path = member.name
                if os.path.isabs(member_path) or ".." in member_path.split(os.path.sep):
                    logger.warning("Skipped unsafe member in tar: %s", member_path)
                    continue
                if member.issym() or member.islnk():
                    logger.warning("Skipped symlink/hardlink in tar: %s", member_path)
                    continue
                if member.isdir():
                    target_path = safe_join(extract_to, member_path)
                    os.makedirs(target_path, exist_ok=True)
                    set_secure_permissions(target_path, is_dir=True)
                elif member.isreg():
                    target_path = safe_join(extract_to, member_path)
                    os.makedirs(os.path.dirname(target_path), exist_ok=True)
                    extracted_file = tf.extractfile(member)
                    if extracted_file is None:
                        continue
                    with open(target_path, "wb") as out_f:
                        shutil.copyfileobj(extracted_file, out_f)
                    set_secure_permissions(target_path, is_dir=False)
                else:
                    logger.warning("Skipped unsupported tar member type: %s", member_path)
    else:
        logger.error("Unsupported archive format: %s", archive_path)
        raise ValueError("Unsupported archive format")


def move_contents(src_dir: str, dest_dir: str) -> None:
    for entry in os.listdir(src_dir):
        src_path = os.path.join(src_dir, entry)
        dest_path = os.path.join(dest_dir, entry)
        shutil.move(src_path, dest_path)


def create_zip(source_dir: str, zip_path: str) -> None:
    with zipfile.ZipFile(zip_path, "w", zipfile.ZIP_DEFLATED) as zf:
        for root, _, files in os.walk(source_dir):
            for file in files:
                full_path = os.path.join(root, file)
                rel_path = os.path.relpath(full_path, source_dir)
                zf.write(full_path, rel_path)


def set_secure_permissions(path: str, is_dir: bool = False) -> None:
    if is_dir:
        mode = stat.S_IRWXU | stat.S_IRGRP | stat.S_IXGRP  # 0o750
    else:
        mode = stat.S_IRUSR | stat.S_IWUSR | stat.S_IRGRP  # 0o640
    os.chmod(path, mode)


def verify_checksum(file_path: str, expected_sha256: str) -> bool:
    import hashlib

    sha256 = hashlib.sha256()
    try:
        with open(file_path, "rb") as f:
            for block in iter(lambda: f.read(8192), b""):
                sha256.update(block)
    except Exception:
        return False
    return sha256.hexdigest().lower() == expected_sha256.lower()


def process_products(product_map: dict, build_root: str) -> None:
    staging_root = os.path.join(build_root, "staging")
    final_root = os.path.join(build_root, "final")
    for p_name, packages in product_map.items():
        if not is_safe_product_name(p_name):
            logger.warning("Skipping unsafe product name: %s", p_name)
            continue
        if not isinstance(packages, list):
            logger.warning("Invalid package list for product: %s", p_name)
            continue

        staging_dir = os.path.join(staging_root, p_name)
        final_dir = os.path.join(final_root, p_name)

        for d in (staging_dir, final_dir):
            os.makedirs(d, exist_ok=True, mode=0o750)
            set_secure_permissions(d, is_dir=True)

        for pkg in packages:
            url = None
            checksum = None
            if isinstance(pkg, str):
                url = pkg
            elif isinstance(pkg, dict) and isinstance(pkg.get("url"), str):
                url = pkg["url"]
                checksum = pkg.get("sha256")
            else:
                logger.warning("Skipping malformed package entry for product %s: %s", p_name, pkg)
                continue

            if not is_safe_url(url) or not is_url_allowed(url):
                logger.warning("Skipping disallowed URL: %s", url)
                continue

            try:
                filename = os.path.basename(urllib.parse.urlparse(url).path) or "downloaded_pkg"
                safe_filename = re.sub(r"[^A-Za-z0-9._-]", "_", filename)
                download_path = os.path.join(staging_dir, safe_filename)

                download_file(url, download_path)
                if checksum:
                    if not verify_checksum(download_path, checksum):
                        logger.error("Checksum verification failed for %s", url)
                        os.remove(download_path)
                        continue

                extract_dir = tempfile.mkdtemp(dir=staging_dir)
                set_secure_permissions(extract_dir, is_dir=True)
                extract_archive(download_path, extract_dir)
                move_contents(extract_dir, final_dir)
                shutil.rmtree(extract_dir, ignore_errors=True)
                os.remove(download_path)
            except Exception:
                logger.error("Error processing package %s for product %s", url, p_name)
                continue


def main() -> None:
    parser = argparse.ArgumentParser(description="Secure product builder")
    parser.add_argument("manifest", help="Path to JSON file with product/package mapping")
    parser.add_argument("build_dir", help="Path to the build directory")
    args = parser.parse_args()

    try:
        with open(args.manifest, "r", encoding="utf-8") as f:
            manifest_data = json.load(f)
        if not isinstance(manifest_data, dict):
            logger.error("Manifest JSON must be an object")
            sys.exit(1)
    except Exception:
        logger.error("Failed to read manifest file")
        sys.exit(1)

    build_dir = os.path.abspath(args.build_dir)
    try:
        os.makedirs(build_dir, exist_ok=True, mode=0o750)
        set_secure_permissions(build_dir, is_dir=True)
    except Exception:
        logger.error("Unable to prepare build directory")
        sys.exit(1)

    process_products(manifest_data, build_dir)

    final_dir = os.path.join(build_dir, "final")
    zip_path = os.path.join(build_dir, "final.zip")
    try:
        create_zip(final_dir, zip_path)
        set_secure_permissions(zip_path, is_dir=False)
        logger.info("Created zip archive at %s", zip_path)
    except Exception:
        logger.error("Failed to create zip archive")
        sys.exit(1)


if __name__ == "__main__":
    main()

