import os
import sys
import json
import shlex
import re
import subprocess
import argparse
from pathlib import Path

# ANSI color codes
COLOR_CMD = "\033[93m"    # Yellow
COLOR_INP = "\033[96m"    # Cyan
COLOR_OUT = "\033[92m"    # Green
COLOR_ERR = "\033[91m"    # Red
COLOR_RST = "\033[0m"

# Whitelisted commands (least‑privilege)
ALLOWED_CMDS = {"ls", "pwd", "whoami", "date", "echo"}

# Restrictive pattern for safe arguments (alphanumerics, dot, dash, underscore, slash)
SAFE_ARG_RE = re.compile(r'^[a-zA-Z0-9._/\-]+$')

# Pattern to strip ANSI escape sequences
ANSI_RE = re.compile(r'\x1b\[[0-9;]*[mK]')

def strip_ansi(text: str) -> str:
    return ANSI_RE.sub("", text)

def load_json(path: Path) -> dict:
    # Ensure the path is within the current working directory
    base_dir = Path.cwd().resolve()
    try:
        resolved_path = path.resolve(strict=True)
    except FileNotFoundError:
        sys.exit(f"{COLOR_ERR}JSON file not found: {path}{COLOR_RST}")
    if not str(resolved_path).startswith(str(base_dir)):
        sys.exit(f"{COLOR_ERR}JSON file must reside within the working directory.{COLOR_RST}")

    try:
        with resolved_path.open("r", encoding="utf-8") as f:
            data = json.load(f)
        if not isinstance(data, dict):
            raise ValueError("JSON root must be an object")
        return data
    except json.JSONDecodeError as e:
        sys.exit(f"{COLOR_ERR}Failed to parse JSON: {e}{COLOR_RST}")
    except Exception as e:
        sys.exit(f"{COLOR_ERR}Failed to read JSON file: {e}{COLOR_RST}")

def is_allowed(command: str) -> bool:
    try:
        parts = shlex.split(command)
        if not parts:
            return False
        if parts[0] not in ALLOWED_CMDS:
            return False
        for arg in parts[1:]:
            if not SAFE_ARG_RE.fullmatch(arg):
                return False
        return True
    except ValueError:  # shlex split error
        return False

def run_command(parts: list) -> tuple[str, int]:
    try:
        result = subprocess.run(
            parts,
            capture_output=True,
            text=True,
            shell=False,
            check=False,
        )
        return result.stdout, result.returncode
    except FileNotFoundError:
        return "", 127
    except Exception:
        return "", 1

def main() -> None:
    parser = argparse.ArgumentParser(description="Execute whitelisted commands from a JSON file.")
    parser.add_argument("json_path", help="Path to commands JSON file")
    parser.add_argument(
        "--interactive",
        action="store_true",
        help="Pause after each command (default: no pause)",
    )
    args = parser.parse_args()

    cmd_dict = load_json(Path(args.json_path))
    results: dict[str, str | None] = {}

    for cmd, inp in cmd_dict.items():
        if not isinstance(cmd, str) or not isinstance(inp, str):
            print(f"{COLOR_ERR}Invalid entry types; skipping.{COLOR_RST}")
            continue

        print(f"{COLOR_CMD}Command:{COLOR_RST} {cmd}")
        print(f"{COLOR_INP}Input:{COLOR_RST} {inp}")

        if not is_allowed(cmd):
            print(f"{COLOR_ERR}Command not allowed or contains unsafe arguments. Skipping.{COLOR_RST}")
            results[cmd] = None
            if args.interactive:
                input("Press Enter to continue...")
            continue

        parts = shlex.split(cmd)
        output, exit_status = run_command(parts)

        if exit_status != 0:
            print(f"{COLOR_ERR}Command execution failed with status {exit_status}.{COLOR_RST}")
        else:
            print(f"{COLOR_OUT}Output:{COLOR_RST}\n{strip_ansi(output)}")

        results[cmd] = output.rstrip("\n")
        if args.interactive:
            input("Press Enter to continue...")

    print(f"{COLOR_CMD}Results:{COLOR_RST}")
    try:
        print(json.dumps(results, ensure_ascii=False, indent=2))
    except (TypeError, ValueError) as e:
        print(f"{COLOR_ERR}Failed to serialize results: {e}{COLOR_RST}")

if __name__ == "__main__":
    main()

