public class AntlrRunner {
    // Absolute path to the antlr4 binary – adjust if installed elsewhere
    private static final Path ANTLR_BINARY = Paths.get("/usr/local/bin/antlr4");

    // Whitelist of allowed antlr4 options (flag only, value may follow after '=').
    private static final Set<String> ALLOWED_OPTIONS = Set.of(
            "-D",          // property definition, e.g., -Dlanguage=Java
            "-listener",
            "-no-listener",
            "-visitor",
            "-no-visitor",
            "-encoding",
            "-package",
            "-o",
            "-lib"
    );

    // Maximum amount of error output (bytes) to read before truncating.
    private static final int MAX_ERROR_OUTPUT = 64 * 1024; // 64 KiB

    public static void main(String[] args) {
        if (args.length < 2) {
            System.err.println("Usage: java AntlrRunner <directory> <grammarFile> [options...]");
            System.exit(1);
        }

        // Verify that the antlr binary exists and is executable.
        if (!Files.isRegularFile(ANTLR_BINARY) || !Files.isExecutable(ANTLR_BINARY)) {
            System.err.println("Error: antlr4 executable not found or not executable at " + ANTLR_BINARY);
            System.exit(1);
