        if (!grammarFile.isAbsolute()) {
            grammarFile = dir.resolve(grammarFile).normalize();
        }

        // Validate grammar file (initial check)
        if (!Files.isRegularFile(grammarFile) || !Files.isReadable(grammarFile)) {
            System.err.println("Error: Grammar file is not readable or does not exist.");
            System.exit(1);
        }

        // Validate options against whitelist
        List<String> options = new ArrayList<>();
        for (int i = 2; i < args.length; i++) {
            String opt = args[i];
            if (opt.contains(" ") || opt.contains("\t") || opt.contains("\n")) {
                System.err.println("Error: Option contains whitespace: '" + opt + "'.");
                System.exit(1);
            }
            String flag = opt;
            int eqIdx = opt.indexOf('=');
            if (eqIdx != -1) {
                flag = opt.substring(0, eqIdx);
            }
            if (!ALLOWED_OPTIONS.contains(flag)) {
                System.err.println("Error: Disallowed option '" + opt + "'.");
                System.exit(1);
            }
            options.add(opt);
        }

        // Build command with absolute antlr path
        List<String> command = new ArrayList<>();
        command.add(ANTLR_BINARY.toString());
        command.addAll(options);
        command.add(grammarFile.toString());

        ProcessBuilder pb = new ProcessBuilder(command);
        pb.directory(dir.toFile());

        // Restrict environment to minimal necessary variables
        Map<String, String> env = pb.environment();
        env.keySet().retainAll(Set.of("PATH", "JAVA_HOME"));

        pb.redirectErrorStream(false);

