import requests
from requests import Response, Session
from requests.exceptions import RequestException, Timeout, HTTPError


class AssetUpdateError(Exception):
    """Custom exception for asset update failures."""
    pass


def _validate_url(url: str) -> None:
    """Validate that the URL is HTTPS, has no query/fragment, and does not point to a private network."""
    if not isinstance(url, str):
        raise ValueError("Base URL must be a string.")
    parsed = urlparse(url)
    if parsed.scheme != "https":
        raise ValueError("Base URL must use HTTPS scheme.")
    if not parsed.netloc:
        raise ValueError("Base URL must contain a network location.")
    if parsed.query or parsed.fragment:
        raise ValueError("Base URL must not contain query strings or fragments.")
    hostname = parsed.hostname
    if not hostname:
        raise ValueError("Base URL must contain a hostname.")

    # Reject explicit private IP addresses or localhost
    try:
        ip = ipaddress.ip_address(hostname)
        if ip.is_private or ip.is_loopback:
            raise ValueError("Base URL must not resolve to a private or loopback IP address.")
    except ValueError:
        # Not an IP literal; resolve DNS and check each address
        try:
            for info in socket.getaddrinfo(hostname, None):
                addr = info[4][0]
                ip_obj = ipaddress.ip_address(addr)
                if ip_obj.is_private or ip_obj.is_loopback:
                    raise ValueError("Base URL resolves to a private or loopback IP address.")
        except socket.gaierror as exc:
            raise ValueError("Unable to resolve hostname in Base URL.") from exc


def _validate_asset_id(asset_id: str) -> None:
    if not isinstance(asset_id, str) or not re.fullmatch(r"[A-Za-z0-9\-_]+", asset_id):
        raise ValueError("Asset type ID contains invalid characters.")


def _validate_name(name: str) -> str:
    if not isinstance(name, str):
        raise ValueError("Name must be a string.")
    cleaned = name.strip()
    if not cleaned:
        raise ValueError("Name cannot be empty or whitespace.")
    if len(cleaned) > 255:
        raise ValueError("Name exceeds maximum length of 255 characters.")
    if any(ord(ch) < 32 for ch in cleaned):
        raise ValueError("Name contains control characters.")
    return cleaned


def _validate_api_key(api_key: str) -> None:
    if not isinstance(api_key, str) or not api_key.strip():
        raise ValueError("API key must be a non‑empty string.")


def _handle_response(resp: Response, max_bytes: int = 1_048_576) -> Dict[str, Any]:
    """Validate response, limit size, and decode JSON."""
    if resp.is_redirect:
        raise AssetUpdateError(f"Unexpected redirect to {resp.headers.get('Location')}")
    try:
        resp.raise_for_status()
    except HTTPError as exc:
        raise AssetUpdateError("Unexpected response from server.") from exc

    content_length = resp.headers.get("Content-Length")
    if content_length is not None:
        try:
            if int(content_length) > max_bytes:
                raise AssetUpdateError("Response payload exceeds size limit.")
        except ValueError:
            pass  # ignore malformed Content-Length header

    data = b""
    for chunk in resp.iter_content(chunk_size=8192):
        data += chunk
        if len(data) > max_bytes:
            raise AssetUpdateError("Response payload exceeds size limit.")
    try:
        return json.loads(data.decode(resp.encoding or "utf-8"))
    except (json.JSONDecodeError, UnicodeDecodeError) as exc:
        raise AssetUpdateError("Failed to decode JSON response.") from exc


def update_asset_type(
    base_url: str,
    asset_type_id: str,
    new_name: str,
    api_key: str,
    timeout: int = 5,
) -> Dict[str, Any]:
    """
    Retrieve an existing asset type, create a new one with an updated name,
    delete the original, and return the newly created asset type data.
    """
    _validate_url(base_url)
    _validate_asset_id(asset_type_id)
    _validate_api_key(api_key)
    cleaned_name = _validate_name(new_name)

    headers = {
        "Accept": "application/json",
        "Authorization": f"Bearer {api_key}",
    }

    session: Session = requests.Session()
    session.headers.update(headers)

    try:
        # Retrieve current asset type
        get_url = urljoin(base_url.rstrip("/") + "/", f"asset-types/{asset_type_id}")
        get_resp = session.get(
            get_url,
            timeout=timeout,
            verify=True,
            allow_redirects=False,
            stream=True,
        )
        current_asset = _handle_response(get_resp)

        # Prepare payload for new asset type, copying existing fields except name
        new_asset_payload = dict(current_asset)
        new_asset_payload["name"] = cleaned_name
        new_asset_payload.pop("id", None)

        # Create new asset type
        post_url = urljoin(base_url.rstrip("/") + "/", "asset-types")
        post_resp = session.post(
            post_url,
            json=new_asset_payload,
            timeout=timeout,
            verify=True,
            allow_redirects=False,
            stream=True,
        )
        new_asset = _handle_response(post_resp)

        # Delete old asset type
        del_url = urljoin(base_url.rstrip("/") + "/", f"asset-types/{asset_type_id}")
        del_resp = session.delete(
            del_url,
            timeout=timeout,
            verify=True,
            allow_redirects=False,
            stream=True,
        )
        _handle_response(del_resp)

        return new_asset

    except (RequestException, Timeout) as exc:
        raise AssetUpdateError("Network communication failure.") from exc
    finally:
        session.close()

