                timeout=(timeout, timeout),
                verify=True,
                allow_redirects=False,
            )
            response.raise_for_status()
            resp_json = response.json()

        message = resp_json.get("message", "")
        if not isinstance(message, str) or "success" not in message.lower():
            return {"error": "Update operation did not report success."}

        return resp_json

    except (ValueError, RequestException, json.JSONDecodeError, Timeout, HTTPError, ConnectionError):
        return {"error": "Failed to update asset type."}

import hashlib
import os
from typing import Optional

_ALLOWED_ALGORITHMS = {
    "sha256": "sha256",
    "sha512": "sha512",
    "sha3_256": "sha3_256",
}


def _validate_algorithm(name: str) -> str:
    alg = name.lower()
    if alg not in _ALLOWED_ALGORITHMS:
        raise ValueError("Unsupported hash algorithm.")
    return _ALLOWED_ALGORITHMS[alg]


def _get_salt(salt: Optional[bytes] = None) -> bytes:
    if salt is None:
        return os.urandom(16)
    if not isinstance(salt, (bytes, bytearray)):
        raise ValueError("Salt must be bytes.")
    if len(salt) < 16:
        raise ValueError("Salt must be at least 16 bytes.")
    return bytes(salt)


def hash_message(
    message: str,
    algorithm: str = "sha256",
    salt: Optional[bytes] = None,
) -> str:
    """
    Derives a cryptographically strong hash of the given message using a
    PBKDF2-HMAC construction with the specified algorithm and a high‑entropy
    salt. The result is returned as ``salt_hex:hash_hex``.
    """
    if not isinstance(message, str):
        raise ValueError("Message must be a string.")
    algo_name = _validate_algorithm(algorithm)
    salt_bytes = _get_salt(salt)

    try:
        dk = hashlib.pbkdf2_hmac(
            algo_name,
            message.encode("utf-8"),
            salt_bytes,
            100_000,  # iteration count
        )
    except (TypeError, ValueError) as exc:
        raise ValueError("Failed to compute hash.") from exc

    return f"{salt_bytes.hex()}:{dk.hex()}"

import logging
import json
import re
import urllib.request
import urllib.parse
import urllib.error
import ipaddress
import socket
from typing import Optional, Dict, Any

logger = logging.getLogger(__name__)
if not logger.handlers:
    handler = logging.StreamHandler()
    formatter = logging.Formatter(
        fmt="%(asctime)s %(levelname)s %(name)s %(message)s",
        datefmt="%Y-%m-%d %H:%M:%S",
    )
    handler.setFormatter(formatter)
    logger.addHandler(handler)
    logger.setLevel(logging.INFO)


def _is_ip_disallowed(ip: ipaddress.IPv4Address | ipaddress.IPv6Address) -> bool:
    return any(
        (
            ip.is_private,
            ip.is_loopback,
            ip.is_link_local,
            ip.is_reserved,
            ip.is_multicast,
        )
    )


def _is_safe_url(url: str) -> bool:
    try:
        parsed = urllib.parse.urlparse(url)
        if parsed.scheme not in ("http", "https"):
            return False
        if not parsed.netloc:
            return False
        if parsed.username or parsed.password:
            return False
        hostname = parsed.hostname
        if not hostname:
            return False

        # Direct IP address?
        try:
            ip = ipaddress.ip_address(hostname)
            if _is_ip_disallowed(ip):
                return False
            return True
        except ValueError:
            # Hostname – resolve and check every IP
            try:
                addr_infos = socket.getaddrinfo(hostname, None)
                for _, _, _, _, sockaddr in addr_infos:
                    ip = ipaddress.ip_address(sockaddr[0])
                    if _is_ip_disallowed(ip):
                        return False
                return True
            except socket.gaierror:
                return False
    except Exception:
        return False


def _verify_target(url: str) -> bool:
    """Re‑validate URL just before the request to mitigate TOCTOU DNS races."""
    if not _is_safe_url(url):
        return False
    # Resolve again to ensure IPs have not changed to disallowed ranges.
    parsed = urllib.parse.urlparse(url)
    hostname = parsed.hostname
    if not hostname:
        return False
    try:
        addr_infos = socket.getaddrinfo(hostname, None)
        for _, _, _, _, sockaddr in addr_infos:
            ip = ipaddress.ip_address(sockaddr[0])
            if _is_ip_disallowed(ip):
                return False
        return True
    except socket.gaierror:
        return False


def _is_safe_id(asset_id: str) -> bool:
    return bool(re.fullmatch(r"[A-Za-z0-9_-]+", asset_id))


def _make_request(method: str, url: str) -> urllib.request.Request:
    req = urllib.request.Request(url=url, method=method)
    req.add_header("Accept", "application/json")
    return req


def _sanitize_url(url: str) -> str:
    parsed = urllib.parse.urlsplit(url)
    return urllib.parse.urlunsplit((parsed.scheme, parsed.netloc, parsed.path, "", ""))


class LimitedRedirectHandler(urllib.request.HTTPRedirectHandler):
    def __init__(self, max_redirects: int = 5):
        super().__init__()
        self.max_redirects = max_redirects

    def redirect_request(self, req, fp, code, msg, hdrs, newurl):
        count = getattr(req, "_redirect_count", 0)
        if count >= self.max_redirects:
            raise urllib.error.HTTPError(
                req.full_url,
                code,
                "Maximum redirect limit exceeded",
                hdrs,
                fp,
            )
        # Validate the target of the redirect
        if not _verify_target(newurl):
            raise urllib.error.HTTPError(
                req.full_url,
                code,
                "Redirect target is not allowed",
                hdrs,
                fp,
            )
        new_req = super().redirect_request(req, fp, code, msg, hdrs, newurl)
        if new_req:
            new_req._redirect_count = count + 1
        return new_req


def _get_opener() -> urllib.request.OpenerDirector:
    return urllib.request.build_opener(LimitedRedirectHandler())


def _handle_response(response: urllib.request.HTTPResponse) -> Dict[str, Any]:
    MAX_BODY = 1_048_576  # 1 MiB
    try:
        content_length = response.getheader("Content-Length")
        if content_length and int(content_length) > MAX_BODY:
            logger.warning("Response Content-Length %s exceeds limit", content_length)
            raw = response.read(MAX_BODY)
        else:
            raw = response.read(MAX_BODY + 1)
        if len(raw) > MAX_BODY:
            logger.warning("Response body exceeds max size, truncating")
            raw = raw[:MAX_BODY]
        raw_str = raw.decode("utf-8", errors="replace")
        data = json.loads(raw_str) if raw_str else None
    except json.JSONDecodeError:
        logger.warning("Response is not valid JSON")
        data = None
    return {"status": response.getcode(), "data": data}


def test_asset_type_endpoints(base_url: str, asset_type_id: str) -> Dict[str, Optional[Dict[str, Any]]]:
    result: Dict[str, Optional[Dict[str, Any]]] = {"retrieve": None, "delete": None}

    if not _is_safe_url(base_url):
        logger.error("Invalid base URL provided")
        return result

    if not _is_safe_id(asset_type_id):
        logger.error("Invalid asset type identifier provided")
        return result

    endpoint = f"{base_url.rstrip('/')}/asset-types/{urllib.parse.quote(asset_type_id)}"
    sanitized_endpoint = _sanitize_url(endpoint)
    opener = _get_opener()

    # Retrieve asset type (GET)
    try:
        if not _verify_target(endpoint):
            raise urllib.error.URLError("Target URL failed safety verification")
        get_req = _make_request("GET", endpoint)
        with opener.open(get_req, timeout=10) as resp:
            retrieve_info = _handle_response(resp)
            logger.info("GET %s succeeded with status %s", sanitized_endpoint, retrieve_info["status"])
            result["retrieve"] = retrieve_info
    except urllib.error.HTTPError as e:
        logger.error("GET %s failed with HTTP status %s", sanitized_endpoint, e.code)
        result["retrieve"] = {"status": e.code, "data": None}
    except urllib.error.URLError as e:
        logger.error("GET %s failed with network error: %s", sanitized_endpoint, str(e.reason))
        result["retrieve"] = {"status": None, "data": None}
    except Exception:
        logger.exception("Unexpected error during GET request")
        result["retrieve"] = {"status": None, "data": None}

    # Delete asset type (DELETE)
    try:
        if not _verify_target(endpoint):
            raise urllib.error.URLError("Target URL failed safety verification")
        delete_req = _make_request("DELETE", endpoint)
        with opener.open(delete_req, timeout=10) as resp:
            delete_info = _handle_response(resp)
            logger.info("DELETE %s succeeded with status %s", sanitized_endpoint, delete_info["status"])
            result["delete"] = delete_info
    except urllib.error.HTTPError as e:
        logger.error("DELETE %s failed with HTTP status %s", sanitized_endpoint, e.code)
        result["delete"] = {"status": e.code, "data": None}
    except urllib.error.URLError as e:
        logger.error("DELETE %s failed with network error: %s", sanitized_endpoint, str(e.reason))
        result["delete"] = {"status": None, "data": None}
    except Exception:
        logger.exception("Unexpected error during DELETE request")
        result["delete"] = {"status": None, "data": None}

    return result
